{
  "name": "AutoGasto - Gestor de Despesas Veiculares",
  "description": "Uma aplicação completa para monitorar gastos com combustível e manutenção, calculando médias de consumo e fornecendo insights inteligentes.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ExpenseType {
  FUEL = 'FUEL',
  MAINTENANCE = 'MAINTENANCE',
  OTHER = 'OTHER'
}

export interface Expense {
  id: string;
  date: string;
  type: ExpenseType;
  odometer: number;
  value: number;
  liters?: number;
  description: string;
}

export interface CarStats {
  totalSpent: number;
  totalLiters: number;
  averageConsumption: number;
  totalDistance: number;
  lastOdometer: number;
}

import { GoogleGenAI } from "@google/genai";
import { Expense } from "../types";

export const getInsights = async (expenses: Expense[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    Analise o seguinte histórico de despesas de um veículo e forneça 3 dicas curtas e valiosas de economia ou manutenção em português:
    ${JSON.stringify(expenses)}

    Formato de resposta desejado: um array de strings.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      }
    });

    return JSON.parse(response.text || "[]");
  } catch (error) {
    console.error("Erro ao obter insights do Gemini:", error);
    return ["Mantenha os pneus calibrados para economizar combustível.", "Realize revisões periódicas conforme o manual.", "Evite acelerações bruscas para melhorar a média."];
  }
};

import React from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  LineChart, Line, AreaChart, Area 
} from 'recharts';
import { Expense, CarStats, ExpenseType } from '../types';
import { Fuel, Wrench, TrendingUp, Gauge, DollarSign } from 'lucide-react';

interface DashboardProps {
  expenses: Expense[];
  stats: CarStats;
}

export const Dashboard: React.FC<DashboardProps> = ({ expenses, stats }) => {
  // Process data for charts
  const chartData = expenses
    .slice(-10)
    .map(e => ({
      name: new Date(e.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
      valor: e.value,
      tipo: e.type === ExpenseType.FUEL ? 'Combustível' : 'Manutenção'
    }));

  const fuelEfficiencyData = expenses
    .filter(e => e.type === ExpenseType.FUEL)
    .map((e, i, arr) => {
      if (i === 0) return null;
      const prev = arr[i - 1];
      const dist = e.odometer - prev.odometer;
      const efficiency = e.liters ? (dist / e.liters) : 0;
      return {
        date: new Date(e.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
        kmL: parseFloat(efficiency.toFixed(2))
      };
    })
    .filter(Boolean);

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {/* Card: Gasto Total */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-xl">
            <DollarSign size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Gasto Total</p>
            <h3 className="text-2xl font-bold text-slate-800">
              R$ {stats.totalSpent.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
            </h3>
          </div>
        </div>

        {/* Card: Média Geral */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-green-50 text-green-600 rounded-xl">
            <Gauge size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Média Geral</p>
            <h3 className="text-2xl font-bold text-slate-800">
              {stats.averageConsumption.toFixed(2)} <span className="text-sm font-normal">km/L</span>
            </h3>
          </div>
        </div>

        {/* Card: Distância Total */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-purple-50 text-purple-600 rounded-xl">
            <TrendingUp size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Distância Total</p>
            <h3 className="text-2xl font-bold text-slate-800">
              {stats.totalDistance.toLocaleString('pt-BR')} <span className="text-sm font-normal">km</span>
            </h3>
          </div>
        </div>

        {/* Card: Último Odômetro */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-orange-50 text-orange-600 rounded-xl">
            <Fuel size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Último Odômetro</p>
            <h3 className="text-2xl font-bold text-slate-800">
              {stats.lastOdometer.toLocaleString('pt-BR')} <span className="text-sm font-normal">km</span>
            </h3>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Gráfico de Gastos */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h4 className="text-lg font-semibold text-slate-800 mb-6">Últimos Lançamentos</h4>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip 
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="valor" fill="#3b82f6" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Gráfico de Eficiência */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h4 className="text-lg font-semibold text-slate-800 mb-6">Desempenho (km/L)</h4>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={fuelEfficiencyData}>
                <defs>
                  <linearGradient id="colorKml" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip 
                   contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Area type="monotone" dataKey="kmL" stroke="#10b981" fillOpacity={1} fill="url(#colorKml)" strokeWidth={3} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ExpenseType, Expense } from '../types';
import { Plus, X } from 'lucide-react';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'>) => void;
  onClose: () => void;
  lastOdometer: number;
}

export const ExpenseForm: React.FC<ExpenseFormProps> = ({ onAdd, onClose, lastOdometer }) => {
  const [type, setType] = useState<ExpenseType>(ExpenseType.FUEL);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [odometer, setOdometer] = useState<string>(lastOdometer.toString());
  const [value, setValue] = useState<string>('');
  const [liters, setLiters] = useState<string>('');
  const [description, setDescription] = useState<string>('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onAdd({
      type,
      date,
      odometer: parseFloat(odometer),
      value: parseFloat(value),
      liters: type === ExpenseType.FUEL ? parseFloat(liters) : undefined,
      description: description || (type === ExpenseType.FUEL ? 'Abastecimento' : 'Manutenção'),
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center">
          <h3 className="text-xl font-bold text-slate-800">Novo Lançamento</h3>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-400">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div className="flex bg-slate-100 p-1 rounded-xl">
            <button
              type="button"
              onClick={() => setType(ExpenseType.FUEL)}
              className={`flex-1 py-2 px-4 rounded-lg text-sm font-semibold transition-all ${
                type === ExpenseType.FUEL ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'
              }`}
            >
              Combustível
            </button>
            <button
              type="button"
              onClick={() => setType(ExpenseType.MAINTENANCE)}
              className={`flex-1 py-2 px-4 rounded-lg text-sm font-semibold transition-all ${
                type === ExpenseType.MAINTENANCE ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'
              }`}
            >
              Manutenção
            </button>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-500 uppercase">Data</label>
              <input
                type="date"
                required
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-500 uppercase">Odômetro (km)</label>
              <input
                type="number"
                required
                min={lastOdometer}
                value={odometer}
                onChange={(e) => setOdometer(e.target.value)}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-slate-500 uppercase">Valor (R$)</label>
              <input
                type="number"
                step="0.01"
                required
                placeholder="0,00"
                value={value}
                onChange={(e) => setValue(e.target.value)}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
            </div>
            {type === ExpenseType.FUEL && (
              <div className="space-y-1">
                <label className="text-xs font-bold text-slate-500 uppercase">Litros</label>
                <input
                  type="number"
                  step="0.01"
                  required
                  placeholder="0.00"
                  value={liters}
                  onChange={(e) => setLiters(e.target.value)}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                />
              </div>
            )}
          </div>

          <div className="space-y-1">
            <label className="text-xs font-bold text-slate-500 uppercase">Descrição</label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder={type === ExpenseType.FUEL ? "Ex: Posto Ipiranga" : "Ex: Troca de óleo"}
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              rows={2}
            />
          </div>

          <button
            type="submit"
            className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white font-bold rounded-2xl shadow-lg shadow-blue-200 transition-all flex items-center justify-center space-x-2"
          >
            <Plus size={20} />
            <span>Salvar Lançamento</span>
          </button>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Fuel, Wrench } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  const stats = useMemo<CarStats>(() => {
    const totalSpent = expenses.reduce((acc, curr) => acc + curr.value, 0);
    const fuelExpenses = expenses.filter(e => e.type === ExpenseType.FUEL).sort((a, b) => a.odometer - b.odometer);

    let totalDistance = 0;
    let totalLiters = 0;

    if (fuelExpenses.length > 1) {
      totalDistance = fuelExpenses[fuelExpenses.length - 1].odometer - fuelExpenses[0].odometer;
      // Consideramos os litros a partir do segundo abastecimento para o cálculo de km/l
      // Mas aqui vamos somar todos menos o último para uma média simples de "combustível consumido"
      totalLiters = fuelExpenses.slice(1).reduce((acc, curr) => acc + (curr.liters || 0), 0);
    }

    const averageConsumption = totalLiters > 0 ? totalDistance / totalLiters : 0;
    const lastOdometer = expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;

    return {
      totalSpent,
      totalLiters: fuelExpenses.reduce((acc, curr) => acc + (curr.liters || 0), 0),
      averageConsumption,
      totalDistance,
      lastOdometer
    };
  }, [expenses]);

  const handleAddExpense = (newExpense: Omit<Expense, 'id'>) => {
    const expense: Expense = {
      ...newExpense,
      id: crypto.randomUUID(),
    };
    setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  return (
    <div className="min-h-screen pb-24 md:pb-8">
      {/* Header */}
      <header className="bg-white border-b border-slate-100 sticky top-0 z-40">
        <div className="max-w-5xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white">
              <Gauge size={24} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">AutoGasto</h1>
          </div>
          <button 
            onClick={() => setIsFormOpen(true)}
            className="hidden md:flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl font-semibold transition-all shadow-md shadow-blue-100"
          >
            <Plus size={20} />
            <span>Novo Lançamento</span>
          </button>
          <button 
            onClick={() => setIsFormOpen(true)}
            className="md:hidden p-2.5 bg-blue-600 text-white rounded-xl shadow-lg"
          >
            <Plus size={24} />
          </button>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8">
        {/* Insights Section */}
        {expenses.length >= 2 && (
          <div className="mb-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-3xl p-6 text-white shadow-xl relative overflow-hidden">
            <div className="relative z-10">
              <div className="flex justify-between items-center mb-4">
                <div className="flex items-center space-x-2">
                  <Sparkles size={20} className="text-yellow-300" />
                  <h2 className="font-bold text-lg">Insights da IA</h2>
                </div>
                <button 
                  onClick={fetchAIInsights}
                  disabled={loadingInsights}
                  className="text-xs bg-white/20 hover:bg-white/30 px-3 py-1.5 rounded-full transition-all flex items-center space-x-1"
                >
                  {loadingInsights ? "Analisando..." : "Atualizar Dicas"}
                </button>
              </div>

              {insights.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  {insights.map((tip, idx) => (
                    <div key={idx} className="bg-white/10 backdrop-blur-md p-4 rounded-2xl text-sm border border-white/10">
                      {tip}
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-indigo-100 text-sm italic">
                  Clique em "Atualizar Dicas" para que nossa IA analise seus gastos e ofereça conselhos personalizados.
                </p>
              )}
            </div>
            {/* Background decoration */}
            <div className="absolute -right-8 -bottom-8 w-40 h-40 bg-white/10 rounded-full blur-3xl"></div>
          </div>
        )}

        {/* Navigation Tabs (Mobile only context switch) */}
        <div className="flex space-x-4 mb-6">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`flex items-center space-x-2 px-6 py-3 rounded-2xl font-bold transition-all ${
              activeTab === 'dashboard' ? 'bg-slate-800 text-white shadow-lg' : 'bg-white text-slate-500 hover:bg-slate-50'
            }`}
          >
            <LayoutDashboard size={18} />
            <span>Dashboard</span>
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex items-center space-x-2 px-6 py-3 rounded-2xl font-bold transition-all ${
              activeTab === 'history' ? 'bg-slate-800 text-white shadow-lg' : 'bg-white text-slate-500 hover:bg-slate-50'
            }`}
          >
            <History size={18} />
            <span>Histórico</span>
          </button>
        </div>

        {activeTab === 'dashboard' ? (
          <Dashboard expenses={expenses} stats={stats} />
        ) : (
          <div className="bg-white rounded-3xl shadow-sm border border-slate-100 overflow-hidden">
            <div className="p-6 border-b border-slate-100">
              <h2 className="text-lg font-bold text-slate-800">Todos os Lançamentos</h2>
            </div>
            <div className="overflow-x-auto">
              {expenses.length === 0 ? (
                <div className="p-12 text-center text-slate-400">
                  <div className="mb-4 flex justify-center">
                    <History size={48} strokeWidth={1.5} />
                  </div>
                  <p>Nenhum registro encontrado.</p>
                  <button 
                    onClick={() => setIsFormOpen(true)}
                    className="mt-4 text-blue-600 font-bold hover:underline"
                  >
                    Começar a lançar
                  </button>
                </div>
              ) : (
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b border-slate-100">
                    <tr>
                      <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Data</th>
                      <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Tipo</th>
                      <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase">Descrição</th>
                      <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Odômetro</th>
                      <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-right">Valor</th>
                      <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase text-center">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {expenses.map((expense) => (
                      <tr key={expense.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-600">
                          {new Date(expense.date).toLocaleDateString('pt-BR')}
                        </td>
                        <td className="px-6 py-4 whitespace-nowrap">
                          <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                            expense.type === ExpenseType.FUEL ? 'bg-blue-100 text-blue-800' : 'bg-orange-100 text-orange-800'
                          }`}>
                            {expense.type === ExpenseType.FUEL ? <Fuel size={12} className="mr-1" /> : <Wrench size={12} className="mr-1" />}
                            {expense.type === ExpenseType.FUEL ? 'Combustível' : 'Manutenção'}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-sm text-slate-700 max-w-xs truncate">
                          {expense.description}
                        </td>
                        <td className="px-6 py-4 text-sm text-slate-600 text-right font-mono">
                          {expense.odometer.toLocaleString('pt-BR')} km
                        </td>
                        <td className="px-6 py-4 text-sm font-bold text-slate-900 text-right">
                          R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                        </td>
                        <td className="px-6 py-4 text-center">
                          <button 
                            onClick={() => handleDeleteExpense(expense.id)}
                            className="p-2 text-slate-400 hover:text-red-500 transition-colors rounded-lg hover:bg-red-50"
                          >
                            <Trash2 size={18} />
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Floating Action Button (FAB) Mobile */}
      <div className="md:hidden fixed bottom-6 right-6">
        <button 
          onClick={() => setIsFormOpen(true)}
          className="w-16 h-16 bg-blue-600 text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-105 transition-transform"
        >
          <Plus size={32} />
        </button>
      </div>

      {isFormOpen && (
