  MAINTENANCE = 'MAINTENANCE',
  OTHER = 'OTHER'
}

export type FuelType = 'Gasolina' | 'Etanol' | 'Diesel' | 'GNV';

export interface MaintenanceItem {
  id: string;
  description: string;
  value: number;
}

export interface Location {
  id: string;
  name: string;
  type: 'POSTO' | 'OFICINA';
}

export interface Expense {
  id: string;
  date: string;
  type: ExpenseType;
  odometer: number;
  value: number;
  locationId?: string;
  fuelType?: FuelType;
  liters?: number;
  description: string; // Para combustível, vira o tipo. Para manutenção, um resumo.
  maintenanceItems?: MaintenanceItem[];
}

export interface CarStats {
  totalSpent: number;
  totalLiters: number;
  averageConsumption: number;
  totalDistance: number;
  lastOdometer: number;
}

import React, { useState, useMemo } from 'react';
import { ExpenseType, Expense, Location, FuelType, MaintenanceItem } from '../types';
import { Plus, X, Trash2, MapPin } from 'lucide-react';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'>) => void;
  onClose: () => void;
  lastOdometer: number;
  locations: Location[];
}

export const ExpenseForm: React.FC<ExpenseFormProps> = ({ onAdd, onClose, lastOdometer, locations }) => {
  const [type, setType] = useState<ExpenseType>(ExpenseType.FUEL);
  // Data puxar automático o dia
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [odometer, setOdometer] = useState<string>(lastOdometer.toString());
  const [locationId, setLocationId] = useState<string>('');

  // Fuel specific
  const [fuelType, setFuelType] = useState<FuelType>('Gasolina');
  const [fuelValue, setFuelValue] = useState<string>('');
  const [liters, setLiters] = useState<string>('');

  // Maintenance specific
  const [maintItems, setMaintItems] = useState<MaintenanceItem[]>([
    { id: crypto.randomUUID(), description: '', value: 0 }
  ]);

  const totalValue = useMemo(() => {
    if (type === ExpenseType.FUEL) return parseFloat(fuelValue) || 0;
    return maintItems.reduce((acc, item) => acc + (item.value || 0), 0);
  }, [type, fuelValue, maintItems]);

  const addMaintItem = () => {
    setMaintItems([...maintItems, { id: crypto.randomUUID(), description: '', value: 0 }]);
  };

  const removeMaintItem = (id: string) => {
    if (maintItems.length > 1) {
      setMaintItems(maintItems.filter(item => item.id !== id));
    }
  };

  const updateMaintItem = (id: string, field: 'description' | 'value', val: string) => {
    setMaintItems(maintItems.map(item => {
      if (item.id === id) {
        return { ...item, [field]: field === 'value' ? parseFloat(val) || 0 : val };
      }
      return item;
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!locationId) {
      alert("Por favor, selecione um local.");
      return;
    }

    const payload: Omit<Expense, 'id'> = {
      type,
      date,
      odometer: parseFloat(odometer),
      value: totalValue,
      locationId,
      description: type === ExpenseType.FUEL ? fuelType : 'Manutenção Multi-item',
    };

    if (type === ExpenseType.FUEL) {
      payload.fuelType = fuelType;
      payload.liters = parseFloat(liters);
    } else {
      payload.maintenanceItems = maintItems;
    }

    onAdd(payload);
    onClose();
  };

  const filteredLocations = locations.filter(l => 
    type === ExpenseType.FUEL ? l.type === 'POSTO' : l.type === 'OFICINA'
  );

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center shrink-0">
          <div>
            <h3 className="text-xl font-bold text-slate-800">Novo Lançamento</h3>
            <p className="text-xs text-slate-400 font-medium uppercase tracking-wider">Registro de {type === ExpenseType.FUEL ? 'Abastecimento' : 'Manutenção'}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-400">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto">
          {/* Tipo de Despesa */}
          <div className="flex bg-slate-100 p-1.5 rounded-2xl">
            <button
              type="button"
              onClick={() => setType(ExpenseType.FUEL)}
              className={`flex-1 py-2.5 px-4 rounded-xl text-sm font-bold transition-all ${
                type === ExpenseType.FUEL ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'
              }`}
            >
              Combustível
            </button>
            <button
              type="button"
              onClick={() => setType(ExpenseType.MAINTENANCE)}
              className={`flex-1 py-2.5 px-4 rounded-xl text-sm font-bold transition-all ${
                type === ExpenseType.MAINTENANCE ? 'bg-white text-orange-600 shadow-sm' : 'text-slate-500'
              }`}
            >
              Manutenção
            </button>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Data</label>
              <input
                type="date"
                required
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Odômetro (km)</label>
              <input
                type="number"
                required
                min={lastOdometer}
                value={odometer}
                onChange={(e) => setOdometer(e.target.value)}
                className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              />
            </div>
          </div>

          {/* Seleção de Local */}
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
              Local ({type === ExpenseType.FUEL ? 'Posto' : 'Oficina'})
            </label>
            <select
              required
              value={locationId}
              onChange={(e) => setLocationId(e.target.value)}
              className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
            >
              <option value="">Selecione um local...</option>
              {filteredLocations.map(loc => (
                <option key={loc.id} value={loc.id}>{loc.name}</option>
              ))}
            </select>
            {filteredLocations.length === 0 && (
              <p className="text-[10px] text-amber-600 font-medium">Cadastre um local primeiro na aba de locais!</p>
            )}
          </div>

          {/* Campos Dinâmicos conforme o Tipo */}
          {type === ExpenseType.FUEL ? (
            <div className="space-y-4 animate-in slide-in-from-top-2">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Combustível</label>
                  <select
                    value={fuelType}
                    onChange={(e) => setFuelType(e.target.value as FuelType)}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  >
                    <option value="Gasolina">Gasolina</option>
                    <option value="Etanol">Etanol</option>
                    <option value="Diesel">Diesel</option>
                    <option value="GNV">GNV</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Valor (R$)</label>
                  <input
                    type="number"
                    step="0.01"
                    required
                    value={fuelValue}
                    onChange={(e) => setFuelValue(e.target.value)}
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all font-bold"
                  />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Litros</label>
                <input
                  type="number"
                  step="0.01"
                  required
                  value={liters}
                  onChange={(e) => setLiters(e.target.value)}
                  className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                />
              </div>
            </div>
          ) : (
            <div className="space-y-3 animate-in slide-in-from-top-2">
              <div className="flex justify-between items-center mb-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Itens da Manutenção</label>
                <button
                  type="button"
                  onClick={addMaintItem}
                  className="text-[10px] font-bold text-orange-600 hover:text-orange-700 flex items-center gap-1"
                >
                  <Plus size={14} /> ADICIONAR ITEM
                </button>
              </div>

              {maintItems.map((item) => (
                <div key={item.id} className="flex gap-2 items-end group">
                  <div className="flex-1 space-y-1">
                    <input
                      placeholder="Ex: Troca de óleo"
