            >
              <option value="POSTO">Posto</option>
              <option value="OFICINA">Oficina</option>
            </select>
          </div>
          <button
            type="submit"
            className="bg-slate-800 text-white px-6 py-3 rounded-xl font-bold hover:bg-slate-900 transition-all flex items-center justify-center gap-2"
          >
            <Plus size={18} />
            Cadastrar
          </button>
        </form>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {locations.map(loc => (
          <div key={loc.id} className="bg-white p-4 rounded-2xl border border-slate-100 flex items-center justify-between hover:shadow-md transition-shadow">
            <div className="flex items-center gap-3">
              <div className={`p-2.5 rounded-xl ${loc.type === 'POSTO' ? 'bg-blue-50 text-blue-600' : 'bg-orange-50 text-orange-600'}`}>
                {loc.type === 'POSTO' ? <Fuel size={20} /> : <Wrench size={20} />}
              </div>
              <div>
                <p className="font-bold text-slate-800">{loc.name}</p>
                <p className="text-[10px] font-bold text-slate-400 uppercase">{loc.type}</p>
              </div>
            </div>
            <button
              onClick={() => onRemove(loc.id)}
              className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
            >
              <Trash2 size={18} />
            </button>
          </div>
        ))}
        {locations.length === 0 && (
          <div className="col-span-full py-12 text-center text-slate-400 italic">
            Nenhum local cadastrado.
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { LocationManager } from './components/LocationManager';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Fuel, Wrench, Gauge, MapPin, ChevronDown } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'locations'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const stats = useMemo<CarStats>(() => {
    const totalSpent = expenses.reduce((acc, curr) => acc + curr.value, 0);
    const fuelExpenses = expenses
      .filter(e => e.type === ExpenseType.FUEL)
      .sort((a, b) => a.odometer - b.odometer);

    let totalDistance = 0;
    let totalLiters = 0;

    if (fuelExpenses.length > 1) {
      totalDistance = fuelExpenses[fuelExpenses.length - 1].odometer - fuelExpenses[0].odometer;
      totalLiters = fuelExpenses.slice(1).reduce((acc, curr) => acc + (curr.liters || 0), 0);
    }

    const averageConsumption = totalLiters > 0 ? totalDistance / totalLiters : 0;
    const lastOdometer = expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;

    return {
      totalSpent,
      totalLiters: fuelExpenses.reduce((acc, curr) => acc + (curr.liters || 0), 0),
      averageConsumption,
      totalDistance,
      lastOdometer
    };
  }, [expenses]);

  const handleAddExpense = (newExpense: Omit<Expense, 'id'>) => {
    const expense: Expense = {
      ...newExpense,
      id: crypto.randomUUID(),
    };
    setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  return (
    <div className="min-h-screen pb-24 md:pb-8 bg-[#F8FAFC]">
      {/* Header */}
      <header className="bg-white border-b border-slate-100 sticky top-0 z-40">
        <div className="max-w-5xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-100">
              <Gauge size={22} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">AutoGasto</h1>
          </div>
          <button 
            onClick={() => setIsFormOpen(true)}
            className="hidden md:flex items-center space-x-2 bg-slate-900 hover:bg-slate-800 text-white px-6 py-2.5 rounded-2xl font-bold transition-all shadow-xl shadow-slate-200"
          >
            <Plus size={20} />
            <span>Novo Lançamento</span>
          </button>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8">
        {/* Navigation Tabs */}
        <div className="flex space-x-2 mb-8 bg-white p-1.5 rounded-[22px] w-fit shadow-sm border border-slate-100">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'dashboard' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <LayoutDashboard size={18} />
            <span>Dashboard</span>
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'history' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <History size={18} />
            <span>Histórico</span>
          </button>
          <button 
            onClick={() => setActiveTab('locations')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'locations' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <MapPin size={18} />
            <span>Locais</span>
          </button>
        </div>

        {activeTab === 'dashboard' && (
          <>
             {/* Insights Section */}
            {expenses.length >= 2 && (
              <div className="mb-8 bg-gradient-to-br from-indigo-600 to-blue-700 rounded-3xl p-6 text-white shadow-2xl shadow-indigo-100 relative overflow-hidden">
                <div className="relative z-10">
                  <div className="flex justify-between items-center mb-6">
                    <div className="flex items-center space-x-2">
                      <Sparkles size={20} className="text-yellow-300" />
                      <h2 className="font-bold text-lg">Inteligência AutoGasto</h2>
                    </div>
                    <button 
                      onClick={fetchAIInsights}
                      disabled={loadingInsights}
                      className="text-[10px] font-black uppercase tracking-widest bg-white/20 hover:bg-white/30 px-4 py-2 rounded-full transition-all"
                    >
                      {loadingInsights ? "Analisando..." : "Analisar Gastos"}
                    </button>
                  </div>

                  {insights.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      {insights.map((tip, idx) => (
                        <div key={idx} className="bg-white/10 backdrop-blur-md p-4 rounded-2xl text-sm border border-white/5 font-medium leading-relaxed">
                          {tip}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <p className="text-white/70 text-sm font-medium">
                      O AutoGasto está pronto para analisar seu perfil de direção. Clique acima para começar.
                    </p>
                  )}
                </div>
              </div>
            )}
            <Dashboard expenses={expenses} stats={stats} />
          </>
        )}

        {activeTab === 'locations' && (
          <LocationManager 
            locations={locations} 
            onAdd={handleAddLocation} 
            onRemove={handleRemoveLocation} 
          />
        )}

        {activeTab === 'history' && (
          <div className="space-y-4">
            {expenses.length === 0 ? (
              <div className="bg-white p-16 text-center text-slate-400 rounded-3xl border border-dashed border-slate-200">
                <History size={48} strokeWidth={1} className="mx-auto mb-4 opacity-20" />
                <p className="font-medium">Nenhum lançamento registrado.</p>
              </div>
            ) : (
              expenses.map(expense => (
                <div key={expense.id} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex flex-col md:flex-row md:items-center gap-6 group transition-all hover:shadow-md">
                  <div className={`p-4 rounded-2xl shrink-0 ${expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-600' : 'bg-orange-50 text-orange-600'}`}>
                    {expense.type === ExpenseType.FUEL ? <Fuel size={24} /> : <Wrench size={24} />}
                  </div>

                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                        {new Date(expense.date).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-1">
                        <MapPin size={10} /> {getLocationName(expense.locationId)}
                      </span>
                    </div>
                    <h4 className="font-bold text-slate-800 text-lg">
                      {expense.type === ExpenseType.FUEL ? `Abastecimento: ${expense.fuelType}` : 'Manutenção Preventiva/Corretiva'}
                    </h4>

                    {expense.maintenanceItems && (
                      <div className="mt-2 flex flex-wrap gap-2">
                        {expense.maintenanceItems.map(item => (
                          <span key={item.id} className="text-[11px] font-semibold bg-slate-50 text-slate-600 px-2 py-1 rounded-lg border border-slate-100">
                            {item.description}: R$ {item.value.toFixed(2)}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>

                  <div className="text-right shrink-0">
                    <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">{expense.odometer.toLocaleString()} KM</div>
                    <div className="text-2xl font-black text-slate-900">R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</div>
                  </div>

                  <div className="md:border-l md:pl-4">
                    <button 
                      onClick={() => handleDeleteExpense(expense.id)}
                      className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                    >
                      <Trash2 size={20} />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </main>

      {/* FAB Mobile */}
      <div className="md:hidden fixed bottom-8 right-6 z-30">
        <button 
          onClick={() => setIsFormOpen(true)}
          className="w-16 h-16 bg-blue-600 text-white rounded-2xl shadow-2xl flex items-center justify-center hover:scale-105 transition-transform"
        >
          <Plus size={32} />
        </button>
      </div>

      {isFormOpen && (
        <ExpenseForm 
          lastOdometer={stats.lastOdometer}
          locations={locations}
          onAdd={handleAddExpense} 
          onClose={() => setIsFormOpen(false)} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area 
} from 'recharts';
import { Expense, CarStats, ExpenseType } from '../types';
import { Fuel, Wrench, TrendingUp, Gauge, DollarSign, Calendar } from 'lucide-react';

interface DashboardProps {
  expenses: Expense[];
}

type FilterPeriod = 'all' | '30' | '90' | '180' | 'year';

export const Dashboard: React.FC<DashboardProps> = ({ expenses }) => {
  const [period, setPeriod] = useState<FilterPeriod>('all');

  // Filtragem dos dados baseada no período selecionado
  const filteredExpenses = useMemo(() => {
    if (period === 'all') return expenses;

    const now = new Date();
    const filterDate = new Date();

    if (period === '30') filterDate.setDate(now.getDate() - 30);
    else if (period === '90') filterDate.setDate(now.getDate() - 90);
    else if (period === '180') filterDate.setDate(now.getDate() - 180);
    else if (period === 'year') filterDate.setFullYear(now.getFullYear(), 0, 1); // Desde o início do ano atual

    return expenses.filter(e => new Date(e.date) >= filterDate);
  }, [expenses, period]);

  // Recálculo das estatísticas para o período filtrado
  const stats = useMemo<CarStats>(() => {
    const totalSpent = filteredExpenses.reduce((acc, curr) => acc + curr.value, 0);
    const fuelExpenses = filteredExpenses
      .filter(e => e.type === ExpenseType.FUEL)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    let totalDistance = 0;
    let totalLiters = 0;

    if (fuelExpenses.length > 1) {
      totalDistance = fuelExpenses[fuelExpenses.length - 1].odometer - fuelExpenses[0].odometer;
      // Cálculo de consumo considerando abastecimentos completos
      totalLiters = fuelExpenses.slice(1).reduce((acc, curr) => acc + (curr.liters || 0), 0);
    }

    const averageConsumption = totalLiters > 0 ? totalDistance / totalLiters : 0;
    const lastOdometer = expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;

    return {
      totalSpent,
      totalLiters: fuelExpenses.reduce((acc, curr) => acc + (curr.liters || 0), 0),
      averageConsumption,
      totalDistance,
      lastOdometer
    };
  }, [filteredExpenses, expenses]);

  // Processamento para os gráficos
  const chartData = useMemo(() => {
    return [...filteredExpenses]
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .slice(-15) // Mostrar no máximo os últimos 15 registros no gráfico
      .map(e => ({
        name: new Date(e.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
        valor: e.value,
        tipo: e.type === ExpenseType.FUEL ? 'Combustível' : 'Manutenção'
      }));
  }, [filteredExpenses]);

  const fuelEfficiencyData = useMemo(() => {
    return filteredExpenses
      .filter(e => e.type === ExpenseType.FUEL)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .map((e, i, arr) => {
        if (i === 0) return null;
        const prev = arr[i - 1];
        const dist = e.odometer - prev.odometer;
        const efficiency = e.liters ? (dist / e.liters) : 0;
        return {
          date: new Date(e.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
          kmL: parseFloat(efficiency.toFixed(2))
        };
      })
      .filter((item): item is { date: string; kmL: number } => item !== null);
  }, [filteredExpenses]);

  const FilterButton = ({ value, label }: { value: FilterPeriod, label: string }) => (
    <button
      onClick={() => setPeriod(value)}
      className={`px-4 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap ${
        period === value 
          ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' 
          : 'bg-white text-slate-500 hover:bg-slate-50 border border-slate-100'
      }`}
    >
      {label}
    </button>
  );

  return (
    <div className="space-y-6">
      {/* Filtros de Período */}
      <div className="flex items-center gap-3 overflow-x-auto pb-2 scrollbar-hide">
        <div className="p-2 bg-slate-100 rounded-xl text-slate-500 shrink-0">
          <Calendar size={18} />
        </div>
        <FilterButton value="30" label="Últimos 30 dias" />
        <FilterButton value="90" label="90 dias" />
        <FilterButton value="180" label="6 meses" />
        <FilterButton value="year" label="Este Ano" />
        <FilterButton value="all" label="Tudo" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {/* Card: Gasto no Período */}
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl">
            <DollarSign size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Gasto Período</p>
            <h3 className="text-xl font-black text-slate-800">
              R$ {stats.totalSpent.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
            </h3>
          </div>
        </div>

        {/* Card: Média no Período */}
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-emerald-50 text-emerald-600 rounded-2xl">
            <Gauge size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Média Período</p>
            <h3 className="text-xl font-black text-slate-800">
              {stats.averageConsumption.toFixed(2)} <span className="text-xs font-bold text-slate-400">km/L</span>
            </h3>
          </div>
        </div>

        {/* Card: Distância no Período */}
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-violet-50 text-violet-600 rounded-2xl">
            <TrendingUp size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Distância Período</p>
            <h3 className="text-xl font-black text-slate-800">
              {stats.totalDistance.toLocaleString('pt-BR')} <span className="text-xs font-bold text-slate-400">km</span>
            </h3>
          </div>
        </div>

        {/* Card: Odômetro Atual */}
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center space-x-4">
          <div className="p-3 bg-orange-50 text-orange-600 rounded-2xl">
            <Fuel size={24} />
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Odômetro Atual</p>
            <h3 className="text-xl font-black text-slate-800">
              {stats.lastOdometer.toLocaleString('pt-BR')} <span className="text-xs font-bold text-slate-400">km</span>
            </h3>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6">Custos no Período</h4>
          <div className="h-64">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: 700 }}
                  />
                  <Bar dataKey="valor" fill="#3b82f6" radius={[6, 6, 0, 0]} barSize={32} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">
                Sem dados para o período.
              </div>
            )}
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6">Eficiência (km/L)</h4>
          <div className="h-64">
            {fuelEfficiencyData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={fuelEfficiencyData}>
                  <defs>
                    <linearGradient id="colorKml" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: 700 }}
                  />
                  <Area type="monotone" dataKey="kmL" stroke="#10b981" fillOpacity={1} fill="url(#colorKml)" strokeWidth={3} />
                </AreaChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-400 text-sm italic">
                Abasteça pelo menos duas vezes para ver a eficiência.
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { LocationManager } from './components/LocationManager';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Fuel, Wrench, Gauge, MapPin } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'locations'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleAddExpense = (newExpense: Omit<Expense, 'id'>) => {
    const expense: Expense = {
      ...newExpense,
      id: crypto.randomUUID(),
    };
    setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  return (
    <div className="min-h-screen pb-24 md:pb-8 bg-[#F8FAFC]">
      {/* Header */}
      <header className="bg-white border-b border-slate-100 sticky top-0 z-40">
        <div className="max-w-5xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-100">
              <Gauge size={22} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">AutoGasto</h1>
          </div>
          <button 
            onClick={() => setIsFormOpen(true)}
            className="hidden md:flex items-center space-x-2 bg-slate-900 hover:bg-slate-800 text-white px-6 py-2.5 rounded-2xl font-bold transition-all shadow-xl shadow-slate-200"
          >
            <Plus size={20} />
            <span>Novo Lançamento</span>
          </button>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8">
        {/* Navigation Tabs */}
        <div className="flex space-x-2 mb-8 bg-white p-1.5 rounded-[22px] w-fit shadow-sm border border-slate-100">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'dashboard' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <LayoutDashboard size={18} />
            <span>Dashboard</span>
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'history' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <History size={18} />
            <span>Histórico</span>
          </button>
          <button 
            onClick={() => setActiveTab('locations')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'locations' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <MapPin size={18} />
            <span>Locais</span>
          </button>
        </div>

        {activeTab === 'dashboard' && (
          <>
             {/* Insights Section */}
            {expenses.length >= 2 && (
              <div className="mb-8 bg-gradient-to-br from-indigo-600 to-blue-700 rounded-3xl p-6 text-white shadow-2xl shadow-indigo-100 relative overflow-hidden">
                <div className="relative z-10">
                  <div className="flex justify-between items-center mb-6">
                    <div className="flex items-center space-x-2">
                      <Sparkles size={20} className="text-yellow-300" />
                      <h2 className="font-bold text-lg">Inteligência AutoGasto</h2>
                    </div>
                    <button 
                      onClick={fetchAIInsights}
                      disabled={loadingInsights}
                      className="text-[10px] font-black uppercase tracking-widest bg-white/20 hover:bg-white/30 px-4 py-2 rounded-full transition-all"
                    >
                      {loadingInsights ? "Analisando..." : "Analisar Gastos"}
                    </button>
                  </div>

                  {insights.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      {insights.map((tip, idx) => (
                        <div key={idx} className="bg-white/10 backdrop-blur-md p-4 rounded-2xl text-sm border border-white/5 font-medium leading-relaxed">
                          {tip}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <p className="text-white/70 text-sm font-medium">
                      O AutoGasto está pronto para analisar seu perfil de direção. Clique acima para começar.
                    </p>
                  )}
                </div>
              </div>
            )}
            <Dashboard expenses={expenses} />
          </>
        )}

        {activeTab === 'locations' && (
          <LocationManager 
            locations={locations} 
            onAdd={handleAddLocation} 
            onRemove={handleRemoveLocation} 
          />
        )}

        {activeTab === 'history' && (
          <div className="space-y-4">
            {expenses.length === 0 ? (
              <div className="bg-white p-16 text-center text-slate-400 rounded-3xl border border-dashed border-slate-200">
                <History size={48} strokeWidth={1} className="mx-auto mb-4 opacity-20" />
                <p className="font-medium">Nenhum lançamento registrado.</p>
              </div>
            ) : (
              expenses.map(expense => (
                <div key={expense.id} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex flex-col md:flex-row md:items-center gap-6 group transition-all hover:shadow-md">
                  <div className={`p-4 rounded-2xl shrink-0 ${expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-600' : 'bg-orange-50 text-orange-600'}`}>
                    {expense.type === ExpenseType.FUEL ? <Fuel size={24} /> : <Wrench size={24} />}
                  </div>

                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">
                        {new Date(expense.date).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-400 flex items-center gap-1">
                        <MapPin size={10} /> {getLocationName(expense.locationId)}
                      </span>
                    </div>
                    <h4 className="font-bold text-slate-800 text-lg">
                      {expense.type === ExpenseType.FUEL ? `Abastecimento: ${expense.fuelType}` : 'Manutenção Preventiva/Corretiva'}
                    </h4>

                    {expense.maintenanceItems && (
                      <div className="mt-2 flex flex-wrap gap-2">
                        {expense.maintenanceItems.map(item => (
                          <span key={item.id} className="text-[11px] font-semibold bg-slate-50 text-slate-600 px-2 py-1 rounded-lg border border-slate-100">
                            {item.description}: R$ {item.value.toFixed(2)}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>

                  <div className="text-right shrink-0">
                    <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">{expense.odometer.toLocaleString()} KM</div>
                    <div className="text-2xl font-black text-slate-900">R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</div>
                  </div>

                  <div className="md:border-l md:pl-4">
                    <button 
                      onClick={() => handleDeleteExpense(expense.id)}
                      className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
