                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </main>

      {/* FAB Mobile */}
      <div className="md:hidden fixed bottom-8 right-6 z-30">
        <button 
          onClick={() => setIsFormOpen(true)}
          className="w-16 h-16 bg-blue-600 text-white rounded-2xl shadow-2xl flex items-center justify-center hover:scale-105 transition-transform"
