        <form onSubmit={handleSubmit} className="flex flex-col md:flex-row gap-4">
          <div className="flex-1 space-y-1">
            <label className="text-[11px] font-black text-slate-700 uppercase tracking-widest ml-1">Nome do Local</label>
            <input
              type="text"
              placeholder="Ex: Posto do Trevo"
              value={name}
              onChange={(e) => setName(e.target.value)}
