            />
          </div>
          <div className="w-full md:w-48 space-y-1">
            <label className="text-[11px] font-black text-slate-700 uppercase tracking-widest ml-1">Categoria</label>
            <select
              value={type}
              onChange={(e) => setType(e.target.value as any)}
              className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl outline-none text-slate-900 font-bold"
            >
              <option value="POSTO">Posto de Combustível</option>
              <option value="OFICINA">Oficina Mecânica</option>
