import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area 
} from 'recharts';
import { Expense, CarStats, ExpenseType } from '../types';
import { Fuel, Wrench, TrendingUp, Gauge, DollarSign, Calendar, SlidersHorizontal, HandCoins } from 'lucide-react';

interface DashboardProps {
  expenses: Expense[];
}

type FilterPeriod = 'all' | '30' | '90' | '180' | 'year' | 'custom';

export const Dashboard: React.FC<DashboardProps> = ({ expenses }) => {
  const [period, setPeriod] = useState<FilterPeriod>('all');
  const [customStart, setCustomStart] = useState<string>(new Date(new Date().setDate(new Date().getDate() - 7)).toISOString().split('T')[0]);
  const [customEnd, setCustomEnd] = useState<string>(new Date().toISOString().split('T')[0]);

  // Filtragem dos dados baseada no período selecionado
  const filteredExpenses = useMemo(() => {
    if (period === 'all') return expenses;

    const now = new Date();
    let filterDateStart: Date;
    let filterDateEnd: Date = new Date();

    if (period === 'custom') {
      filterDateStart = new Date(customStart);
      filterDateEnd = new Date(customEnd);
      filterDateEnd.setHours(23, 59, 59, 999);
    } else {
      filterDateStart = new Date();
      if (period === '30') filterDateStart.setDate(now.getDate() - 30);
      else if (period === '90') filterDateStart.setDate(now.getDate() - 90);
      else if (period === '180') filterDateStart.setDate(now.getDate() - 180);
      else if (period === 'year') filterDateStart.setFullYear(now.getFullYear(), 0, 1);
    }

    return expenses.filter(e => {
      const d = new Date(e.date);
      return d >= filterDateStart && d <= filterDateEnd;
    });
  }, [expenses, period, customStart, customEnd]);

  const stats = useMemo<CarStats>(() => {
    const totalSpent = filteredExpenses
      .filter(e => e.type !== ExpenseType.SERVICE_REVENUE)
      .reduce((acc, curr) => acc + curr.value, 0);

    const totalServiceRevenue = filteredExpenses
      .filter(e => e.type === ExpenseType.SERVICE_REVENUE)
      .reduce((acc, curr) => acc + curr.value, 0);

    const fuelExpenses = filteredExpenses
      .filter(e => e.type === ExpenseType.FUEL)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    let totalDistance = 0;
    let totalLiters = 0;

    if (fuelExpenses.length > 1) {
      totalDistance = fuelExpenses[fuelExpenses.length - 1].odometer - fuelExpenses[0].odometer;
      totalLiters = fuelExpenses.slice(1).reduce((acc, curr) => acc + (curr.liters || 0), 0);
    }

    const averageConsumption = totalLiters > 0 ? totalDistance / totalLiters : 0;
    const lastOdometer = expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;

    return {
      totalSpent,
      totalLiters: fuelExpenses.reduce((acc, curr) => acc + (curr.liters || 0), 0),
      averageConsumption,
      totalDistance,
      lastOdometer,
      totalServiceRevenue
    };
  }, [filteredExpenses, expenses]);

  const chartData = useMemo(() => {
    return [...filteredExpenses]
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .slice(-15)
      .map(e => ({
        name: new Date(e.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
        valor: e.type === ExpenseType.SERVICE_REVENUE ? 0 : e.value, // Mostrar apenas custos no gráfico de custos
        ganho: e.type === ExpenseType.SERVICE_REVENUE ? e.value : 0
      }));
  }, [filteredExpenses]);

  const fuelEfficiencyData = useMemo(() => {
    return filteredExpenses
      .filter(e => e.type === ExpenseType.FUEL)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .map((e, i, arr) => {
        if (i === 0) return null;
        const prev = arr[i - 1];
        const dist = e.odometer - prev.odometer;
        const efficiency = e.liters ? (dist / e.liters) : 0;
        return {
          date: new Date(e.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
          kmL: parseFloat(efficiency.toFixed(2))
        };
      })
      .filter((item): item is { date: string; kmL: number } => item !== null);
  }, [filteredExpenses]);

  const FilterButton = ({ value, label }: { value: FilterPeriod, label: string }) => (
    <button
      onClick={() => setPeriod(value)}
      className={`px-4 py-2 rounded-xl text-xs font-bold transition-all whitespace-nowrap ${
        period === value 
          ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' 
          : 'bg-white text-slate-500 hover:bg-slate-50 border border-slate-100'
      }`}
    >
      {label}
    </button>
  );

  return (
    <div className="space-y-6">
      <div className="space-y-4">
        <div className="flex items-center gap-3 overflow-x-auto pb-2 scrollbar-hide">
          <div className="p-2 bg-slate-100 rounded-xl text-slate-500 shrink-0">
            <SlidersHorizontal size={18} />
          </div>
          <FilterButton value="30" label="30 dias" />
          <FilterButton value="90" label="90 dias" />
          <FilterButton value="180" label="6 meses" />
          <FilterButton value="year" label="Este Ano" />
          <FilterButton value="custom" label="Personalizado" />
          <FilterButton value="all" label="Tudo" />
        </div>

        {period === 'custom' && (
          <div className="bg-white p-4 rounded-2xl border border-slate-100 flex flex-wrap gap-4 items-end animate-in fade-in slide-in-from-top-2 duration-300">
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Início</label>
              <input 
                type="date" 
                value={customStart}
                onChange={(e) => setCustomStart(e.target.value)}
                className="block w-full p-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Fim</label>
              <input 
                type="date" 
                value={customEnd}
                onChange={(e) => setCustomEnd(e.target.value)}
                className="block w-full p-2 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4">
        <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center space-x-3">
          <div className="p-2.5 bg-blue-50 text-blue-600 rounded-xl">
            <DollarSign size={20} />
          </div>
          <div>
            <p className="text-[9px] font-black text-slate-900 uppercase tracking-widest">Gastos</p>
            <h3 className="text-lg font-black text-slate-900">
              R$ {stats.totalSpent.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
            </h3>
          </div>
        </div>

        <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center space-x-3">
          <div className="p-2.5 bg-emerald-50 text-emerald-600 rounded-xl">
            <HandCoins size={20} />
          </div>
          <div>
            <p className="text-[9px] font-black text-slate-900 uppercase tracking-widest">Ganhos (Km)</p>
            <h3 className="text-lg font-black text-emerald-600">
              R$ {stats.totalServiceRevenue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
            </h3>
          </div>
        </div>

        <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center space-x-3">
          <div className="p-2.5 bg-amber-50 text-amber-600 rounded-xl">
            <Gauge size={20} />
          </div>
          <div>
            <p className="text-[9px] font-black text-slate-900 uppercase tracking-widest">Consumo</p>
            <h3 className="text-lg font-black text-slate-900">
              {stats.averageConsumption.toFixed(2)} <span className="text-[10px] font-bold text-slate-500">km/L</span>
            </h3>
          </div>
        </div>

        <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center space-x-3">
          <div className="p-2.5 bg-violet-50 text-violet-600 rounded-xl">
            <TrendingUp size={20} />
          </div>
          <div>
            <p className="text-[9px] font-black text-slate-900 uppercase tracking-widest">Distância</p>
            <h3 className="text-lg font-black text-slate-900">
              {stats.totalDistance.toLocaleString('pt-BR')} <span className="text-[10px] font-bold text-slate-500">km</span>
            </h3>
          </div>
        </div>

        <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-100 flex items-center space-x-3">
          <div className="p-2.5 bg-slate-50 text-slate-600 rounded-xl">
            <Fuel size={20} />
          </div>
          <div>
            <p className="text-[9px] font-black text-slate-900 uppercase tracking-widest">Odômetro</p>
            <h3 className="text-lg font-black text-slate-900">
              {stats.lastOdometer.toLocaleString('pt-BR')} <span className="text-[10px] font-bold text-slate-500">km</span>
            </h3>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-6">Fluxo Financeiro</h4>
          <div className="h-64">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10, fontWeight: 700}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10, fontWeight: 700}} />
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: 700 }}
                  />
                  <Bar dataKey="valor" name="Custos" fill="#3b82f6" radius={[6, 6, 0, 0]} barSize={20} />
                  <Bar dataKey="ganho" name="Ganhos" fill="#10b981" radius={[6, 6, 0, 0]} barSize={20} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-500 text-sm italic font-medium">
                Sem dados para este intervalo.
              </div>
            )}
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-6">Eficiência (km/L)</h4>
          <div className="h-64">
            {fuelEfficiencyData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={fuelEfficiencyData}>
                  <defs>
                    <linearGradient id="colorKml" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#10b981" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="date" axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10, fontWeight: 700}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10, fontWeight: 700}} />
                  <Tooltip 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: 700 }}
                  />
                  <Area type="monotone" dataKey="kmL" stroke="#10b981" fillOpacity={1} fill="url(#colorKml)" strokeWidth={3} />
                </AreaChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-500 text-sm italic font-medium">
                Selecione um intervalo com abastecimentos.
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

