import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { LocationManager } from './components/LocationManager';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Fuel, Wrench, Gauge, MapPin, Navigation } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'locations'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleAddExpense = (newExpense: Omit<Expense, 'id'>) => {
    const expense: Expense = {
      ...newExpense,
      id: crypto.randomUUID(),
    };
    setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  return (
    <div className="min-h-screen pb-24 md:pb-8 bg-[#F8FAFC]">
      <header className="bg-white border-b border-slate-100 sticky top-0 z-40">
        <div className="max-w-5xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-100">
              <Gauge size={22} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">AutoGasto</h1>
          </div>
          <button 
            onClick={() => setIsFormOpen(true)}
            className="hidden md:flex items-center space-x-2 bg-slate-900 hover:bg-slate-800 text-white px-6 py-2.5 rounded-2xl font-bold transition-all shadow-xl shadow-slate-200"
          >
            <Plus size={20} />
            <span>Novo Lançamento</span>
          </button>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8">
        <div className="flex space-x-2 mb-8 bg-white p-1.5 rounded-[22px] w-fit shadow-sm border border-slate-100">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'dashboard' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <LayoutDashboard size={18} />
            <span>Dashboard</span>
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'history' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <History size={18} />
            <span>Histórico</span>
          </button>
          <button 
            onClick={() => setActiveTab('locations')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'locations' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <MapPin size={18} />
            <span>Locais</span>
          </button>
        </div>

        {activeTab === 'dashboard' && (
          <>
            {expenses.length >= 2 && (
              <div className="mb-8 bg-gradient-to-br from-indigo-600 to-blue-700 rounded-3xl p-6 text-white shadow-2xl shadow-indigo-100 relative overflow-hidden">
                <div className="relative z-10">
                  <div className="flex justify-between items-center mb-6">
                    <div className="flex items-center space-x-2">
                      <Sparkles size={20} className="text-yellow-300" />
                      <h2 className="font-bold text-lg">Inteligência AutoGasto</h2>
                    </div>
                    <button 
                      onClick={fetchAIInsights}
                      disabled={loadingInsights}
                      className="text-[10px] font-black uppercase tracking-widest bg-white/20 hover:bg-white/30 px-4 py-2 rounded-full transition-all"
                    >
                      {loadingInsights ? "Analisando..." : "Analisar Gastos"}
                    </button>
                  </div>

                  {insights.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      {insights.map((tip, idx) => (
                        <div key={idx} className="bg-white/10 backdrop-blur-md p-4 rounded-2xl text-sm border border-white/5 font-medium leading-relaxed">
                          {tip}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <p className="text-white/70 text-sm font-medium">
                      O AutoGasto está pronto para analisar seu perfil de direção. Clique acima para começar.
                    </p>
                  )}
                </div>
              </div>
            )}
            <Dashboard expenses={expenses} />
          </>
        )}

        {activeTab === 'locations' && (
          <LocationManager 
            locations={locations} 
            onAdd={handleAddLocation} 
            onRemove={handleRemoveLocation} 
          />
        )}

        {activeTab === 'history' && (
          <div className="space-y-4">
            {expenses.length === 0 ? (
              <div className="bg-white p-16 text-center text-slate-400 rounded-3xl border border-dashed border-slate-200">
                <History size={48} strokeWidth={1} className="mx-auto mb-4 opacity-20" />
                <p className="font-medium">Nenhum lançamento registrado.</p>
              </div>
            ) : (
              expenses.map(expense => (
                <div key={expense.id} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex flex-col md:flex-row md:items-center gap-6 group transition-all hover:shadow-md">
                  <div className={`p-4 rounded-2xl shrink-0 ${
                    expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-600' : 
                    expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-600' :
                    'bg-emerald-50 text-emerald-600'
                  }`}>
                    {expense.type === ExpenseType.FUEL ? <Fuel size={24} /> : 
                     expense.type === ExpenseType.MAINTENANCE ? <Wrench size={24} /> : 
                     <Navigation size={24} />}
                  </div>

                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-900">
                        {new Date(expense.date).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-900 flex items-center gap-1">
                        <MapPin size={10} /> {getLocationName(expense.locationId)}
                      </span>
                    </div>
                    <h4 className="font-bold text-slate-800 text-lg">
                      {expense.type === ExpenseType.FUEL ? `Abastecimento: ${expense.fuelType}` : 
                       expense.type === ExpenseType.SERVICE_REVENUE ? 'Trajeto de Serviço (Ganhos)' : 
                       'Manutenção Preventiva/Corretiva'}
                    </h4>

                    {expense.maintenanceItems && (
                      <div className="mt-2 flex flex-wrap gap-2">
                        {expense.maintenanceItems.map(item => (
                          <span key={item.id} className="text-[11px] font-semibold bg-slate-50 text-slate-600 px-2 py-1 rounded-lg border border-slate-100">
                            {item.description}: R$ {item.value.toFixed(2)}
                          </span>
                        ))}
                      </div>
                    )}

                    {expense.type === ExpenseType.SERVICE_REVENUE && (
                      <div className="mt-1 text-xs font-bold text-emerald-600">
                        {expense.odometerStart} km ➔ {expense.odometer} km | R$ {expense.ratePerKm?.toFixed(2)} / km
                      </div>
                    )}
                  </div>

                  <div className="text-right shrink-0">
                    <div className="text-[10px] font-black uppercase tracking-widest text-slate-900 mb-1">{expense.odometer.toLocaleString()} KM</div>
                    <div className={`text-2xl font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-600' : 'text-slate-900'}`}>
                      {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </div>
                  </div>

                  <div className="md:border-l md:pl-4">
                    <button 
                      onClick={() => handleDeleteExpense(expense.id)}
                      className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                    >
                      <Trash2 size={20} />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </main>

      <div className="md:hidden fixed bottom-8 right-6 z-30">
        <button 
          onClick={() => setIsFormOpen(true)}
          className="w-16 h-16 bg-blue-600 text-white rounded-2xl shadow-2xl flex items-center justify-center hover:scale-105 transition-transform"
        >
          <Plus size={32} />
        </button>
      </div>

      {isFormOpen && (
        <ExpenseForm 
          lastOdometer={lastOdometer}
          locations={locations}
          onAdd={handleAddExpense} 
          onClose={() => setIsFormOpen(false)} 
        />
      )}
    </div>
  );
};

export default App;

export enum ExpenseType {
  FUEL = 'FUEL',
  MAINTENANCE = 'MAINTENANCE',
  SERVICE_REVENUE = 'SERVICE_REVENUE',
  OTHER = 'OTHER'
}

export type FuelType = 'Gasolina' | 'Etanol' | 'Diesel' | 'GNV';

export interface MaintenanceItem {
  id: string;
  description: string;
  value: number;
}

export interface Location {
  id: string;
  name: string;
  type: 'POSTO' | 'OFICINA' | 'CLIENTE';
}

export interface Expense {
  id: string;
  date: string;
  type: ExpenseType;
  odometer: number; // No caso de serviço, é o odômetro final
  odometerStart?: number; // Específico para serviço
  value: number;
  locationId?: string;
  fuelType?: FuelType;
  liters?: number;
  description: string;
  notes?: string; // Campo para observações personalizadas
  maintenanceItems?: MaintenanceItem[];
  ratePerKm?: number; // Específico para serviço
}

export interface CarStats {
  totalSpent: number;
  totalLiters: number;
  averageConsumption: number;
  totalDistance: number;
  lastOdometer: number;
  totalServiceRevenue: number;
}

import React, { useState, useMemo, useEffect } from 'react';
import { ExpenseType, Expense, Location, FuelType, MaintenanceItem } from '../types';
import { Plus, X, Trash2, MapPin, Navigation, DollarSign, MessageSquare } from 'lucide-react';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'>) => void;
  onClose: () => void;
  lastOdometer: number;
  locations: Location[];
}

export const ExpenseForm: React.FC<ExpenseFormProps> = ({ onAdd, onClose, lastOdometer, locations }) => {
  const [type, setType] = useState<ExpenseType>(ExpenseType.FUEL);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [locationId, setLocationId] = useState<string>('');
  const [notes, setNotes] = useState('');

  // Odometer common
  const [odometer, setOdometer] = useState<string>(lastOdometer.toString());

  // Fuel specific
  const [fuelType, setFuelType] = useState<FuelType>('Gasolina');
  const [fuelValue, setFuelValue] = useState<string>('');
  const [liters, setLiters] = useState<string>('');

  // Maintenance specific
  const [maintItems, setMaintItems] = useState<MaintenanceItem[]>([
    { id: crypto.randomUUID(), description: '', value: 0 }
  ]);

  // Service Revenue specific
  const [odometerStart, setOdometerStart] = useState<string>(lastOdometer.toString());
  const [ratePerKm, setRatePerKm] = useState<string>('0.00');

  const totalValue = useMemo(() => {
    if (type === ExpenseType.FUEL) return parseFloat(fuelValue) || 0;
    if (type === ExpenseType.MAINTENANCE) return maintItems.reduce((acc, item) => acc + (item.value || 0), 0);
    if (type === ExpenseType.SERVICE_REVENUE) {
      const dist = (parseFloat(odometer) || 0) - (parseFloat(odometerStart) || 0);
      return Math.max(0, dist * (parseFloat(ratePerKm) || 0));
    }
    return 0;
  }, [type, fuelValue, maintItems, odometer, odometerStart, ratePerKm]);

  const addMaintItem = () => {
    setMaintItems([...maintItems, { id: crypto.randomUUID(), description: '', value: 0 }]);
  };

  const removeMaintItem = (id: string) => {
    if (maintItems.length > 1) {
      setMaintItems(maintItems.filter(item => item.id !== id));
    }
  };

  const updateMaintItem = (id: string, field: 'description' | 'value', val: string) => {
    setMaintItems(maintItems.map(item => {
      if (item.id === id) {
        return { ...item, [field]: field === 'value' ? parseFloat(val) || 0 : val };
      }
      return item;
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!locationId) {
      alert("Por favor, selecione um local/cliente.");
      return;
    }

    const payload: Omit<Expense, 'id'> = {
      type,
      date,
      odometer: parseFloat(odometer),
      value: totalValue,
      locationId,
      notes: notes.trim(),
      description: type === ExpenseType.FUEL ? fuelType : (type === ExpenseType.SERVICE_REVENUE ? 'Km Rodado' : 'Manutenção Multi-item'),
    };

    if (type === ExpenseType.FUEL) {
      payload.fuelType = fuelType;
      payload.liters = parseFloat(liters);
    } else if (type === ExpenseType.MAINTENANCE) {
      payload.maintenanceItems = maintItems;
    } else if (type === ExpenseType.SERVICE_REVENUE) {
      payload.odometerStart = parseFloat(odometerStart);
      payload.ratePerKm = parseFloat(ratePerKm);
    }

    onAdd(payload);
    onClose();
  };

  const filteredLocations = locations.filter(l => {
    if (type === ExpenseType.FUEL) return l.type === 'POSTO';
    if (type === ExpenseType.MAINTENANCE) return l.type === 'OFICINA';
    return l.type === 'CLIENTE';
  });

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in fade-in zoom-in duration-200 flex flex-col max-h-[90vh]">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center shrink-0">
          <div>
            <h3 className="text-xl font-bold text-slate-900">Novo Lançamento</h3>
            <p className="text-xs text-slate-700 font-bold uppercase tracking-wider">
              {type === ExpenseType.FUEL && 'Abastecimento'}
              {type === ExpenseType.MAINTENANCE && 'Manutenção'}
              {type === ExpenseType.SERVICE_REVENUE && 'Serviço Prestado'}
            </p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-400">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5 overflow-y-auto">
          {/* Tipo de Despesa */}
          <div className="flex bg-slate-100 p-1.5 rounded-2xl">
            <button
              type="button"
              onClick={() => setType(ExpenseType.FUEL)}
              className={`flex-1 py-2.5 px-2 rounded-xl text-[11px] font-black transition-all ${
                type === ExpenseType.FUEL ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-600'
              }`}
            >
              Combustível
            </button>
            <button
              type="button"
              onClick={() => setType(ExpenseType.MAINTENANCE)}
              className={`flex-1 py-2.5 px-2 rounded-xl text-[11px] font-black transition-all ${
                type === ExpenseType.MAINTENANCE ? 'bg-white text-orange-600 shadow-sm' : 'text-slate-600'
              }`}
            >
              Manutenção
            </button>
            <button
              type="button"
              onClick={() => setType(ExpenseType.SERVICE_REVENUE)}
              className={`flex-1 py-2.5 px-2 rounded-xl text-[11px] font-black transition-all ${
                type === ExpenseType.SERVICE_REVENUE ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-600'
              }`}
            >
              Serviço (Km)
            </button>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Data</label>
              <input
                type="date"
                required
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900 font-bold"
              />
            </div>
            {type !== ExpenseType.SERVICE_REVENUE ? (
              <div className="space-y-1">
                <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Odômetro (km)</label>
                <input
                  type="number"
                  required
                  min={lastOdometer}
                  value={odometer}
                  onChange={(e) => setOdometer(e.target.value)}
                  className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900 font-bold"
                />
              </div>
            ) : (
              <div className="space-y-1">
                <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Valor p/ KM (R$)</label>
                <input
                  type="number"
                  step="0.01"
                  required
                  value={ratePerKm}
                  onChange={(e) => setRatePerKm(e.target.value)}
                  className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all text-slate-900 font-black"
                />
              </div>
            )}
          </div>

          {/* Seleção de Local / Cliente */}
          <div className="space-y-1">
            <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">
              {type === ExpenseType.FUEL ? 'Posto' : type === ExpenseType.MAINTENANCE ? 'Oficina' : 'Empresa/Cliente'}
            </label>
            <select
              required
              value={locationId}
              onChange={(e) => setLocationId(e.target.value)}
              className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900 font-bold"
            >
              <option value="">Selecione...</option>
              {filteredLocations.map(loc => (
                <option key={loc.id} value={loc.id}>{loc.name}</option>
              ))}
            </select>
          </div>

          {/* Campos Específicos de Serviço */}
          {type === ExpenseType.SERVICE_REVENUE && (
            <div className="grid grid-cols-2 gap-4 animate-in slide-in-from-top-2">
              <div className="space-y-1">
                <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Km Saída</label>
                <input
                  type="number"
                  required
                  value={odometerStart}
                  onChange={(e) => setOdometerStart(e.target.value)}
                  className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all text-slate-900 font-bold"
                />
              </div>
              <div className="space-y-1">
                <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Km Chegada</label>
                <input
                  type="number"
                  required
                  min={odometerStart}
                  value={odometer}
                  onChange={(e) => setOdometer(e.target.value)}
                  className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all text-slate-900 font-bold"
                />
              </div>
            </div>
          )}

          {/* Campos Dinâmicos Fuel/Maintenance */}
          {type === ExpenseType.FUEL && (
            <div className="space-y-4 animate-in slide-in-from-top-2">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Combustível</label>
                  <select
                    value={fuelType}
                    onChange={(e) => setFuelType(e.target.value as FuelType)}
                    className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900 font-bold"
                  >
                    <option value="Gasolina">Gasolina</option>
                    <option value="Etanol">Etanol</option>
                    <option value="Diesel">Diesel</option>
                    <option value="GNV">GNV</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Valor (R$)</label>
                  <input
                    type="number"
                    step="0.01"
                    required
                    value={fuelValue}
                    onChange={(e) => setFuelValue(e.target.value)}
                    className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900 font-black"
                  />
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Litros</label>
                <input
                  type="number"
                  step="0.01"
                  required
                  value={liters}
                  onChange={(e) => setLiters(e.target.value)}
                  className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900 font-bold"
                />
              </div>
            </div>
          )}

          {type === ExpenseType.MAINTENANCE && (
            <div className="space-y-3 animate-in slide-in-from-top-2">
              <div className="flex justify-between items-center mb-1">
                <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest">Itens da Manutenção</label>
                <button
                  type="button"
                  onClick={addMaintItem}
                  className="text-[11px] font-black text-orange-600 hover:text-orange-700 flex items-center gap-1"
                >
                  <Plus size={14} /> ADICIONAR ITEM
                </button>
              </div>

              {maintItems.map((item) => (
                <div key={item.id} className="flex gap-2 items-end group">
                  <div className="flex-1 space-y-1">
                    <input
                      placeholder="Ex: Troca de óleo"
                      value={item.description}
                      onChange={(e) => updateMaintItem(item.id, 'description', e.target.value)}
                      className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-xl text-sm outline-none focus:border-orange-500 text-slate-900 font-bold placeholder:text-slate-400"
                    />
                  </div>
                  <div className="w-24 space-y-1">
                    <input
                      type="number"
                      step="0.01"
                      placeholder="0,00"
                      value={item.value || ''}
                      onChange={(e) => updateMaintItem(item.id, 'value', e.target.value)}
                      className="w-full p-2.5 bg-slate-50 border border-slate-300 rounded-xl text-sm font-black text-right outline-none focus:border-orange-500 text-slate-900"
                    />
                  </div>
                  <button
                    type="button"
                    onClick={() => removeMaintItem(item.id)}
                    className="p-2.5 text-slate-400 hover:text-red-500 transition-colors"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              ))}
            </div>
          )}

          {/* Campo de Observação */}
          <div className="space-y-1">
            <label className="text-[11px] font-black text-slate-900 uppercase tracking-widest flex items-center gap-2">
              <MessageSquare size={12} /> Observações
            </label>
            <textarea
              placeholder="Algum detalhe importante sobre este lançamento?"
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              rows={2}
              className="w-full p-3 bg-slate-50 border border-slate-300 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none transition-all text-slate-900 font-bold placeholder:text-slate-400 text-sm resize-none"
            />
          </div>

          <div className="pt-4 border-t border-slate-200 flex justify-between items-center">
            <div className="text-slate-900 text-xs font-black uppercase tracking-wider">
              {type === ExpenseType.SERVICE_REVENUE ? 'Total a Receber:' : 'Total do Lançamento:'}
            </div>
            <div className={`text-2xl font-black ${type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-600' : 'text-slate-900'}`}>
              R$ {totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
            </div>
          </div>

          <button
            type="submit"
            className={`w-full py-4 text-white font-black rounded-2xl shadow-xl transition-all flex items-center justify-center space-x-2 ${
              type === ExpenseType.FUEL ? 'bg-blue-600 hover:bg-blue-700 shadow-blue-100' :
              type === ExpenseType.MAINTENANCE ? 'bg-orange-600 hover:bg-orange-700 shadow-orange-100' :
              'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-100'
            }`}
          >
            <span>Salvar Lançamento</span>
          </button>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { LocationManager } from './components/LocationManager';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Fuel, Wrench, Gauge, MapPin, Navigation, MessageSquare } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'locations'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleAddExpense = (newExpense: Omit<Expense, 'id'>) => {
    const expense: Expense = {
      ...newExpense,
      id: crypto.randomUUID(),
    };
    setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  return (
    <div className="min-h-screen pb-24 md:pb-8 bg-[#F8FAFC]">
      <header className="bg-white border-b border-slate-100 sticky top-0 z-40">
        <div className="max-w-5xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-100">
              <Gauge size={22} />
            </div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">AutoGasto</h1>
          </div>
          <button 
            onClick={() => setIsFormOpen(true)}
            className="hidden md:flex items-center space-x-2 bg-slate-900 hover:bg-slate-800 text-white px-6 py-2.5 rounded-2xl font-bold transition-all shadow-xl shadow-slate-200"
          >
            <Plus size={20} />
            <span>Novo Lançamento</span>
          </button>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8">
        <div className="flex space-x-2 mb-8 bg-white p-1.5 rounded-[22px] w-fit shadow-sm border border-slate-100">
          <button 
            onClick={() => setActiveTab('dashboard')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'dashboard' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <LayoutDashboard size={18} />
            <span>Dashboard</span>
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'history' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <History size={18} />
            <span>Histórico</span>
          </button>
          <button 
            onClick={() => setActiveTab('locations')}
            className={`flex items-center space-x-2 px-6 py-2.5 rounded-2xl font-bold transition-all text-sm ${
              activeTab === 'locations' ? 'bg-slate-800 text-white' : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <MapPin size={18} />
            <span>Locais</span>
          </button>
        </div>

        {activeTab === 'dashboard' && (
          <>
            {expenses.length >= 2 && (
              <div className="mb-8 bg-gradient-to-br from-indigo-600 to-blue-700 rounded-3xl p-6 text-white shadow-2xl shadow-indigo-100 relative overflow-hidden">
                <div className="relative z-10">
                  <div className="flex justify-between items-center mb-6">
                    <div className="flex items-center space-x-2">
                      <Sparkles size={20} className="text-yellow-300" />
                      <h2 className="font-bold text-lg">Inteligência AutoGasto</h2>
                    </div>
                    <button 
                      onClick={fetchAIInsights}
                      disabled={loadingInsights}
                      className="text-[10px] font-black uppercase tracking-widest bg-white/20 hover:bg-white/30 px-4 py-2 rounded-full transition-all"
                    >
                      {loadingInsights ? "Analisando..." : "Analisar Gastos"}
                    </button>
                  </div>

                  {insights.length > 0 ? (
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                      {insights.map((tip, idx) => (
                        <div key={idx} className="bg-white/10 backdrop-blur-md p-4 rounded-2xl text-sm border border-white/5 font-medium leading-relaxed">
                          {tip}
                        </div>
                      ))}
                    </div>
                  ) : (
                    <p className="text-white/70 text-sm font-medium">
                      O AutoGasto está pronto para analisar seu perfil de direção. Clique acima para começar.
                    </p>
                  )}
                </div>
              </div>
            )}
            <Dashboard expenses={expenses} />
          </>
        )}

        {activeTab === 'locations' && (
          <LocationManager 
            locations={locations} 
            onAdd={handleAddLocation} 
            onRemove={handleRemoveLocation} 
          />
        )}

        {activeTab === 'history' && (
          <div className="space-y-4">
            {expenses.length === 0 ? (
              <div className="bg-white p-16 text-center text-slate-400 rounded-3xl border border-dashed border-slate-200">
                <History size={48} strokeWidth={1} className="mx-auto mb-4 opacity-20" />
                <p className="font-medium">Nenhum lançamento registrado.</p>
              </div>
            ) : (
              expenses.map(expense => (
                <div key={expense.id} className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex flex-col md:flex-row md:items-center gap-6 group transition-all hover:shadow-md">
                  <div className={`p-4 rounded-2xl shrink-0 ${
                    expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-600' : 
                    expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-600' :
                    'bg-emerald-50 text-emerald-600'
                  }`}>
                    {expense.type === ExpenseType.FUEL ? <Fuel size={24} /> : 
                     expense.type === ExpenseType.MAINTENANCE ? <Wrench size={24} /> : 
                     <Navigation size={24} />}
                  </div>

                  <div className="flex-1">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-900">
                        {new Date(expense.date).toLocaleDateString('pt-BR')}
                      </span>
                      <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                      <span className="text-[10px] font-black uppercase tracking-widest text-slate-900 flex items-center gap-1">
                        <MapPin size={10} /> {getLocationName(expense.locationId)}
                      </span>
                    </div>
                    <h4 className="font-bold text-slate-800 text-lg">
                      {expense.type === ExpenseType.FUEL ? `Abastecimento: ${expense.fuelType}` : 
                       expense.type === ExpenseType.SERVICE_REVENUE ? 'Trajeto de Serviço (Ganhos)' : 
                       'Manutenção Preventiva/Corretiva'}
                    </h4>

                    {expense.maintenanceItems && (
                      <div className="mt-2 flex flex-wrap gap-2">
                        {expense.maintenanceItems.map(item => (
                          <span key={item.id} className="text-[11px] font-semibold bg-slate-50 text-slate-600 px-2 py-1 rounded-lg border border-slate-100">
                            {item.description}: R$ {item.value.toFixed(2)}
                          </span>
                        ))}
                      </div>
                    )}

                    {expense.type === ExpenseType.SERVICE_REVENUE && (
                      <div className="mt-1 text-xs font-bold text-emerald-600">
                        {expense.odometerStart} km ➔ {expense.odometer} km | R$ {expense.ratePerKm?.toFixed(2)} / km
                      </div>
                    )}

                    {expense.notes && (
                      <div className="mt-3 flex items-start gap-2 bg-slate-50 p-2.5 rounded-xl border border-slate-100 text-xs text-slate-600 font-medium italic italic">
                        <MessageSquare size={14} className="shrink-0 text-slate-400 mt-0.5" />
                        "{expense.notes}"
                      </div>
                    )}
                  </div>

                  <div className="text-right shrink-0">
                    <div className="text-[10px] font-black uppercase tracking-widest text-slate-900 mb-1">{expense.odometer.toLocaleString()} KM</div>
                    <div className={`text-2xl font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-600' : 'text-slate-900'}`}>
                      {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                    </div>
                  </div>

                  <div className="md:border-l md:pl-4">
                    <button 
                      onClick={() => handleDeleteExpense(expense.id)}
                      className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
                    >
                      <Trash2 size={20} />
                    </button>
                  </div>
                </div>
              ))
            )}
          </div>
        )}
      </main>

      <div className="md:hidden fixed bottom-8 right-6 z-30">
        <button 
          onClick={() => setIsFormOpen(true)}
          className="w-16 h-16 bg-blue-600 text-white rounded-2xl shadow-2xl flex items-center justify-center hover:scale-105 transition-transform"
        >
          <Plus size={32} />
        </button>
      </div>

      {isFormOpen && (
        <ExpenseForm 
          lastOdometer={lastOdometer}
          locations={locations}
          onAdd={handleAddExpense} 
          onClose={() => setIsFormOpen(false)} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Expense, ExpenseType, Location } from '../types';
import { FileText, Printer, Calendar, Filter, Fuel, Wrench, Navigation, DollarSign, HandCoins } from 'lucide-react';

interface ReportsProps {
  expenses: Expense[];
  locations: Location[];
}

type ReportType = 'ALL' | 'FUEL' | 'MAINTENANCE' | 'SERVICE';

export const Reports: React.FC<ReportsProps> = ({ expenses, locations }) => {
  const [startDate, setStartDate] = useState<string>(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [reportType, setReportType] = useState<ReportType>('ALL');

  const filteredData = useMemo(() => {
    return expenses.filter(e => {
      const date = new Date(e.date);
      const start = new Date(startDate);
      const end = new Date(endDate);
      end.setHours(23, 59, 59, 999);

      const matchesDate = date >= start && date <= end;
      const matchesType = 
        reportType === 'ALL' || 
        (reportType === 'FUEL' && e.type === ExpenseType.FUEL) ||
        (reportType === 'MAINTENANCE' && e.type === ExpenseType.MAINTENANCE) ||
        (reportType === 'SERVICE' && e.type === ExpenseType.SERVICE_REVENUE);

      return matchesDate && matchesType;
    }).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [expenses, startDate, endDate, reportType]);

  const totals = useMemo(() => {
    return filteredData.reduce((acc, curr) => {
      if (curr.type === ExpenseType.SERVICE_REVENUE) {
        acc.earned += curr.value;
      } else {
        acc.spent += curr.value;
      }
      return acc;
    }, { spent: 0, earned: 0 });
  }, [filteredData]);

  const getLocationName = (id?: string) => locations.find(l => l.id === id)?.name || 'N/A';

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="space-y-6">
      {/* Filtros de Relatório */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 no-print">
        <div className="flex items-center gap-2 mb-6">
          <div className="p-2 bg-blue-50 text-blue-600 rounded-xl">
            <Filter size={20} />
          </div>
          <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">Filtros do Relatório</h3>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Data Início</label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input 
                type="date" 
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Data Fim</label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input 
                type="date" 
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Tipo de Lançamento</label>
            <select 
              value={reportType}
              onChange={(e) => setReportType(e.target.value as ReportType)}
              className="w-full p-3 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500 appearance-none cursor-pointer"
            >
              <option value="ALL">Todos os Tipos</option>
              <option value="FUEL">Apenas Combustível</option>
              <option value="MAINTENANCE">Apenas Manutenção</option>
              <option value="SERVICE">Apenas Serviços (Km)</option>
            </select>
          </div>

          <button 
            onClick={handlePrint}
            className="bg-slate-900 text-white p-3 rounded-2xl font-black flex items-center justify-center gap-2 hover:bg-slate-800 transition-all shadow-lg active:scale-95"
          >
            <Printer size={18} />
            Imprimir Relatório
          </button>
        </div>
      </div>

      {/* Conteúdo do Relatório */}
      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden print:shadow-none print:border-none">
        {/* Cabeçalho do Relatório para Impressão */}
        <div className="p-8 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <FileText size={24} className="text-blue-600" />
              <h2 className="text-2xl font-black text-slate-900 tracking-tight">Relatório de Atividades</h2>
            </div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">
              Período: {new Date(startDate).toLocaleDateString()} até {new Date(endDate).toLocaleDateString()}
            </p>
          </div>

          <div className="flex gap-4">
            <div className="bg-white p-4 rounded-2xl border border-slate-200 min-w-[140px] shadow-sm">
              <p className="text-[9px] font-black text-slate-500 uppercase mb-1">Total Gasto</p>
              <p className="text-xl font-black text-red-600">R$ {totals.spent.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            </div>
            <div className="bg-white p-4 rounded-2xl border border-slate-200 min-w-[140px] shadow-sm">
              <p className="text-[9px] font-black text-slate-500 uppercase mb-1">Total Ganho</p>
              <p className="text-xl font-black text-emerald-600">R$ {totals.earned.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            </div>
          </div>
        </div>

        {/* Tabela de Dados */}
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/50">
                <th className="px-6 py-4 text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100">Data</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100">Tipo</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100">Local / Cliente</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100 text-right">KM</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100 text-right">Valor</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredData.map((e) => (
                <tr key={e.id} className="hover:bg-slate-50/30 transition-colors">
                  <td className="px-6 py-4 text-xs font-bold text-slate-900">
                    {new Date(e.date).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <div className={`p-1.5 rounded-lg ${
                        e.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-600' : 
                        e.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-600' : 
                        'bg-emerald-50 text-emerald-600'
                      }`}>
                        {e.type === ExpenseType.FUEL ? <Fuel size={14} /> : 
                         e.type === ExpenseType.MAINTENANCE ? <Wrench size={14} /> : 
                         <Navigation size={14} />}
                      </div>
                      <span className="text-xs font-bold text-slate-900">
                        {e.type === ExpenseType.FUEL ? 'Combustível' : 
                         e.type === ExpenseType.MAINTENANCE ? 'Manutenção' : 
                         'Serviço'}
                      </span>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-xs font-bold text-slate-900">{getLocationName(e.locationId)}</span>
                      <span className="text-[10px] text-slate-500 font-medium truncate max-w-[200px]">{e.description}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right text-xs font-bold text-slate-900">
                    {e.odometer.toLocaleString()}
                  </td>
                  <td className={`px-6 py-4 text-right text-sm font-black ${
                    e.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-600' : 'text-slate-900'
                  }`}>
                    {e.type === ExpenseType.SERVICE_REVENUE ? '+' : '-'} R$ {e.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </td>
                </tr>
              ))}
              {filteredData.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-6 py-20 text-center">
                    <div className="flex flex-col items-center gap-2 text-slate-400">
                      <FileText size={40} strokeWidth={1} className="opacity-20" />
                      <p className="text-sm font-medium italic">Nenhum lançamento encontrado para os filtros selecionados.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <style>{`
        @media print {
          body { background: white !important; }
          .no-print { display: none !important; }
          #root { padding: 0 !important; margin: 0 !important; }
          main { padding: 0 !important; max-width: 100% !important; }
          .print\\:shadow-none { box-shadow: none !important; }
          .print\\:border-none { border: none !important; }
          header, nav { display: none !important; }
        }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { LocationManager } from './components/LocationManager';
import { Reports } from './components/Reports';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Fuel, Wrench, Gauge, MapPin, Navigation, MessageSquare, FileText } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'locations' | 'reports'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

