                      )}
                    </div>

                    <div className="text-right shrink-0">
                      <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-1">{expense.odometer.toLocaleString()} KM TOTAL</div>
                      <div className={`text-3xl font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-600' : 'text-slate-900'}`}>
                        {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
