import React, { useState, useMemo } from 'react';
import { Expense, ExpenseType, Location, PaymentMethod } from '../types';
import { FileText, Printer, Calendar, Filter, Fuel, Wrench, Navigation, DollarSign, HandCoins, CheckCircle2, Clock, Zap, CreditCard, Wallet } from 'lucide-react';

interface ReportsProps {
  expenses: Expense[];
  locations: Location[];
}

type ReportType = 'ALL' | 'FUEL' | 'MAINTENANCE' | 'SERVICE';
type StatusFilter = 'ALL' | 'RECEIVED' | 'PENDING';
type PaymentFilter = 'ALL' | PaymentMethod;

export const Reports: React.FC<ReportsProps> = ({ expenses, locations }) => {
  const [startDate, setStartDate] = useState<string>(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [reportType, setReportType] = useState<ReportType>('ALL');
  const [statusFilter, setStatusFilter] = useState<StatusFilter>('ALL');
  const [paymentFilter, setPaymentFilter] = useState<PaymentFilter>('ALL');

  const filteredData = useMemo(() => {
    return expenses.filter(e => {
      const date = new Date(e.date);
      const start = new Date(startDate);
      const end = new Date(endDate);
      end.setHours(23, 59, 59, 999);

      const matchesDate = date >= start && date <= end;

      const matchesType = 
        reportType === 'ALL' || 
        (reportType === 'FUEL' && e.type === ExpenseType.FUEL) ||
        (reportType === 'MAINTENANCE' && e.type === ExpenseType.MAINTENANCE) ||
        (reportType === 'SERVICE' && e.type === ExpenseType.SERVICE_REVENUE);

      const matchesStatus = 
        statusFilter === 'ALL' ||
        (e.type === ExpenseType.SERVICE_REVENUE && e.status === statusFilter) ||
        (e.type !== ExpenseType.SERVICE_REVENUE && statusFilter === 'RECEIVED');

      const matchesPayment = 
        paymentFilter === 'ALL' || 
        e.paymentMethod === paymentFilter;

      return matchesDate && matchesType && matchesStatus && matchesPayment;
    }).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [expenses, startDate, endDate, reportType, statusFilter, paymentFilter]);

  const totals = useMemo(() => {
    return filteredData.reduce((acc, curr) => {
      if (curr.type === ExpenseType.SERVICE_REVENUE) {
        if (curr.status === 'RECEIVED') acc.earned += curr.value;
        else acc.pending += curr.value;
      } else {
        acc.spent += curr.value;
      }
      return acc;
    }, { spent: 0, earned: 0, pending: 0 });
  }, [filteredData]);

  const getLocationName = (id?: string) => locations.find(l => l.id === id)?.name || 'N/A';

  const getPaymentMethodIcon = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return <Zap size={12} />;
      case 'CREDITO': return <CreditCard size={12} />;
      case 'DEBITO': return <CreditCard size={12} />;
      case 'DINHEIRO': return <Wallet size={12} />;
      default: return null;
    }
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="space-y-6">
      {/* Filtros de Relatório */}
      <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 no-print">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-2">
            <div className="p-2 bg-blue-50 text-blue-600 rounded-xl">
              <Filter size={20} />
            </div>
            <h3 className="text-lg font-black text-slate-900 uppercase tracking-tight">Filtros do Relatório</h3>
          </div>
          <button 
            onClick={handlePrint}
            className="bg-slate-900 text-white px-6 py-2.5 rounded-2xl font-black flex items-center gap-2 hover:bg-slate-800 transition-all shadow-lg active:scale-95 text-sm"
          >
            <Printer size={18} />
            Imprimir
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4 items-end">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Período (Início)</label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input 
                type="date" 
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Período (Fim)</label>
            <div className="relative">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={16} />
              <input 
                type="date" 
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
                className="w-full pl-10 pr-4 py-3 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Tipo</label>
            <select 
              value={reportType}
              onChange={(e) => setReportType(e.target.value as ReportType)}
              className="w-full p-3 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500 appearance-none cursor-pointer"
            >
              <option value="ALL">Todos os Tipos</option>
              <option value="FUEL">Combustível</option>
              <option value="MAINTENANCE">Manutenção</option>
              <option value="SERVICE">Serviços (Km)</option>
            </select>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Status</label>
            <select 
              value={statusFilter}
              onChange={(e) => setStatusFilter(e.target.value as StatusFilter)}
              className="w-full p-3 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500 appearance-none cursor-pointer"
            >
              <option value="ALL">Todos os Status</option>
              <option value="RECEIVED">Recebidos / Pagos</option>
              <option value="PENDING">Em Aberto / Pendente</option>
            </select>
          </div>

          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest ml-1">Pagamento</label>
            <select 
              value={paymentFilter}
              onChange={(e) => setPaymentFilter(e.target.value as PaymentFilter)}
              className="w-full p-3 bg-slate-50 border border-slate-300 rounded-2xl text-sm font-bold text-slate-900 outline-none focus:ring-2 focus:ring-blue-500 appearance-none cursor-pointer"
            >
              <option value="ALL">Todas Formas</option>
              <option value="PIX">PIX</option>
              <option value="CREDITO">Crédito</option>
              <option value="DEBITO">Débito</option>
              <option value="DINHEIRO">Dinheiro</option>
            </select>
          </div>
        </div>
      </div>

      {/* Conteúdo do Relatório */}
      <div className="bg-white rounded-[40px] shadow-sm border border-slate-100 overflow-hidden print:shadow-none print:border-none">
        {/* Cabeçalho do Relatório para Impressão */}
        <div className="p-8 border-b border-slate-100 bg-slate-50/50 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <FileText size={24} className="text-blue-600" />
              <h2 className="text-2xl font-black text-slate-900 tracking-tight">Relatório de Atividades</h2>
            </div>
            <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">
              Período: {new Date(startDate).toLocaleDateString()} até {new Date(endDate).toLocaleDateString()}
              {statusFilter !== 'ALL' && ` • Status: ${statusFilter === 'RECEIVED' ? 'Recebidos' : 'Em Aberto'}`}
              {paymentFilter !== 'ALL' && ` • Pagamento: ${paymentFilter}`}
            </p>
          </div>

          <div className="flex flex-wrap gap-4">
            <div className="bg-white p-4 rounded-2xl border border-slate-200 min-w-[140px] shadow-sm">
              <p className="text-[9px] font-black text-slate-500 uppercase mb-1">Total Gasto</p>
              <p className="text-xl font-black text-red-600">R$ {totals.spent.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            </div>
            <div className="bg-white p-4 rounded-2xl border border-slate-200 min-w-[140px] shadow-sm">
              <p className="text-[9px] font-black text-slate-500 uppercase mb-1">Total Recebido</p>
              <p className="text-xl font-black text-emerald-600">R$ {totals.earned.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            </div>
            {totals.pending > 0 && (
              <div className="bg-amber-50 p-4 rounded-2xl border border-amber-200 min-w-[140px] shadow-sm">
                <p className="text-[9px] font-black text-amber-700 uppercase mb-1">Em Aberto</p>
                <p className="text-xl font-black text-amber-700">R$ {totals.pending.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
              </div>
            )}
          </div>
        </div>

        {/* Tabela de Dados */}
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/50">
                <th className="px-6 py-4 text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100">Data</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100">Tipo / Pagamento</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100">Local / Cliente</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100 text-right">KM</th>
                <th className="px-6 py-4 text-[10px] font-black text-slate-900 uppercase tracking-widest border-b border-slate-100 text-right">Valor / Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredData.map((e) => (
                <tr key={e.id} className="hover:bg-slate-50/30 transition-colors">
                  <td className="px-6 py-4 text-xs font-bold text-slate-900">
                    {new Date(e.date).toLocaleDateString()}
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <div className={`p-1.5 rounded-lg ${
                        e.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-600' : 
                        e.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-600' : 
                        'bg-emerald-50 text-emerald-600'
                      }`}>
                        {e.type === ExpenseType.FUEL ? <Fuel size={14} /> : 
                         e.type === ExpenseType.MAINTENANCE ? <Wrench size={14} /> : 
                         <Navigation size={14} />}
                      </div>
                      <div className="flex flex-col">
                        <span className="text-xs font-bold text-slate-900">
                          {e.type === ExpenseType.FUEL ? 'Combustível' : e.type === ExpenseType.MAINTENANCE ? 'Manutenção' : 'Serviço'}
                        </span>
                        <span className="text-[9px] font-black uppercase text-slate-400 flex items-center gap-1">
                          {getPaymentMethodIcon(e.paymentMethod)} {e.paymentMethod}
                        </span>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-xs font-bold text-slate-900">{getLocationName(e.locationId)}</span>
                      <span className="text-[10px] text-slate-500 font-medium truncate max-w-[200px]">{e.description}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-right text-xs font-bold text-slate-900">
                    {e.odometer.toLocaleString()}
                  </td>
                  <td className="px-6 py-4 text-right">
                    <div className="flex flex-col items-end">
                      <span className={`text-sm font-black ${
                        e.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-600' : 'text-slate-900'
                      }`}>
                        {e.type === ExpenseType.SERVICE_REVENUE ? '+' : '-'} R$ {e.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </span>
                      {e.type === ExpenseType.SERVICE_REVENUE && (
                        <span className={`text-[8px] font-black uppercase tracking-widest flex items-center gap-1 ${
                          e.status === 'RECEIVED' ? 'text-emerald-500' : 'text-amber-500'
                        }`}>
                          {e.status === 'RECEIVED' ? <CheckCircle2 size={8} /> : <Clock size={8} />}
                          {e.status === 'RECEIVED' ? 'Recebido' : 'Em Aberto'}
                        </span>
                      )}
                    </div>
                  </td>
                </tr>
              ))}
              {filteredData.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-6 py-20 text-center">
                    <div className="flex flex-col items-center gap-2 text-slate-400">
                      <FileText size={40} strokeWidth={1} className="opacity-20" />
                      <p className="text-sm font-medium italic">Nenhum lançamento encontrado para os filtros selecionados.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location, PaymentMethod } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { LocationManager } from './components/LocationManager';
import { Reports } from './components/Reports';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Fuel, Wrench, Gauge, MapPin, Navigation, MessageSquare, FileText, Printer, ChevronRight, CheckCircle2, Clock, Zap, CreditCard, Wallet } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'locations' | 'reports'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleAddExpense = (newExpense: Omit<Expense, 'id'>) => {
    const expense: Expense = {
      ...newExpense,
      id: crypto.randomUUID(),
    };
    setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  const getPaymentMethodLabel = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return { label: 'PIX', icon: <Zap size={10} /> };
      case 'CREDITO': return { label: 'Crédito', icon: <CreditCard size={10} /> };
      case 'DEBITO': return { label: 'Débito', icon: <CreditCard size={10} /> };
      case 'DINHEIRO': return { label: 'Dinheiro', icon: <Wallet size={10} /> };
      default: return { label: '-', icon: null };
    }
  };

  const NavItem = ({ id, icon: Icon, label, colorClass }: { id: any, icon: any, label: string, colorClass: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex items-center w-full p-4 mb-2 rounded-2xl transition-all duration-300 group ${
        activeTab === id 
          ? `bg-slate-900 text-white shadow-xl shadow-slate-200` 
          : `text-slate-500 hover:bg-slate-50`
