    >
      <div className={`shrink-0 ${activeTab === id ? 'text-white' : colorClass}`}>
        <Icon size={24} />
      </div>
      <span className={`ml-4 font-black text-sm whitespace-nowrap overflow-hidden transition-all duration-300 opacity-0 group-hover:opacity-100 group-hover:w-auto w-0`}>
        {label}
      </span>
      {activeTab === id && (
        <div className="ml-auto opacity-0 group-hover:opacity-100 transition-opacity">
           <ChevronRight size={16} />
        </div>
      )}
    </button>
  );

  const MobileNavItem = ({ id, icon: Icon, label }: { id: any, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center gap-1 w-full py-2 transition-all ${
        activeTab === id ? 'text-blue-600' : 'text-slate-400'
      }`}
    >
      <Icon size={22} className={activeTab === id ? 'animate-bounce' : ''} />
      <span className="text-[10px] font-black uppercase tracking-tighter">{label}</span>
    </button>
  );

  return (
    <div className="flex min-h-screen bg-[#F8FAFC]">
      {/* Sidebar Desktop (Hidden on Mobile) */}
      <aside className="hidden md:flex fixed left-0 top-0 h-full z-50 bg-white border-r border-slate-100 transition-all duration-300 ease-in-out w-20 hover:w-64 group no-print shadow-2xl shadow-slate-200">
        <div className="flex flex-col h-full p-4">
          <div className="flex items-center mb-10 overflow-hidden">
            <div className="w-12 h-12 bg-blue-600 rounded-xl shrink-0 flex items-center justify-center text-white shadow-lg shadow-blue-100">
              <Gauge size={28} />
            </div>
            <span className="ml-4 text-xl font-black text-slate-800 tracking-tight opacity-0 group-hover:opacity-100 transition-opacity duration-300">
              AutoGasto
            </span>
          </div>
          <nav className="flex-1">
            <NavItem id="dashboard" icon={LayoutDashboard} label="Dashboard" colorClass="text-blue-500" />
            <NavItem id="history" icon={History} label="Histórico" colorClass="text-slate-600" />
            <NavItem id="reports" icon={FileText} label="Relatórios" colorClass="text-indigo-500" />
            <NavItem id="locations" icon={MapPin} label="Locais/Clientes" colorClass="text-emerald-500" />
          </nav>
          <button 
            onClick={() => setIsFormOpen(true)}
            className="flex items-center justify-center w-full p-4 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl font-black transition-all shadow-xl shadow-emerald-100 mb-4"
          >
            <Plus size={24} className="shrink-0" />
            <span className="ml-3 overflow-hidden whitespace-nowrap transition-all duration-300 opacity-0 group-hover:opacity-100 group-hover:w-auto w-0">
              Novo Lançamento
            </span>
          </button>
        </div>
      </aside>

      {/* Navigation Mobile (Hidden on Desktop) */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 flex md:hidden items-center justify-around z-50 no-print safe-area-bottom shadow-[0_-10px_25px_-5px_rgba(0,0,0,0.05)] h-20 px-2">
        <MobileNavItem id="dashboard" icon={LayoutDashboard} label="Home" />
        <MobileNavItem id="history" icon={History} label="Histórico" />
        <div className="w-16"></div> {/* Spacer for FAB */}
        <MobileNavItem id="reports" icon={FileText} label="Relatórios" />
        <MobileNavItem id="locations" icon={MapPin} label="Locais" />
      </nav>

      {/* FAB Mobile (Centered slightly above Nav) */}
      <button 
        onClick={() => setIsFormOpen(true)}
        className="md:hidden fixed bottom-6 left-1/2 -translate-x-1/2 w-16 h-16 bg-blue-600 text-white rounded-2xl shadow-2xl z-[60] flex items-center justify-center active:scale-90 transition-transform no-print border-4 border-white"
      >
        <Plus size={32} strokeWidth={3} />
      </button>

      {/* Main Content */}
      <div className="flex-1 md:ml-20 transition-all duration-300 pb-24 md:pb-0">
        <header className="bg-white/80 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 no-print">
          <div className="max-w-5xl mx-auto px-4 md:px-6 py-4 md:py-5 flex justify-between items-center">
            <h2 className="text-lg md:text-xl font-black text-slate-900 uppercase tracking-tight truncate pr-4">
              {activeTab === 'dashboard' && 'Visão Geral'}
              {activeTab === 'history' && 'Histórico'}
              {activeTab === 'reports' && 'Relatórios'}
              {activeTab === 'locations' && 'Locais'}
            </h2>

            <div className="flex items-center gap-4 shrink-0">
              <span className="text-[10px] md:text-xs font-black text-slate-400 uppercase tracking-widest bg-slate-50 px-3 py-1.5 rounded-full border border-slate-100">
                Km: {lastOdometer.toLocaleString()}
              </span>
            </div>
