                  <div className="absolute top-0 right-0 w-48 md:w-64 h-48 md:h-64 bg-white/10 rounded-full -mr-24 md:-mr-32 -mt-24 md:-mt-32 blur-3xl"></div>
                  <div className="relative z-10">
                    <div className="flex justify-between items-center mb-4 md:mb-6">
                      <div className="flex items-center space-x-2 md:space-x-3">
                        <div className="p-2 bg-yellow-400 rounded-lg text-slate-900">
                          <Sparkles size={18} />
                        </div>
                        <h2 className="font-black text-lg md:text-xl tracking-tight">Dicas da IA</h2>
