          {activeTab === 'reports' && (
            <div className="animate-in slide-in-from-left-4 duration-300">
              <Reports 
                expenses={expenses} 
                locations={locations} 
              />
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-4 animate-in slide-in-from-left-4 duration-300">
              {expenses.length > 0 && (
                <div className="flex justify-between items-center mb-4 md:mb-6 no-print">
                  <div>
                    <h3 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">Histórico</h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Todos os registros</p>
                  </div>
                  <button 
                    onClick={() => window.print()}
                    className="flex items-center gap-2 px-4 md:px-6 py-2 md:py-3 bg-white border border-slate-200 rounded-2xl text-xs md:text-sm font-black text-slate-700 hover:bg-slate-50 transition-all shadow-sm active:scale-95"
                  >
                    <Printer size={18} />
                    PDF
                  </button>
                </div>
              )}

              {expenses.length === 0 ? (
                <div className="bg-white p-12 md:p-20 text-center text-slate-400 rounded-[32px] md:rounded-[40px] border-4 border-dashed border-slate-50">
                  <History size={48} md:size={64} strokeWidth={1} className="mx-auto mb-4 md:mb-6 opacity-20" />
                  <p className="text-lg md:text-xl font-bold text-slate-300">Nenhuma atividade registrada.</p>
                </div>
              ) : (
                expenses.map(expense => (
                  <div key={expense.id} className="bg-white rounded-[24px] md:rounded-[32px] p-5 md:p-7 shadow-sm border border-slate-100 flex flex-col md:flex-row md:items-center gap-4 md:gap-6 group transition-all hover:shadow-xl hover:shadow-slate-200/50 print:mb-4">
                    <div className={`p-4 md:p-5 rounded-2xl md:rounded-3xl shrink-0 transition-transform group-hover:scale-105 duration-300 w-fit ${
                      expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-600' : 
                      expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-600' :
                      'bg-emerald-50 text-emerald-600'
                    }`}>
                      {expense.type === ExpenseType.FUEL ? <Fuel size={24} /> : 
                       expense.type === ExpenseType.MAINTENANCE ? <Wrench size={24} /> : 
                       <Navigation size={24} />}
                    </div>

                    <div className="flex-1">
                      <div className="flex flex-wrap items-center gap-2 mb-1.5 md:mb-2">
                        <span className="text-[10px] font-black uppercase tracking-widest text-slate-400 bg-slate-50 px-2.5 py-1 rounded-full border border-slate-100">
                          {new Date(expense.date).toLocaleDateString('pt-BR')}
                        </span>
                        <span className="text-[10px] font-black uppercase tracking-widest text-slate-500 flex items-center gap-1">
                          <MapPin size={10} className="text-slate-300" /> {getLocationName(expense.locationId)}
                        </span>

                        <div className="flex items-center gap-2 ml-auto">
                          {expense.paymentMethod && (
                            <span className="text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full bg-slate-100 text-slate-400 flex items-center gap-1">
                              {getPaymentMethodLabel(expense.paymentMethod).icon}
                              {getPaymentMethodLabel(expense.paymentMethod).label}
                            </span>
                          )}
                          {expense.type === ExpenseType.SERVICE_REVENUE && (
                            <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full flex items-center gap-1 ${
                              expense.status === 'RECEIVED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                            }`}>
                              {expense.status === 'RECEIVED' ? 'OK' : 'Pendente'}
                            </span>
                          )}
                        </div>
                      </div>
                      <h4 className="font-black text-slate-800 text-base md:text-xl tracking-tight truncate max-w-[200px] md:max-w-none">
                        {expense.type === ExpenseType.FUEL ? `${expense.fuelType}` : 
                         expense.type === ExpenseType.SERVICE_REVENUE ? 'Serviço' : 
                         'Manutenção'}
                      </h4>

                      {expense.type === ExpenseType.SERVICE_REVENUE && (
                        <div className="mt-1 text-[10px] font-black text-emerald-600 bg-emerald-50 inline-block px-2 py-0.5 rounded-md">
                          {expense.odometerStart} ➔ {expense.odometer} km
                        </div>
                      )}

                      {expense.notes && (
                        <p className="mt-2 text-[11px] text-slate-400 font-medium italic line-clamp-2">
                          "{expense.notes}"
                        </p>
                      )}
                    </div>

                    <div className="flex justify-between items-center md:flex-col md:items-end md:text-right shrink-0 border-t md:border-t-0 md:border-l border-slate-50 pt-3 md:pt-0 md:pl-6">
                      <div className="md:mb-1">
                        <div className="text-[9px] font-black uppercase tracking-widest text-slate-300 md:mb-0.5">{expense.odometer.toLocaleString()} KM</div>
                        <div className={`text-xl md:text-2xl font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-600' : 'text-slate-900'}`}>
                          {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                        </div>
                      </div>

                      <button 
                        onClick={() => handleDeleteExpense(expense.id)}
                        className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all active:scale-90 no-print"
                      >
                        <Trash2 size={20} />
                      </button>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </main>
      </div>

      {isFormOpen && (
        <ExpenseForm 
          lastOdometer={lastOdometer}
          locations={locations}
          onAdd={handleAddExpense} 
          onClose={() => setIsFormOpen(false)} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { ExpenseType, Expense, Location, FuelType, MaintenanceItem, PaymentMethod } from '../types';
import { Plus, X, Trash2, MapPin, Navigation, DollarSign, MessageSquare, CheckCircle2, Clock, CreditCard, Wallet, Zap } from 'lucide-react';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'>) => void;
  onClose: () => void;
  lastOdometer: number;
  locations: Location[];
}

export const ExpenseForm: React.FC<ExpenseFormProps> = ({ onAdd, onClose, lastOdometer, locations }) => {
  const [type, setType] = useState<ExpenseType>(ExpenseType.FUEL);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [locationId, setLocationId] = useState<string>('');
  const [notes, setNotes] = useState('');
  const [status, setStatus] = useState<'RECEIVED' | 'PENDING'>('RECEIVED');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('PIX');

  // Odometer common
  const [odometer, setOdometer] = useState<string>(lastOdometer.toString());

  // Fuel specific
  const [fuelType, setFuelType] = useState<FuelType>('Gasolina');
  const [fuelValue, setFuelValue] = useState<string>('');
  const [liters, setLiters] = useState<string>('');

  // Maintenance specific
  const [maintItems, setMaintItems] = useState<MaintenanceItem[]>([
    { id: crypto.randomUUID(), description: '', value: 0 }
  ]);

  // Service Revenue specific
  const [odometerStart, setOdometerStart] = useState<string>(lastOdometer.toString());
  const [ratePerKm, setRatePerKm] = useState<string>('0.00');

  const totalValue = useMemo(() => {
    if (type === ExpenseType.FUEL) return parseFloat(fuelValue) || 0;
    if (type === ExpenseType.MAINTENANCE) return maintItems.reduce((acc, item) => acc + (item.value || 0), 0);
    if (type === ExpenseType.SERVICE_REVENUE) {
      const dist = (parseFloat(odometer) || 0) - (parseFloat(odometerStart) || 0);
      return Math.max(0, dist * (parseFloat(ratePerKm) || 0));
    }
    return 0;
  }, [type, fuelValue, maintItems, odometer, odometerStart, ratePerKm]);

  const addMaintItem = () => {
    setMaintItems([...maintItems, { id: crypto.randomUUID(), description: '', value: 0 }]);
  };

  const removeMaintItem = (id: string) => {
    if (maintItems.length > 1) {
      setMaintItems(maintItems.filter(item => item.id !== id));
    }
  };

  const updateMaintItem = (id: string, field: 'description' | 'value', val: string) => {
    setMaintItems(maintItems.map(item => {
      if (item.id === id) {
        return { ...item, [field]: field === 'value' ? parseFloat(val) || 0 : val };
      }
      return item;
    }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!locationId) {
      alert("Por favor, selecione um local/cliente.");
      return;
    }

    const payload: Omit<Expense, 'id'> = {
      type,
      date,
      odometer: parseFloat(odometer),
      value: totalValue,
      locationId,
      notes: notes.trim(),
      description: type === ExpenseType.FUEL ? fuelType : (type === ExpenseType.SERVICE_REVENUE ? 'Km Rodado' : 'Manutenção Multi-item'),
      paymentMethod,
    };

    if (type === ExpenseType.FUEL) {
      payload.fuelType = fuelType;
      payload.liters = parseFloat(liters);
    } else if (type === ExpenseType.MAINTENANCE) {
      payload.maintenanceItems = maintItems;
    } else if (type === ExpenseType.SERVICE_REVENUE) {
      payload.odometerStart = parseFloat(odometerStart);
      payload.ratePerKm = parseFloat(ratePerKm);
      payload.status = status;
    }

    onAdd(payload);
    onClose();
  };

  const filteredLocations = locations.filter(l => {
    if (type === ExpenseType.FUEL) return l.type === 'POSTO';
    if (type === ExpenseType.MAINTENANCE) return l.type === 'OFICINA';
    return l.type === 'CLIENTE';
  });

  return (
    <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-md z-[100] flex items-end md:items-center justify-center">
      <div className="bg-white rounded-t-[32px] md:rounded-[32px] shadow-2xl w-full max-w-lg overflow-hidden animate-in slide-in-from-bottom duration-300 flex flex-col max-h-[95vh]">
        <div className="p-6 border-b border-slate-100 flex justify-between items-center shrink-0">
          <div>
            <h3 className="text-xl font-black text-slate-900 tracking-tight">Novo Registro</h3>
            <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest">Preencha os detalhes</p>
          </div>
          <button onClick={onClose} className="p-3 hover:bg-slate-50 rounded-2xl text-slate-300 transition-colors">
            <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-6 overflow-y-auto pb-10 scrollbar-hide">
          {/* Tipo de Despesa */}
          <div className="flex bg-slate-100 p-1.5 rounded-2xl">
            {(['FUEL', 'MAINTENANCE', 'SERVICE_REVENUE'] as ExpenseType[]).map((t) => (
              <button
                key={t}
                type="button"
                onClick={() => setType(t)}
                className={`flex-1 py-3 px-1 rounded-xl text-[10px] font-black uppercase tracking-tighter transition-all ${
                  type === t ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500'
                }`}
              >
                {t === 'FUEL' ? 'Abastecer' : t === 'MAINTENANCE' ? 'Oficina' : 'Serviço'}
              </button>
            ))}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Data</label>
              <input
                type="date"
                required
                value={date}
                onChange={(e) => setDate(e.target.value)}
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 outline-none transition-all text-slate-900 font-bold"
              />
            </div>
            {type !== ExpenseType.SERVICE_REVENUE ? (
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Odômetro (km)</label>
                <input
                  type="number"
                  inputMode="numeric"
                  required
                  min={lastOdometer}
                  value={odometer}
                  onChange={(e) => setOdometer(e.target.value)}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 outline-none transition-all text-slate-900 font-bold"
                />
              </div>
            ) : (
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Valor p/ KM (R$)</label>
                <input
                  type="number"
                  inputMode="decimal"
                  step="0.01"
                  required
                  value={ratePerKm}
                  onChange={(e) => setRatePerKm(e.target.value)}
                  className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-emerald-100 focus:border-emerald-500 outline-none transition-all text-slate-900 font-black"
                />
              </div>
            )}
          </div>

          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest">
              Local / Cliente
            </label>
            <select
              required
              value={locationId}
              onChange={(e) => setLocationId(e.target.value)}
              className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 outline-none transition-all text-slate-900 font-bold appearance-none bg-[url('data:image/svg+xml;charset=utf-8,%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20fill%3D%22none%22%20viewBox%3D%220%200%2020%2020%22%3E%3Cpath%20stroke%3D%22%236b7280%22%20stroke-linecap%3D%22round%22%20stroke-linejoin%3D%22round%22%20stroke-width%3D%221.5%22%20d%3D%22m6%208%204%204%204-4%22%2F%3E%3C%2Fsvg%3E')] bg-[length:1.25rem_1.25rem] bg-[right_1rem_center] bg-no-repeat"
            >
              <option value="">Selecione...</option>
              {filteredLocations.map(loc => (
                <option key={loc.id} value={loc.id}>{loc.name}</option>
              ))}
            </select>
          </div>

          <div className="space-y-1.5">
            <label className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Forma Pagto.</label>
            <div className="grid grid-cols-2 gap-2">
              {(['PIX', 'CREDITO', 'DEBITO', 'DINHEIRO'] as PaymentMethod[]).map(pm => (
                <button
                  key={pm}
