import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area 
} from 'recharts';
import { Expense, CarStats, ExpenseType } from '../types';
import { Fuel, Wrench, TrendingUp, Gauge, DollarSign, Calendar, SlidersHorizontal, HandCoins, Clock, CheckCircle2 } from 'lucide-react';

interface DashboardProps {
  expenses: Expense[];
}

type FilterPeriod = 'all' | '30' | '90' | '180' | 'year' | 'custom';

export const Dashboard: React.FC<DashboardProps> = ({ expenses }) => {
  const [period, setPeriod] = useState<FilterPeriod>('all');
  const [customStart, setCustomStart] = useState<string>(new Date(new Date().setDate(new Date().getDate() - 7)).toISOString().split('T')[0]);
  const [customEnd, setCustomEnd] = useState<string>(new Date().toISOString().split('T')[0]);

  const filteredExpenses = useMemo(() => {
    if (period === 'all') return expenses;
    const now = new Date();
    let filterDateStart: Date;
    let filterDateEnd: Date = new Date();

    if (period === 'custom') {
      filterDateStart = new Date(customStart);
      filterDateEnd = new Date(customEnd);
      filterDateEnd.setHours(23, 59, 59, 999);
    } else {
      filterDateStart = new Date();
      if (period === '30') filterDateStart.setDate(now.getDate() - 30);
      else if (period === '90') filterDateStart.setDate(now.getDate() - 90);
      else if (period === '180') filterDateStart.setDate(now.getDate() - 180);
      else if (period === 'year') filterDateStart.setFullYear(now.getFullYear(), 0, 1);
    }
    return expenses.filter(e => {
      const d = new Date(e.date);
      return d >= filterDateStart && d <= filterDateEnd;
    });
  }, [expenses, period, customStart, customEnd]);

  const stats = useMemo<CarStats>(() => {
    const totalSpent = filteredExpenses
      .filter(e => e.type !== ExpenseType.SERVICE_REVENUE)
      .reduce((acc, curr) => acc + curr.value, 0);

    const totalServiceRevenue = filteredExpenses
      .filter(e => e.type === ExpenseType.SERVICE_REVENUE && e.status === 'RECEIVED')
      .reduce((acc, curr) => acc + curr.value, 0);

    const pendingServiceRevenue = filteredExpenses
      .filter(e => e.type === ExpenseType.SERVICE_REVENUE && e.status === 'PENDING')
      .reduce((acc, curr) => acc + curr.value, 0);

    const fuelExpenses = filteredExpenses
      .filter(e => e.type === ExpenseType.FUEL)
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

    let totalDistance = 0;
    let totalLiters = 0;
    if (fuelExpenses.length > 1) {
      totalDistance = fuelExpenses[fuelExpenses.length - 1].odometer - fuelExpenses[0].odometer;
      totalLiters = fuelExpenses.slice(1).reduce((acc, curr) => acc + (curr.liters || 0), 0);
    }
    const averageConsumption = totalLiters > 0 ? totalDistance / totalLiters : 0;
    const lastOdometer = expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;

    return { totalSpent, totalLiters: fuelExpenses.reduce((acc, curr) => acc + (curr.liters || 0), 0), averageConsumption, totalDistance, lastOdometer, totalServiceRevenue, pendingServiceRevenue };
  }, [filteredExpenses, expenses]);

  const chartData = useMemo(() => {
    return [...filteredExpenses]
      .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
      .slice(-15)
      .map(e => ({
        name: new Date(e.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
        valor: e.type === ExpenseType.SERVICE_REVENUE ? 0 : e.value, 
        ganho: e.type === ExpenseType.SERVICE_REVENUE ? e.value : 0
      }));
  }, [filteredExpenses]);

  const FilterButton = ({ value, label }: { value: FilterPeriod, label: string }) => (
    <button
      onClick={() => setPeriod(value)}
      className={`px-5 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap border ${
        period === value ? 'bg-slate-900 border-slate-900 text-white shadow-lg' : 'bg-white text-slate-500 border-slate-200'
      }`}
    >
      {label}
    </button>
  );

  return (
    <div className="space-y-6">
      <div className="overflow-x-auto scrollbar-hide -mx-4 px-4 md:mx-0 md:px-0">
        <div className="flex items-center gap-2 pb-2">
          <FilterButton value="30" label="30 dias" />
          <FilterButton value="90" label="90 dias" />
          <FilterButton value="year" label="Este Ano" />
          <FilterButton value="custom" label="Custom" />
          <FilterButton value="all" label="Tudo" />
        </div>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white p-5 rounded-[28px] border border-slate-100 flex items-center gap-4 shadow-sm">
          <div className="p-3 bg-red-50 text-red-500 rounded-2xl"><DollarSign size={20} /></div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Gastos</p>
            <h3 className="text-xl font-black text-slate-900">R$ {stats.totalSpent.toLocaleString('pt-BR')}</h3>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[28px] border border-slate-100 flex items-center gap-4 shadow-sm">
          <div className="p-3 bg-emerald-50 text-emerald-500 rounded-2xl"><HandCoins size={20} /></div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Recebido</p>
            <h3 className="text-xl font-black text-emerald-600">R$ {stats.totalServiceRevenue.toLocaleString('pt-BR')}</h3>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[28px] border border-slate-100 flex items-center gap-4 shadow-sm">
          <div className="p-3 bg-blue-50 text-blue-500 rounded-2xl"><Gauge size={20} /></div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Consumo</p>
            <h3 className="text-xl font-black text-slate-900">{stats.averageConsumption.toFixed(2)} <span className="text-xs">km/L</span></h3>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[28px] border border-slate-100 flex items-center gap-4 shadow-sm">
          <div className="p-3 bg-indigo-50 text-indigo-500 rounded-2xl"><TrendingUp size={20} /></div>
          <div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Km Rodados</p>
            <h3 className="text-xl font-black text-slate-900">{stats.totalDistance.toLocaleString()} <span className="text-xs">km</span></h3>
          </div>
        </div>
      </div>

      <div className="bg-white p-5 md:p-6 rounded-[32px] border border-slate-100 shadow-sm">
        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Fluxo Recente</h4>
        <div className="h-64">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 800}} />
              <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: 800 }} />
              <Bar dataKey="valor" name="Gasto" fill="#f43f5e" radius={[4, 4, 0, 0]} barSize={12} />
              <Bar dataKey="ganho" name="Ganho" fill="#10b981" radius={[4, 4, 0, 0]} barSize={12} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { Expense, ExpenseType, Location, PaymentMethod } from '../types';
import { FileText, Printer, Calendar, Filter, Fuel, Wrench, Navigation, DollarSign, HandCoins, CheckCircle2, Clock, Zap, CreditCard, Wallet } from 'lucide-react';

interface ReportsProps {
  expenses: Expense[];
  locations: Location[];
}

type ReportType = 'ALL' | 'FUEL' | 'MAINTENANCE' | 'SERVICE';
type StatusFilter = 'ALL' | 'RECEIVED' | 'PENDING';
type PaymentFilter = 'ALL' | PaymentMethod;

export const Reports: React.FC<ReportsProps> = ({ expenses, locations }) => {
  const [startDate, setStartDate] = useState<string>(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [reportType, setReportType] = useState<ReportType>('ALL');
  const [statusFilter, setStatusFilter] = useState<StatusFilter>('ALL');
  const [paymentFilter, setPaymentFilter] = useState<PaymentFilter>('ALL');

  const filteredData = useMemo(() => {
    return expenses.filter(e => {
      const date = new Date(e.date);
      const start = new Date(startDate);
      const end = new Date(endDate);
      end.setHours(23, 59, 59, 999);
      const matchesDate = date >= start && date <= end;
      const matchesType = reportType === 'ALL' || (reportType === 'FUEL' && e.type === ExpenseType.FUEL) || (reportType === 'MAINTENANCE' && e.type === ExpenseType.MAINTENANCE) || (reportType === 'SERVICE' && e.type === ExpenseType.SERVICE_REVENUE);
      const matchesStatus = statusFilter === 'ALL' || (e.type === ExpenseType.SERVICE_REVENUE && e.status === statusFilter) || (e.type !== ExpenseType.SERVICE_REVENUE && statusFilter === 'RECEIVED');
      const matchesPayment = paymentFilter === 'ALL' || e.paymentMethod === paymentFilter;
      return matchesDate && matchesType && matchesStatus && matchesPayment;
    }).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [expenses, startDate, endDate, reportType, statusFilter, paymentFilter]);

  const totals = useMemo(() => {
    return filteredData.reduce((acc, curr) => {
      if (curr.type === ExpenseType.SERVICE_REVENUE) {
        if (curr.status === 'RECEIVED') acc.earned += curr.value;
        else acc.pending += curr.value;
      } else {
        acc.spent += curr.value;
      }
      return acc;
    }, { spent: 0, earned: 0, pending: 0 });
  }, [filteredData]);

  const getLocationName = (id?: string) => locations.find(l => l.id === id)?.name || 'N/A';
  const getPaymentMethodIcon = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return <Zap size={12} />;
      case 'CREDITO': case 'DEBITO': return <CreditCard size={12} />;
      case 'DINHEIRO': return <Wallet size={12} />;
      default: return null;
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-5 rounded-[28px] border border-slate-100 shadow-sm no-print">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-2">
            <Filter size={18} className="text-blue-600" />
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-400">Filtrar Relatório</span>
          </div>
          <button onClick={() => window.print()} className="bg-slate-900 text-white p-3 rounded-2xl shadow-lg active:scale-95"><Printer size={18} /></button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
          <div className="space-y-1">
            <label className="text-[9px] font-black text-slate-900 uppercase ml-1">Início</label>
            <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold" />
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-slate-900 uppercase ml-1">Fim</label>
            <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold" />
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-slate-900 uppercase ml-1">Tipo</label>
            <select value={reportType} onChange={e => setReportType(e.target.value as any)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold appearance-none">
              <option value="ALL">Todos</option>
              <option value="FUEL">Combustível</option>
              <option value="MAINTENANCE">Manutenção</option>
              <option value="SERVICE">Serviços</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-slate-900 uppercase ml-1">Status</label>
            <select value={statusFilter} onChange={e => setStatusFilter(e.target.value as any)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold appearance-none">
              <option value="ALL">Todos</option>
              <option value="RECEIVED">Recebidos</option>
              <option value="PENDING">Pendentes</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-slate-900 uppercase ml-1">Pagto.</label>
            <select value={paymentFilter} onChange={e => setPaymentFilter(e.target.value as any)} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl text-xs font-bold appearance-none">
              <option value="ALL">Todas</option>
              <option value="PIX">PIX</option>
              <option value="CREDITO">Crédito</option>
              <option value="DEBITO">Débito</option>
              <option value="DINHEIRO">Dinheiro</option>
            </select>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[32px] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-6 md:p-8 bg-slate-50/50 grid grid-cols-2 md:grid-cols-3 gap-4 border-b border-slate-100">
          <div className="col-span-2 md:col-span-1 mb-2 md:mb-0">
            <h3 className="text-xl font-black tracking-tight text-slate-900">Relatório</h3>
            <p className="text-[10px] font-bold text-slate-400 uppercase">{filteredData.length} registros encontrados</p>
          </div>
          <div className="bg-white p-3 rounded-2xl border border-slate-200">
            <p className="text-[8px] font-black text-slate-400 uppercase mb-1">Total Gasto</p>
            <p className="text-lg font-black text-red-500">R$ {totals.spent.toLocaleString('pt-BR')}</p>
          </div>
          <div className="bg-white p-3 rounded-2xl border border-slate-200">
            <p className="text-[8px] font-black text-slate-400 uppercase mb-1">Total Ganho</p>
            <p className="text-lg font-black text-emerald-500">R$ {totals.earned.toLocaleString('pt-BR')}</p>
          </div>
        </div>

        <div className="overflow-x-auto scrollbar-hide">
          <table className="w-full text-left min-w-[600px]">
            <thead>
              <tr className="bg-white">
                <th className="px-6 py-4 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Data</th>
                <th className="px-6 py-4 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Categoria</th>
                <th className="px-6 py-4 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Local</th>
                <th className="px-6 py-4 text-[9px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 text-right">Valor</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {filteredData.map(e => (
                <tr key={e.id} className="hover:bg-slate-50/30">
                  <td className="px-6 py-4 text-[11px] font-bold text-slate-500">{new Date(e.date).toLocaleDateString()}</td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-xs font-black text-slate-900">{e.type === 'FUEL' ? 'Combustível' : e.type === 'MAINTENANCE' ? 'Oficina' : 'Serviço'}</span>
                      <span className="text-[8px] font-bold text-slate-400 uppercase">{e.paymentMethod}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-xs font-bold text-slate-600 truncate max-w-[150px]">{getLocationName(e.locationId)}</td>
                  <td className={`px-6 py-4 text-right text-xs font-black ${e.type === 'SERVICE_REVENUE' ? 'text-emerald-500' : 'text-slate-900'}`}>
                    R$ {e.value.toLocaleString('pt-BR')}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location, PaymentMethod } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { LocationManager } from './components/LocationManager';
import { Reports } from './components/Reports';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Fuel, Wrench, Gauge, MapPin, Navigation, MessageSquare, FileText, Printer, ChevronRight, CheckCircle2, Clock, Zap, CreditCard, Wallet } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'locations' | 'reports'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleAddExpense = (newExpense: Omit<Expense, 'id'>) => {
    const expense: Expense = {
      ...newExpense,
      id: crypto.randomUUID(),
    };
    setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

