import React, { useState, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area 
} from 'recharts';
import { Expense, CarStats, ExpenseType } from '../types';
import { Fuel, Wrench, TrendingUp, Gauge, DollarSign, Calendar, SlidersHorizontal, HandCoins, Clock, CheckCircle2 } from 'lucide-react';

interface DashboardProps {
  expenses: Expense[];
}

type FilterPeriod = 'all' | '30' | '90' | '180' | 'year' | 'custom';

export const Dashboard: React.FC<DashboardProps> = ({ expenses }) => {
  const [period, setPeriod] = useState<FilterPeriod>('all');

  const filteredExpenses = useMemo(() => {
    if (period === 'all') return expenses;
    const now = new Date();
    let filterDateStart = new Date();
    if (period === '30') filterDateStart.setDate(now.getDate() - 30);
    else if (period === '90') filterDateStart.setDate(now.getDate() - 90);
    else if (period === 'year') filterDateStart.setFullYear(now.getFullYear(), 0, 1);

    return expenses.filter(e => new Date(e.date) >= filterDateStart);
  }, [expenses, period]);

  const stats = useMemo<CarStats>(() => {
    const totalSpent = filteredExpenses.filter(e => e.type !== ExpenseType.SERVICE_REVENUE).reduce((acc, curr) => acc + curr.value, 0);
    const totalServiceRevenue = filteredExpenses.filter(e => e.type === ExpenseType.SERVICE_REVENUE && e.status === 'RECEIVED').reduce((acc, curr) => acc + curr.value, 0);
    const fuelExpenses = filteredExpenses.filter(e => e.type === ExpenseType.FUEL).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
    let totalDistance = 0, totalLiters = 0;
    if (fuelExpenses.length > 1) {
      totalDistance = fuelExpenses[fuelExpenses.length - 1].odometer - fuelExpenses[0].odometer;
      totalLiters = fuelExpenses.slice(1).reduce((acc, curr) => acc + (curr.liters || 0), 0);
    }
    const averageConsumption = totalLiters > 0 ? totalDistance / totalLiters : 0;
    return { totalSpent, totalLiters, averageConsumption, totalDistance, lastOdometer: 0, totalServiceRevenue, pendingServiceRevenue: 0 };
  }, [filteredExpenses]);

  const chartData = useMemo(() => {
    return [...filteredExpenses].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime()).slice(-10).map(e => ({
      name: new Date(e.date).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit' }),
      valor: e.type === ExpenseType.SERVICE_REVENUE ? 0 : e.value, 
      ganho: e.type === ExpenseType.SERVICE_REVENUE ? e.value : 0
    }));
  }, [filteredExpenses]);

  return (
    <div className="space-y-6 w-full max-w-full overflow-x-hidden">
      {/* Filtros Mobile com scroll horizontal suave */}
      <div className="flex items-center gap-2 overflow-x-auto pb-4 scrollbar-hide -mx-4 px-4 w-[100vw] md:w-full md:mx-0 md:px-0">
        {(['30', '90', 'year', 'all'] as FilterPeriod[]).map(p => (
          <button
            key={p}
            onClick={() => setPeriod(p)}
            className={`px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all whitespace-nowrap border shrink-0 ${
              period === p ? 'bg-slate-900 border-slate-900 text-white shadow-md' : 'bg-white text-slate-500 border-slate-200'
            }`}
          >
            {p === '30' ? '30 Dias' : p === '90' ? '90 Dias' : p === 'year' ? 'Este Ano' : 'Tudo'}
          </button>
        ))}
      </div>

      {/* Grid de Stats - Ajustado para não quebrar lateralmente */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 md:gap-4 w-full">
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 flex items-center gap-4 shadow-sm w-full">
          <div className="p-3 bg-red-50 text-red-500 rounded-xl shrink-0"><DollarSign size={20} /></div>
          <div className="min-w-0">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest truncate">Gastos</p>
            <h3 className="text-xl font-black text-slate-900 truncate">R$ {stats.totalSpent.toLocaleString('pt-BR')}</h3>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 flex items-center gap-4 shadow-sm w-full">
          <div className="p-3 bg-emerald-50 text-emerald-500 rounded-xl shrink-0"><HandCoins size={20} /></div>
          <div className="min-w-0">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest truncate">Ganhos</p>
            <h3 className="text-xl font-black text-emerald-600 truncate">R$ {stats.totalServiceRevenue.toLocaleString('pt-BR')}</h3>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 flex items-center gap-4 shadow-sm w-full">
          <div className="p-3 bg-blue-50 text-blue-500 rounded-xl shrink-0"><Gauge size={20} /></div>
          <div className="min-w-0">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest truncate">Média</p>
            <h3 className="text-xl font-black text-slate-900 truncate">{stats.averageConsumption.toFixed(1)} <span className="text-xs">km/L</span></h3>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[24px] border border-slate-100 flex items-center gap-4 shadow-sm w-full">
          <div className="p-3 bg-indigo-50 text-indigo-500 rounded-xl shrink-0"><TrendingUp size={20} /></div>
          <div className="min-w-0">
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest truncate">Km Rodados</p>
            <h3 className="text-xl font-black text-slate-900 truncate">{stats.totalDistance.toLocaleString()} <span className="text-xs">km</span></h3>
          </div>
        </div>
      </div>

      <div className="bg-white p-5 rounded-[32px] border border-slate-100 shadow-sm w-full">
        <h4 className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-6">Gráfico de Fluxo</h4>
        <div className="h-48 md:h-64 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} margin={{left: -20, right: 0}}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
              <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 9, fontWeight: 900}} />
              <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 9, fontWeight: 900}} />
              <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgb(0,0,0,0.1)', fontWeight: 800, fontSize: 10 }} />
              <Bar dataKey="valor" name="Gasto" fill="#f43f5e" radius={[3, 3, 0, 0]} barSize={10} />
              <Bar dataKey="ganho" name="Ganho" fill="#10b981" radius={[3, 3, 0, 0]} barSize={10} />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { ExpenseType, Expense, Location, FuelType, MaintenanceItem, PaymentMethod } from '../types';
import { Plus, X, Trash2, MapPin, Navigation, DollarSign, MessageSquare, CheckCircle2, Clock, CreditCard, Wallet, Zap } from 'lucide-react';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'>) => void;
  onClose: () => void;
  lastOdometer: number;
  locations: Location[];
}

export const ExpenseForm: React.FC<ExpenseFormProps> = ({ onAdd, onClose, lastOdometer, locations }) => {
  const [type, setType] = useState<ExpenseType>(ExpenseType.FUEL);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [locationId, setLocationId] = useState<string>('');
  const [notes, setNotes] = useState('');
  const [status, setStatus] = useState<'RECEIVED' | 'PENDING'>('RECEIVED');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('PIX');
  const [odometer, setOdometer] = useState<string>(lastOdometer.toString());
  const [fuelType, setFuelType] = useState<FuelType>('Gasolina');
  const [fuelValue, setFuelValue] = useState<string>('');
  const [liters, setLiters] = useState<string>('');
  const [maintItems, setMaintItems] = useState<MaintenanceItem[]>([{ id: crypto.randomUUID(), description: '', value: 0 }]);
  const [odometerStart, setOdometerStart] = useState<string>(lastOdometer.toString());
  const [ratePerKm, setRatePerKm] = useState<string>('0.00');

  const totalValue = useMemo(() => {
    if (type === ExpenseType.FUEL) return parseFloat(fuelValue) || 0;
    if (type === ExpenseType.MAINTENANCE) return maintItems.reduce((acc, item) => acc + (item.value || 0), 0);
    if (type === ExpenseType.SERVICE_REVENUE) {
      const dist = (parseFloat(odometer) || 0) - (parseFloat(odometerStart) || 0);
      return Math.max(0, dist * (parseFloat(ratePerKm) || 0));
    }
    return 0;
  }, [type, fuelValue, maintItems, odometer, odometerStart, ratePerKm]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!locationId) return alert("Selecione um local");
    const payload: Omit<Expense, 'id'> = {
      type, date, odometer: parseFloat(odometer), value: totalValue, locationId, notes: notes.trim(), paymentMethod,
      description: type === ExpenseType.FUEL ? fuelType : (type === ExpenseType.SERVICE_REVENUE ? 'Km Rodado' : 'Manutenção'),
    };
    if (type === ExpenseType.FUEL) { payload.fuelType = fuelType; payload.liters = parseFloat(liters); }
    else if (type === ExpenseType.MAINTENANCE) payload.maintenanceItems = maintItems;
    else if (type === ExpenseType.SERVICE_REVENUE) { payload.odometerStart = parseFloat(odometerStart); payload.ratePerKm = parseFloat(ratePerKm); payload.status = status; }
    onAdd(payload);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-end md:items-center justify-center p-0 md:p-4 overflow-hidden">
      <div className="bg-white rounded-t-[28px] md:rounded-[28px] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[92vh]">
        <div className="p-5 border-b border-slate-100 flex justify-between items-center bg-white shrink-0">
          <h3 className="text-lg font-black text-slate-900 uppercase">Novo Registro</h3>
          <button onClick={onClose} className="p-2 text-slate-300"><X size={24} /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 overflow-y-auto pb-10 scrollbar-hide">
          <div className="flex bg-slate-100 p-1 rounded-2xl">
            {(['FUEL', 'MAINTENANCE', 'SERVICE_REVENUE'] as ExpenseType[]).map((t) => (
              <button key={t} type="button" onClick={() => setType(t)} className={`flex-1 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-tighter transition-all ${type === t ? 'bg-white text-slate-900 shadow-sm' : 'text-slate-500'}`}>
                {t === 'FUEL' ? 'Abastecer' : t === 'MAINTENANCE' ? 'Oficina' : 'Serviço'}
              </button>
            ))}
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400 ml-1">Data</label>
              <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold" />
            </div>
            <div className="space-y-1">
              <label className="text-[9px] font-black uppercase text-slate-400 ml-1">KM Final</label>
              <input type="number" inputMode="numeric" value={odometer} onChange={e => setOdometer(e.target.value)} className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold" />
            </div>
          </div>

          <div className="space-y-1">
            <label className="text-[9px] font-black uppercase text-slate-400 ml-1">Local / Empresa</label>
            <select value={locationId} onChange={e => setLocationId(e.target.value)} className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold appearance-none">
              <option value="">Selecione...</option>
