              <div className="grid grid-cols-2 gap-3">
                <div className="space-y-1">
                  <label className="text-[9px] font-black uppercase text-emerald-600">KM Inicial</label>
                  <input type="number" inputMode="numeric" value={odometerStart} onChange={e => setOdometerStart(e.target.value)} className="w-full p-3.5 bg-white border border-emerald-200 rounded-xl text-xs font-bold" />
