                <div className="space-y-1">
                  <label className="text-[9px] font-black uppercase text-emerald-600">Valor/KM</label>
                  <input type="number" inputMode="decimal" step="0.01" value={ratePerKm} onChange={e => setRatePerKm(e.target.value)} className="w-full p-3.5 bg-white border border-emerald-200 rounded-xl text-xs font-black" />
