              <div className="flex gap-2">
                <button type="button" onClick={() => setStatus('RECEIVED')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase border transition-all ${status === 'RECEIVED' ? 'bg-emerald-600 text-white' : 'bg-white text-slate-400'}`}>Recebido</button>
                <button type="button" onClick={() => setStatus('PENDING')} className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase border transition-all ${status === 'PENDING' ? 'bg-amber-500 text-white' : 'bg-white text-slate-400'}`}>Em Aberto</button>
              </div>
            </div>
          )}

          <div className="space-y-1">
            <label className="text-[9px] font-black uppercase text-slate-400 ml-1">Notas</label>
            <textarea value={notes} onChange={e => setNotes(e.target.value)} rows={1} className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl text-xs font-medium resize-none" />
