          )}
        </main>
      </div>

      {isFormOpen && (
        <ExpenseForm lastOdometer={lastOdometer} locations={locations} onAdd={handleAddExpense} onClose={() => setIsFormOpen(false)} />
      )}
    </div>
  );
};

