import React, { useState, useMemo } from 'react';
import { Expense, ExpenseType, Location, PaymentMethod } from '../types';
import { FileText, Printer, Calendar, Filter, Fuel, Wrench, Navigation, DollarSign, HandCoins, CheckCircle2, Clock, Zap, CreditCard, Wallet } from 'lucide-react';

interface ReportsProps {
  expenses: Expense[];
  locations: Location[];
}

type ReportType = 'ALL' | 'FUEL' | 'MAINTENANCE' | 'SERVICE';
type StatusFilter = 'ALL' | 'RECEIVED' | 'PENDING';
type PaymentFilter = 'ALL' | PaymentMethod;

export const Reports: React.FC<ReportsProps> = ({ expenses, locations }) => {
  const [startDate, setStartDate] = useState<string>(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [reportType, setReportType] = useState<ReportType>('ALL');
  const [statusFilter, setStatusFilter] = useState<StatusFilter>('ALL');
  const [paymentFilter, setPaymentFilter] = useState<PaymentFilter>('ALL');

  const filteredData = useMemo(() => {
    return expenses.filter(e => {
      const date = new Date(e.date);
      const start = new Date(startDate);
      const end = new Date(endDate);
      end.setHours(23, 59, 59, 999);
      const matchesDate = date >= start && date <= end;
      const matchesType = reportType === 'ALL' || (reportType === 'FUEL' && e.type === ExpenseType.FUEL) || (reportType === 'MAINTENANCE' && e.type === ExpenseType.MAINTENANCE) || (reportType === 'SERVICE' && e.type === ExpenseType.SERVICE_REVENUE);
      const matchesStatus = statusFilter === 'ALL' || (e.type === ExpenseType.SERVICE_REVENUE && e.status === statusFilter) || (e.type !== ExpenseType.SERVICE_REVENUE && statusFilter === 'RECEIVED');
      const matchesPayment = paymentFilter === 'ALL' || e.paymentMethod === paymentFilter;
      return matchesDate && matchesType && matchesStatus && matchesPayment;
    }).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [expenses, startDate, endDate, reportType, statusFilter, paymentFilter]);

  const totals = useMemo(() => {
    return filteredData.reduce((acc, curr) => {
      if (curr.type === ExpenseType.SERVICE_REVENUE) {
        if (curr.status === 'RECEIVED') acc.earned += curr.value;
        else acc.pending += curr.value;
      } else {
        acc.spent += curr.value;
      }
      return acc;
    }, { spent: 0, earned: 0, pending: 0 });
  }, [filteredData]);

  const getLocationName = (id?: string) => locations.find(l => l.id === id)?.name || 'N/A';
  const getPaymentMethodIcon = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return <Zap size={12} />;
      case 'CREDITO': case 'DEBITO': return <CreditCard size={12} />;
      case 'DINHEIRO': return <Wallet size={12} />;
      default: return null;
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-5 rounded-[28px] border border-slate-200 shadow-sm no-print">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-2">
            <Filter size={18} className="text-blue-600" />
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-700">Filtrar Relatório</span>
          </div>
          <button onClick={() => window.print()} className="bg-black text-white p-3 rounded-2xl shadow-lg active:scale-95"><Printer size={18} /></button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
          <div className="space-y-1">
            <label className="text-[9px] font-black text-black uppercase ml-1">Início</label>
            <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-xs font-bold text-black" />
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-black uppercase ml-1">Fim</label>
            <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-xs font-bold text-black" />
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-black uppercase ml-1">Tipo</label>
            <select value={reportType} onChange={e => setReportType(e.target.value as any)} className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-xs font-bold text-black appearance-none">
              <option value="ALL">Todos</option>
              <option value="FUEL">Combustível</option>
              <option value="MAINTENANCE">Manutenção</option>
              <option value="SERVICE">Serviços</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-black uppercase ml-1">Status</label>
            <select value={statusFilter} onChange={e => setStatusFilter(e.target.value as any)} className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-xs font-bold text-black appearance-none">
              <option value="ALL">Todos</option>
              <option value="RECEIVED">Recebidos</option>
              <option value="PENDING">Pendentes</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-black uppercase ml-1">Pagto.</label>
            <select value={paymentFilter} onChange={e => setPaymentFilter(e.target.value as any)} className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-xs font-bold text-black appearance-none">
              <option value="ALL">Todas</option>
              <option value="PIX">PIX</option>
              <option value="CREDITO">Crédito</option>
              <option value="DEBITO">Débito</option>
              <option value="DINHEIRO">Dinheiro</option>
            </select>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[32px] border border-slate-200 shadow-md overflow-hidden">
        <div className="p-6 md:p-8 bg-slate-50/50 grid grid-cols-2 md:grid-cols-3 gap-4 border-b border-slate-200">
          <div className="col-span-2 md:col-span-1 mb-2 md:mb-0">
            <h3 className="text-xl font-black tracking-tight text-black">Relatório</h3>
            <p className="text-[10px] font-bold text-slate-700 uppercase">{filteredData.length} registros encontrados</p>
          </div>
          <div className="bg-white p-3 rounded-2xl border border-slate-200 shadow-sm">
            <p className="text-[8px] font-black text-slate-500 uppercase mb-1">Total Gasto</p>
            <p className="text-lg font-black text-red-600">R$ {totals.spent.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
          </div>
          <div className="bg-white p-3 rounded-2xl border border-slate-200 shadow-sm">
            <p className="text-[8px] font-black text-slate-500 uppercase mb-1">Total Ganho</p>
            <p className="text-lg font-black text-emerald-600">R$ {totals.earned.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
          </div>
        </div>

        <div className="overflow-x-auto scrollbar-hide">
          <table className="w-full text-left min-w-[600px]">
            <thead>
              <tr className="bg-white border-b border-slate-200">
                <th className="px-6 py-4 text-[9px] font-black text-black uppercase tracking-widest">Data</th>
                <th className="px-6 py-4 text-[9px] font-black text-black uppercase tracking-widest">Categoria</th>
                <th className="px-6 py-4 text-[9px] font-black text-black uppercase tracking-widest">Local</th>
                <th className="px-6 py-4 text-[9px] font-black text-black uppercase tracking-widest text-right">Valor</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {filteredData.map(e => (
                <tr key={e.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 text-[11px] font-black text-slate-700">{new Date(e.date).toLocaleDateString()}</td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-xs font-black text-black">{e.type === 'FUEL' ? 'Combustível' : e.type === 'MAINTENANCE' ? 'Oficina' : 'Serviço'}</span>
                      <span className="text-[8px] font-black text-slate-600 uppercase flex items-center gap-1">{getPaymentMethodIcon(e.paymentMethod)} {e.paymentMethod}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-xs font-black text-slate-800 truncate max-w-[150px]">{getLocationName(e.locationId)}</td>
                  <td className={`px-6 py-4 text-right text-xs font-black ${e.type === 'SERVICE_REVENUE' ? 'text-emerald-700' : 'text-black'}`}>
                    {e.type === 'SERVICE_REVENUE' ? '+' : ''} R$ {e.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { ExpenseType, Expense, Location, FuelType, MaintenanceItem, PaymentMethod } from '../types';
import { Plus, X, Trash2, MapPin, Navigation, DollarSign, MessageSquare, CheckCircle2, Clock, CreditCard, Wallet, Zap } from 'lucide-react';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'>) => void;
  onClose: () => void;
  lastOdometer: number;
  locations: Location[];
}

export const ExpenseForm: React.FC<ExpenseFormProps> = ({ onAdd, onClose, lastOdometer, locations }) => {
  const [type, setType] = useState<ExpenseType>(ExpenseType.FUEL);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [locationId, setLocationId] = useState<string>('');
  const [notes, setNotes] = useState('');
  const [status, setStatus] = useState<'RECEIVED' | 'PENDING'>('RECEIVED');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('PIX');
  const [odometer, setOdometer] = useState<string>(lastOdometer.toString());
  const [fuelType, setFuelType] = useState<FuelType>('Gasolina');
  const [fuelValue, setFuelValue] = useState<string>('');
  const [liters, setLiters] = useState<string>('');
  const [maintItems, setMaintItems] = useState<MaintenanceItem[]>([{ id: crypto.randomUUID(), description: '', value: 0 }]);
  const [odometerStart, setOdometerStart] = useState<string>(lastOdometer.toString());
  const [ratePerKm, setRatePerKm] = useState<string>('0.00');

  const totalValue = useMemo(() => {
    if (type === ExpenseType.FUEL) return parseFloat(fuelValue) || 0;
    if (type === ExpenseType.MAINTENANCE) return maintItems.reduce((acc, item) => acc + (item.value || 0), 0);
    if (type === ExpenseType.SERVICE_REVENUE) {
      const dist = (parseFloat(odometer) || 0) - (parseFloat(odometerStart) || 0);
      return Math.max(0, dist * (parseFloat(ratePerKm) || 0));
    }
    return 0;
  }, [type, fuelValue, maintItems, odometer, odometerStart, ratePerKm]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!locationId) return alert("Selecione um local");
    const payload: Omit<Expense, 'id'> = {
      type, date, odometer: parseFloat(odometer), value: totalValue, locationId, notes: notes.trim(), paymentMethod,
      description: type === ExpenseType.FUEL ? fuelType : (type === ExpenseType.SERVICE_REVENUE ? 'Km Rodado' : 'Manutenção'),
    };
    if (type === ExpenseType.FUEL) { payload.fuelType = fuelType; payload.liters = parseFloat(liters); }
    else if (type === ExpenseType.MAINTENANCE) payload.maintenanceItems = maintItems;
    else if (type === ExpenseType.SERVICE_REVENUE) { payload.odometerStart = parseFloat(odometerStart); payload.ratePerKm = parseFloat(ratePerKm); payload.status = status; }
    onAdd(payload);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-end md:items-center justify-center p-0 md:p-4 overflow-hidden">
      <div className="bg-white rounded-t-[28px] md:rounded-[28px] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[92vh]">
        <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-white shrink-0">
          <h3 className="text-xl font-black text-black uppercase tracking-tight">Novo Registro</h3>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-black transition-colors">
            <X size={28} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 overflow-y-auto pb-10 scrollbar-hide">
          {/* Seletor de Tipo */}
          <div className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200">
            {(['FUEL', 'MAINTENANCE', 'SERVICE_REVENUE'] as ExpenseType[]).map((t) => (
              <button 
                key={t} 
                type="button" 
                onClick={() => setType(t)} 
                className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase tracking-tight transition-all ${
                  type === t ? 'bg-white text-black shadow-md border border-slate-200' : 'text-slate-500 hover:text-black'
                }`}
              >
                {t === 'FUEL' ? 'Abastecer' : t === 'MAINTENANCE' ? 'Oficina' : 'Serviço'}
              </button>
            ))}
          </div>

          {/* Data e KM */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Data do Lançamento</label>
              <input 
                type="date" 
                value={date} 
                onChange={e => setDate(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all" 
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Odômetro (KM)</label>
              <input 
                type="number" 
                inputMode="numeric" 
                value={odometer} 
                onChange={e => setOdometer(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all" 
              />
            </div>
          </div>

          {/* Local */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Local / Empresa Parceira</label>
            <div className="relative">
              <select 
                value={locationId} 
                onChange={e => setLocationId(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all appearance-none"
              >
                <option value="">Clique para selecionar...</option>
                {locations.filter(l => (type === 'FUEL' && l.type === 'POSTO') || (type === 'MAINTENANCE' && l.type === 'OFICINA') || (type === 'SERVICE_REVENUE' && l.type === 'CLIENTE')).map(loc => (
                  <option key={loc.id} value={loc.id} className="font-bold text-black">{loc.name}</option>
                ))}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-black">
                <Plus size={20} />
              </div>
            </div>
          </div>

          {/* Forma de Pagamento */}
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Forma de Pagamento</label>
            <div className="grid grid-cols-4 gap-2">
              {(['PIX', 'CREDITO', 'DEBITO', 'DINHEIRO'] as PaymentMethod[]).map(pm => (
                <button 
                  key={pm} 
                  type="button" 
                  onClick={() => setPaymentMethod(pm)} 
                  className={`py-4 rounded-2xl flex flex-col items-center justify-center gap-1 border-2 transition-all ${
                    paymentMethod === pm ? 'bg-black border-black text-white shadow-lg scale-105' : 'bg-white border-slate-300 text-black hover:border-slate-400'
                  }`}
                >
                  {pm === 'PIX' ? <Zap size={18} /> : pm === 'DINHEIRO' ? <Wallet size={18} /> : <CreditCard size={18} />}
                  <span className="text-[9px] font-black uppercase tracking-tight">{pm}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Seção Específica de Abastecimento */}
          {type === 'FUEL' && (
            <div className="grid grid-cols-2 gap-4 p-5 bg-blue-50/80 rounded-[28px] border-2 border-blue-200">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-blue-900 ml-1">Valor Gasto (R$)</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={fuelValue} 
                  onChange={e => setFuelValue(e.target.value)} 
                  placeholder="0,00"
                  className="w-full p-4 bg-white border-2 border-blue-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-blue-900 ml-1">Litros Abast.</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={liters} 
                  onChange={e => setLiters(e.target.value)} 
                  placeholder="0.00"
                  className="w-full p-4 bg-white border-2 border-blue-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
            </div>
          )}

          {/* Seção Específica de Serviço */}
          {type === 'SERVICE_REVENUE' && (
            <div className="space-y-4 p-5 bg-emerald-50/80 rounded-[28px] border-2 border-emerald-200">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black uppercase text-emerald-900 ml-1">KM de Partida</label>
                  <input 
                    type="number" 
                    inputMode="numeric" 
                    value={odometerStart} 
                    onChange={e => setOdometerStart(e.target.value)} 
                    className="w-full p-4 bg-white border-2 border-emerald-300 rounded-2xl text-sm font-black text-black focus:border-emerald-600 outline-none transition-all" 
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black uppercase text-emerald-900 ml-1">Taxa por KM (R$)</label>
                  <input 
                    type="number" 
                    inputMode="decimal" 
                    step="0.01" 
                    value={ratePerKm} 
                    onChange={e => setRatePerKm(e.target.value)} 
                    className="w-full p-4 bg-white border-2 border-emerald-300 rounded-2xl text-sm font-black text-black focus:border-emerald-600 outline-none transition-all" 
                  />
                </div>
              </div>
              <div className="flex gap-2">
                <button 
                  type="button" 
                  onClick={() => setStatus('RECEIVED')} 
                  className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase border-2 transition-all ${
                    status === 'RECEIVED' ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-emerald-200 text-emerald-900'
                  }`}
                >
                  Recebido
                </button>
                <button 
                  type="button" 
                  onClick={() => setStatus('PENDING')} 
                  className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase border-2 transition-all ${
                    status === 'PENDING' ? 'bg-amber-500 border-amber-500 text-white shadow-lg' : 'bg-white border-amber-200 text-amber-900'
                  }`}
                >
                  Em Aberto
                </button>
              </div>
            </div>
          )}

          {/* Notas */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Observações / Detalhes</label>
            <textarea 
              value={notes} 
              onChange={e => setNotes(e.target.value)} 
              rows={2} 
              placeholder="Ex: Troca de óleo, marca do combustível, etc..."
              className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all resize-none placeholder:text-slate-300" 
            />
          </div>

          {/* Rodapé e Botão Salvar */}
          <div className="pt-6 border-t border-slate-200 flex items-center justify-between">
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Valor Final</span>
              <span className="text-3xl font-black text-black">R$ {totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
            </div>
            <button 
              type="submit" 
              className="px-12 py-5 bg-black text-white font-black rounded-2xl shadow-2xl active:scale-95 uppercase tracking-widest text-[13px] hover:bg-slate-900 transition-all"
            >
              Salvar Registro
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { ExpenseType, Expense, Location, FuelType, MaintenanceItem, PaymentMethod } from '../types';
import { Plus, X, Trash2, CreditCard, Wallet, Zap } from 'lucide-react';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'>) => void;
  onClose: () => void;
  lastOdometer: number;
  locations: Location[];
}

export const ExpenseForm: React.FC<ExpenseFormProps> = ({ onAdd, onClose, lastOdometer, locations }) => {
  const [type, setType] = useState<ExpenseType>(ExpenseType.FUEL);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [locationId, setLocationId] = useState<string>('');
  const [notes, setNotes] = useState('');
  const [status, setStatus] = useState<'RECEIVED' | 'PENDING'>('RECEIVED');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('PIX');
  const [odometer, setOdometer] = useState<string>(lastOdometer.toString());
  const [fuelType, setFuelType] = useState<FuelType>('Gasolina');
  const [fuelValue, setFuelValue] = useState<string>('');
  const [liters, setLiters] = useState<string>('');
  const [maintItems, setMaintItems] = useState<MaintenanceItem[]>([{ id: crypto.randomUUID(), description: '', value: 0 }]);
  const [odometerStart, setOdometerStart] = useState<string>(lastOdometer.toString());
  const [ratePerKm, setRatePerKm] = useState<string>('0.00');

  const totalValue = useMemo(() => {
    if (type === ExpenseType.FUEL) return parseFloat(fuelValue) || 0;
    if (type === ExpenseType.MAINTENANCE) return maintItems.reduce((acc, item) => acc + (item.value || 0), 0);
    if (type === ExpenseType.SERVICE_REVENUE) {
      const dist = (parseFloat(odometer) || 0) - (parseFloat(odometerStart) || 0);
      return Math.max(0, dist * (parseFloat(ratePerKm) || 0));
    }
    return 0;
  }, [type, fuelValue, maintItems, odometer, odometerStart, ratePerKm]);

  const addMaintItem = () => {
    setMaintItems([...maintItems, { id: crypto.randomUUID(), description: '', value: 0 }]);
  };

  const updateMaintItem = (id: string, field: 'description' | 'value', val: any) => {
    setMaintItems(maintItems.map(item => 
      item.id === id ? { ...item, [field]: field === 'value' ? parseFloat(val) || 0 : val } : item
    ));
  };

  const removeMaintItem = (id: string) => {
    if (maintItems.length > 1) {
      setMaintItems(maintItems.filter(item => item.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!locationId) {
      alert("Por favor, selecione um local ou empresa.");
      return;
    }

    const payload: Omit<Expense, 'id'> = {
      type, 
      date, 
      odometer: parseFloat(odometer) || 0, 
      value: totalValue, 
      locationId, 
      notes: notes.trim(), 
      paymentMethod,
      description: type === ExpenseType.FUEL ? fuelType : (type === ExpenseType.SERVICE_REVENUE ? 'Km Rodado' : 'Manutenção'),
    };

    if (type === ExpenseType.FUEL) { 
      payload.fuelType = fuelType; 
      payload.liters = parseFloat(liters) || 0; 
    }
    else if (type === ExpenseType.MAINTENANCE) {
      payload.maintenanceItems = maintItems.filter(i => i.description.trim() !== '');
    }
    else if (type === ExpenseType.SERVICE_REVENUE) { 
      payload.odometerStart = parseFloat(odometerStart) || 0; 
      payload.ratePerKm = parseFloat(ratePerKm) || 0; 
      payload.status = status; 
    }

    onAdd(payload);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-end md:items-center justify-center p-0 md:p-4 overflow-hidden">
      <div className="bg-white rounded-t-[28px] md:rounded-[28px] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[92vh]">
        <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-white shrink-0">
          <h3 className="text-xl font-black text-black uppercase tracking-tight">Novo Registro</h3>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-black transition-colors">
            <X size={28} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 overflow-y-auto pb-10 scrollbar-hide">
          {/* Tipo de Lançamento */}
          <div className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200">
            {(['FUEL', 'MAINTENANCE', 'SERVICE_REVENUE'] as ExpenseType[]).map((t) => (
              <button 
                key={t} 
                type="button" 
                onClick={() => setType(t)} 
                className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase tracking-tight transition-all ${
                  type === t ? 'bg-white text-black shadow-md border border-slate-200' : 'text-slate-500 hover:text-black'
                }`}
              >
                {t === 'FUEL' ? 'Abastecer' : t === 'MAINTENANCE' ? 'Oficina' : 'Serviço'}
              </button>
            ))}
          </div>

          {/* Data e KM */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Data</label>
              <input 
                type="date" 
                value={date} 
                onChange={e => setDate(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all" 
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">KM Final</label>
              <input 
                type="number" 
                inputMode="numeric" 
                value={odometer} 
                onChange={e => setOdometer(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all" 
              />
            </div>
          </div>

          {/* Local */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Local / Empresa</label>
            <div className="relative">
              <select 
                value={locationId} 
                onChange={e => setLocationId(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all appearance-none"
              >
                <option value="">Selecione...</option>
                {locations.filter(l => (type === 'FUEL' && l.type === 'POSTO') || (type === 'MAINTENANCE' && l.type === 'OFICINA') || (type === 'SERVICE_REVENUE' && l.type === 'CLIENTE')).map(loc => (
                  <option key={loc.id} value={loc.id} className="font-bold text-black">{loc.name}</option>
                ))}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-black">
                <Plus size={20} />
              </div>
            </div>
          </div>

          {/* Pagamento */}
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Pagamento</label>
            <div className="grid grid-cols-4 gap-2">
              {(['PIX', 'CREDITO', 'DEBITO', 'DINHEIRO'] as PaymentMethod[]).map(pm => (
                <button 
                  key={pm} 
                  type="button" 
                  onClick={() => setPaymentMethod(pm)} 
                  className={`py-4 rounded-2xl flex flex-col items-center justify-center gap-1 border-2 transition-all ${
                    paymentMethod === pm ? 'bg-black border-black text-white shadow-lg scale-105' : 'bg-white border-slate-300 text-black hover:border-slate-400'
                  }`}
                >
                  {pm === 'PIX' ? <Zap size={18} /> : pm === 'DINHEIRO' ? <Wallet size={18} /> : <CreditCard size={18} />}
                  <span className="text-[9px] font-black uppercase tracking-tight">{pm}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Abastecimento */}
          {type === 'FUEL' && (
            <div className="grid grid-cols-2 gap-4 p-5 bg-blue-50/50 rounded-[28px] border-2 border-blue-100">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-black ml-1">Valor (R$)</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={fuelValue} 
                  onChange={e => setFuelValue(e.target.value)} 
                  placeholder="0,00"
                  className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-black ml-1">Litros</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={liters} 
                  onChange={e => setLiters(e.target.value)} 
                  placeholder="0.00"
                  className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
            </div>
          )}

          {/* Oficina (Itens da Manutenção) */}
          {type === 'MAINTENANCE' && (
            <div className="space-y-4 p-5 bg-orange-50/50 rounded-[28px] border-2 border-orange-100">
              <div className="flex justify-between items-center mb-2">
                <label className="text-[10px] font-black uppercase text-black ml-1">Itens da Manutenção</label>
                <button 
                  type="button" 
                  onClick={addMaintItem}
                  className="text-[9px] font-black uppercase bg-black text-white px-3 py-1.5 rounded-lg flex items-center gap-1 shadow-md active:scale-95"
                >
                  <Plus size={12} /> Add Item
                </button>
              </div>

              <div className="space-y-3">
                {maintItems.map((item) => (
                  <div key={item.id} className="flex gap-2 items-start">
                    <div className="flex-1">
                      <input 
                        type="text" 
                        placeholder="Peça ou Serviço" 
                        value={item.description}
                        onChange={(e) => updateMaintItem(item.id, 'description', e.target.value)}
                        className="w-full p-3 bg-white border-2 border-slate-300 rounded-xl text-xs font-black text-black focus:border-orange-600 outline-none transition-all"
                      />
                    </div>
                    <div className="w-24">
                      <input 
                        type="number" 
                        inputMode="decimal"
                        step="0.01"
                        placeholder="Valor"
                        value={item.value || ''}
                        onChange={(e) => updateMaintItem(item.id, 'value', e.target.value)}
                        className="w-full p-3 bg-white border-2 border-slate-300 rounded-xl text-xs font-black text-black focus:border-orange-600 outline-none transition-all"
                      />
                    </div>
                    {maintItems.length > 1 && (
                      <button 
                        type="button" 
                        onClick={() => removeMaintItem(item.id)}
                        className="p-3 text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                      >
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Serviço (Ganhos por KM) */}
          {type === 'SERVICE_REVENUE' && (
            <div className="space-y-4 p-5 bg-emerald-50/50 rounded-[28px] border-2 border-emerald-100">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black uppercase text-black ml-1">KM Inicial</label>
                  <input 
                    type="number" 
                    inputMode="numeric" 
                    value={odometerStart} 
                    onChange={e => setOdometerStart(e.target.value)} 
                    className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-emerald-600 outline-none transition-all" 
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black uppercase text-black ml-1">Taxa/KM (R$)</label>
                  <input 
                    type="number" 
                    inputMode="decimal" 
                    step="0.01" 
                    value={ratePerKm} 
                    onChange={e => setRatePerKm(e.target.value)} 
                    className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-emerald-600 outline-none transition-all" 
                  />
                </div>
              </div>
              <div className="flex gap-2">
                <button 
                  type="button" 
                  onClick={() => setStatus('RECEIVED')} 
                  className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase border-2 transition-all ${
                    status === 'RECEIVED' ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-slate-300 text-black'
                  }`}
                >
                  Recebido
                </button>
                <button 
                  type="button" 
                  onClick={() => setStatus('PENDING')} 
                  className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase border-2 transition-all ${
                    status === 'PENDING' ? 'bg-amber-500 border-amber-500 text-white shadow-lg' : 'bg-white border-slate-300 text-black'
                  }`}
                >
                  Pendente
                </button>
              </div>
            </div>
          )}

          {/* Notas */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Observações</label>
            <textarea 
              value={notes} 
              onChange={e => setNotes(e.target.value)} 
              rows={2} 
              placeholder="Notas adicionais..."
              className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all resize-none placeholder:text-slate-300" 
            />
          </div>

          {/* Resumo e Botão Final */}
          <div className="pt-6 border-t border-slate-200 flex items-center justify-between bg-white sticky bottom-0">
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Valor Total</span>
              <span className="text-3xl font-black text-black">R$ {totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
            </div>
            <button 
              type="submit" 
              className="px-10 py-5 bg-black text-white font-black rounded-2xl shadow-xl active:scale-95 uppercase tracking-widest text-[13px] hover:bg-slate-900 transition-all"
            >
              Salvar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
