              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-black">
                <Plus size={20} />
              </div>
            </div>
          </div>

          {/* Pagamento */}
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Pagamento</label>
            <div className="grid grid-cols-4 gap-2">
              {(['PIX', 'CREDITO', 'DEBITO', 'DINHEIRO'] as PaymentMethod[]).map(pm => (
                <button 
                  key={pm} 
                  type="button" 
                  onClick={() => setPaymentMethod(pm)} 
                  className={`py-4 rounded-2xl flex flex-col items-center justify-center gap-1 border-2 transition-all ${
                    paymentMethod === pm ? 'bg-black border-black text-white shadow-lg scale-105' : 'bg-white border-slate-300 text-black hover:border-slate-400'
                  }`}
                >
                  {pm === 'PIX' ? <Zap size={18} /> : pm === 'DINHEIRO' ? <Wallet size={18} /> : <CreditCard size={18} />}
                  <span className="text-[9px] font-black uppercase tracking-tight">{pm}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Abastecimento */}
          {type === 'FUEL' && (
            <div className="grid grid-cols-2 gap-4 p-5 bg-blue-50/50 rounded-[28px] border-2 border-blue-100">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-black ml-1">Valor (R$)</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={fuelValue} 
                  onChange={e => setFuelValue(e.target.value)} 
                  placeholder="0,00"
                  className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-black ml-1">Litros</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={liters} 
                  onChange={e => setLiters(e.target.value)} 
                  placeholder="0.00"
                  className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
            </div>
          )}

          {/* Oficina (Itens da Manutenção) */}
          {type === 'MAINTENANCE' && (
            <div className="space-y-4 p-5 bg-orange-50/50 rounded-[28px] border-2 border-orange-100">
              <div className="flex justify-between items-center mb-2">
                <label className="text-[10px] font-black uppercase text-black ml-1">Itens da Manutenção</label>
                <button 
                  type="button" 
                  onClick={addMaintItem}
                  className="text-[9px] font-black uppercase bg-black text-white px-3 py-1.5 rounded-lg flex items-center gap-1 shadow-md active:scale-95"
                >
                  <Plus size={12} /> Add Item
                </button>
              </div>

              <div className="space-y-3">
                {maintItems.map((item) => (
                  <div key={item.id} className="flex gap-2 items-start">
                    <div className="flex-1">
                      <input 
                        type="text" 
                        placeholder="Peça ou Serviço" 
                        value={item.description}
                        onChange={(e) => updateMaintItem(item.id, 'description', e.target.value)}
                        className="w-full p-3 bg-white border-2 border-slate-300 rounded-xl text-xs font-black text-black focus:border-orange-600 outline-none transition-all"
                      />
                    </div>
                    <div className="w-24">
                      <input 
                        type="number" 
                        inputMode="decimal"
                        step="0.01"
                        placeholder="Valor"
                        value={item.value || ''}
                        onChange={(e) => updateMaintItem(item.id, 'value', e.target.value)}
                        className="w-full p-3 bg-white border-2 border-slate-300 rounded-xl text-xs font-black text-black focus:border-orange-600 outline-none transition-all"
                      />
                    </div>
                    {maintItems.length > 1 && (
                      <button 
                        type="button" 
                        onClick={() => removeMaintItem(item.id)}
                        className="p-3 text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                      >
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Serviço (Ganhos por KM) */}
          {type === 'SERVICE_REVENUE' && (
            <div className="space-y-4 p-5 bg-emerald-50/50 rounded-[28px] border-2 border-emerald-100">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black uppercase text-black ml-1">KM Inicial</label>
                  <input 
                    type="number" 
                    inputMode="numeric" 
                    value={odometerStart} 
                    onChange={e => setOdometerStart(e.target.value)} 
                    className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-emerald-600 outline-none transition-all" 
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black uppercase text-black ml-1">Taxa/KM (R$)</label>
                  <input 
                    type="number" 
                    inputMode="decimal" 
                    step="0.01" 
                    value={ratePerKm} 
                    onChange={e => setRatePerKm(e.target.value)} 
                    className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-emerald-600 outline-none transition-all" 
                  />
                </div>
              </div>
              <div className="flex gap-2">
                <button 
                  type="button" 
                  onClick={() => setStatus('RECEIVED')} 
                  className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase border-2 transition-all ${
                    status === 'RECEIVED' ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-slate-300 text-black'
                  }`}
                >
                  Recebido
                </button>
                <button 
                  type="button" 
                  onClick={() => setStatus('PENDING')} 
                  className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase border-2 transition-all ${
                    status === 'PENDING' ? 'bg-amber-500 border-amber-500 text-white shadow-lg' : 'bg-white border-slate-300 text-black'
                  }`}
                >
                  Pendente
                </button>
              </div>
            </div>
          )}

          {/* Notas */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Observações</label>
            <textarea 
              value={notes} 
              onChange={e => setNotes(e.target.value)} 
              rows={2} 
              placeholder="Notas adicionais..."
              className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all resize-none placeholder:text-slate-300" 
            />
          </div>

          {/* Resumo e Botão Final (Não mais fixo) */}
          <div className="pt-6 border-t border-slate-200 flex items-center justify-between bg-white pb-8">
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Valor Total</span>
              <span className="text-3xl font-black text-black">R$ {totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
            </div>
            <button 
              type="submit" 
              className="px-10 py-5 bg-black text-white font-black rounded-2xl shadow-xl active:scale-95 uppercase tracking-widest text-[13px] hover:bg-slate-900 transition-all"
            >
              Salvar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export enum ExpenseType {
  FUEL = 'FUEL',
  MAINTENANCE = 'MAINTENANCE',
  SERVICE_REVENUE = 'SERVICE_REVENUE',
  OTHER = 'OTHER'
}

export type FuelType = 'Gasolina' | 'Etanol' | 'Diesel' | 'GNV';

export type PaymentMethod = 'DINHEIRO' | 'CREDITO' | 'DEBITO' | 'PIX' | 'NOTA_PRAZO';

export interface MaintenanceItem {
  id: string;
  description: string;
  value: number;
}

export interface Location {
  id: string;
  name: string;
  type: 'POSTO' | 'OFICINA' | 'CLIENTE';
}

export interface Expense {
  id: string;
  date: string;
  type: ExpenseType;
  odometer: number; // No caso de serviço, é o odômetro final
  odometerStart?: number; // Específico para serviço
  value: number;
  locationId?: string;
  fuelType?: FuelType;
  liters?: number;
  description: string;
  notes?: string; // Campo para observações personalizadas
  maintenanceItems?: MaintenanceItem[];
  ratePerKm?: number; // Específico para serviço
  status?: 'RECEIVED' | 'PENDING'; // Status específico para SERVICE_REVENUE
  paymentMethod?: PaymentMethod;
}

export interface CarStats {
  totalSpent: number;
  totalLiters: number;
  averageConsumption: number;
  totalDistance: number;
  lastOdometer: number;
  totalServiceRevenue: number;
  pendingServiceRevenue: number;
}

import React, { useState, useMemo } from 'react';
import { ExpenseType, Expense, Location, FuelType, MaintenanceItem, PaymentMethod } from '../types';
import { Plus, X, Trash2, CreditCard, Wallet, Zap, FileText } from 'lucide-react';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'>) => void;
  onClose: () => void;
  lastOdometer: number;
  locations: Location[];
}

export const ExpenseForm: React.FC<ExpenseFormProps> = ({ onAdd, onClose, lastOdometer, locations }) => {
  const [type, setType] = useState<ExpenseType>(ExpenseType.FUEL);
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [locationId, setLocationId] = useState<string>('');
  const [notes, setNotes] = useState('');
  const [status, setStatus] = useState<'RECEIVED' | 'PENDING'>('RECEIVED');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('PIX');
  const [odometer, setOdometer] = useState<string>(lastOdometer.toString());
  const [fuelType, setFuelType] = useState<FuelType>('Gasolina');
  const [fuelValue, setFuelValue] = useState<string>('');
  const [liters, setLiters] = useState<string>('');
  const [maintItems, setMaintItems] = useState<MaintenanceItem[]>([{ id: crypto.randomUUID(), description: '', value: 0 }]);
  const [odometerStart, setOdometerStart] = useState<string>(lastOdometer.toString());
  const [ratePerKm, setRatePerKm] = useState<string>('0.00');

  const totalValue = useMemo(() => {
    if (type === ExpenseType.FUEL) return parseFloat(fuelValue) || 0;
    if (type === ExpenseType.MAINTENANCE) return maintItems.reduce((acc, item) => acc + (item.value || 0), 0);
    if (type === ExpenseType.SERVICE_REVENUE) {
      const dist = (parseFloat(odometer) || 0) - (parseFloat(odometerStart) || 0);
      return Math.max(0, dist * (parseFloat(ratePerKm) || 0));
    }
    return 0;
  }, [type, fuelValue, maintItems, odometer, odometerStart, ratePerKm]);

  const addMaintItem = () => {
    setMaintItems([...maintItems, { id: crypto.randomUUID(), description: '', value: 0 }]);
  };

  const updateMaintItem = (id: string, field: 'description' | 'value', val: any) => {
    setMaintItems(maintItems.map(item => 
      item.id === id ? { ...item, [field]: field === 'value' ? parseFloat(val) || 0 : val } : item
    ));
  };

  const removeMaintItem = (id: string) => {
    if (maintItems.length > 1) {
      setMaintItems(maintItems.filter(item => item.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!locationId) {
      alert("Por favor, selecione um local ou empresa.");
      return;
    }

    const payload: Omit<Expense, 'id'> = {
      type, 
      date, 
      odometer: parseFloat(odometer) || 0, 
      value: totalValue, 
      locationId, 
      notes: notes.trim(), 
      paymentMethod,
      description: type === ExpenseType.FUEL ? fuelType : (type === ExpenseType.SERVICE_REVENUE ? 'Km Rodado' : 'Manutenção'),
    };

    if (type === ExpenseType.FUEL) { 
      payload.fuelType = fuelType; 
      payload.liters = parseFloat(liters) || 0; 
    }
    else if (type === ExpenseType.MAINTENANCE) {
      payload.maintenanceItems = maintItems.filter(i => i.description.trim() !== '');
    }
    else if (type === ExpenseType.SERVICE_REVENUE) { 
      payload.odometerStart = parseFloat(odometerStart) || 0; 
      payload.ratePerKm = parseFloat(ratePerKm) || 0; 
      payload.status = status; 
    }

    onAdd(payload);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-end md:items-center justify-center p-0 md:p-4 overflow-hidden">
      <div className="bg-white rounded-t-[28px] md:rounded-[28px] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[92vh]">
        <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-white shrink-0">
          <h3 className="text-xl font-black text-black uppercase tracking-tight">Novo Registro</h3>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-black transition-colors">
            <X size={28} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 overflow-y-auto pb-6 scrollbar-hide">
          {/* Tipo de Lançamento */}
          <div className="flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200">
            {(['FUEL', 'MAINTENANCE', 'SERVICE_REVENUE'] as ExpenseType[]).map((t) => (
              <button 
                key={t} 
                type="button" 
                onClick={() => setType(t)} 
                className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase tracking-tight transition-all ${
                  type === t ? 'bg-white text-black shadow-md border border-slate-200' : 'text-slate-500 hover:text-black'
                }`}
              >
                {t === 'FUEL' ? 'Abastecer' : t === 'MAINTENANCE' ? 'Oficina' : 'Serviço'}
              </button>
            ))}
          </div>

          {/* Data e KM */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Data</label>
              <input 
                type="date" 
                value={date} 
                onChange={e => setDate(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all" 
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">KM Final</label>
              <input 
                type="number" 
                inputMode="numeric" 
                value={odometer} 
                onChange={e => setOdometer(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all" 
              />
            </div>
          </div>

          {/* Local */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Local / Empresa</label>
            <div className="relative">
              <select 
                value={locationId} 
                onChange={e => setLocationId(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all appearance-none"
              >
                <option value="">Selecione...</option>
                {locations.filter(l => (type === 'FUEL' && l.type === 'POSTO') || (type === 'MAINTENANCE' && l.type === 'OFICINA') || (type === 'SERVICE_REVENUE' && l.type === 'CLIENTE')).map(loc => (
                  <option key={loc.id} value={loc.id} className="font-bold text-black">{loc.name}</option>
                ))}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-black">
                <Plus size={20} />
              </div>
            </div>
          </div>

          {/* Pagamento */}
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Pagamento</label>
            <div className="grid grid-cols-2 xs:grid-cols-3 sm:grid-cols-5 gap-2">
              {(['PIX', 'CREDITO', 'DEBITO', 'DINHEIRO', 'NOTA_PRAZO'] as PaymentMethod[]).map(pm => (
                <button 
                  key={pm} 
                  type="button" 
                  onClick={() => setPaymentMethod(pm)} 
                  className={`py-4 rounded-2xl flex flex-col items-center justify-center gap-1 border-2 transition-all ${
                    paymentMethod === pm ? 'bg-black border-black text-white shadow-lg scale-105' : 'bg-white border-slate-300 text-black hover:border-slate-400'
                  }`}
                >
                  {pm === 'PIX' ? <Zap size={18} /> : pm === 'DINHEIRO' ? <Wallet size={18} /> : pm === 'NOTA_PRAZO' ? <FileText size={18} /> : <CreditCard size={18} />}
                  <span className="text-[9px] font-black uppercase tracking-tight">
                    {pm === 'NOTA_PRAZO' ? 'A Prazo' : pm}
                  </span>
                </button>
              ))}
            </div>
          </div>

          {/* Abastecimento */}
          {type === 'FUEL' && (
            <div className="grid grid-cols-2 gap-4 p-5 bg-blue-50/50 rounded-[28px] border-2 border-blue-100">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-black ml-1">Valor (R$)</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={fuelValue} 
                  onChange={e => setFuelValue(e.target.value)} 
                  placeholder="0,00"
                  className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-black ml-1">Litros</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={liters} 
                  onChange={e => setLiters(e.target.value)} 
                  placeholder="0.00"
                  className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
            </div>
          )}

          {/* Oficina (Itens da Manutenção) */}
          {type === 'MAINTENANCE' && (
            <div className="space-y-4 p-5 bg-orange-50/50 rounded-[28px] border-2 border-orange-100">
              <div className="flex justify-between items-center mb-2">
                <label className="text-[10px] font-black uppercase text-black ml-1">Itens da Manutenção</label>
                <button 
                  type="button" 
                  onClick={addMaintItem}
                  className="text-[9px] font-black uppercase bg-black text-white px-3 py-1.5 rounded-lg flex items-center gap-1 shadow-md active:scale-95"
                >
                  <Plus size={12} /> Add Item
                </button>
              </div>

              <div className="space-y-3">
                {maintItems.map((item) => (
                  <div key={item.id} className="flex gap-2 items-start">
                    <div className="flex-1">
                      <input 
                        type="text" 
                        placeholder="Peça ou Serviço" 
                        value={item.description}
                        onChange={(e) => updateMaintItem(item.id, 'description', e.target.value)}
                        className="w-full p-3 bg-white border-2 border-slate-300 rounded-xl text-xs font-black text-black focus:border-orange-600 outline-none transition-all"
                      />
                    </div>
                    <div className="w-24">
                      <input 
                        type="number" 
                        inputMode="decimal"
                        step="0.01"
                        placeholder="Valor"
                        value={item.value || ''}
                        onChange={(e) => updateMaintItem(item.id, 'value', e.target.value)}
                        className="w-full p-3 bg-white border-2 border-slate-300 rounded-xl text-xs font-black text-black focus:border-orange-600 outline-none transition-all"
                      />
                    </div>
                    {maintItems.length > 1 && (
                      <button 
                        type="button" 
                        onClick={() => removeMaintItem(item.id)}
                        className="p-3 text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                      >
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Serviço (Ganhos por KM) */}
          {type === 'SERVICE_REVENUE' && (
            <div className="space-y-4 p-5 bg-emerald-50/50 rounded-[28px] border-2 border-emerald-100">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black uppercase text-black ml-1">KM Inicial</label>
                  <input 
                    type="number" 
                    inputMode="numeric" 
                    value={odometerStart} 
                    onChange={e => setOdometerStart(e.target.value)} 
                    className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-emerald-600 outline-none transition-all" 
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black uppercase text-black ml-1">Taxa/KM (R$)</label>
                  <input 
                    type="number" 
                    inputMode="decimal" 
                    step="0.01" 
                    value={ratePerKm} 
                    onChange={e => setRatePerKm(e.target.value)} 
                    className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-emerald-600 outline-none transition-all" 
                  />
                </div>
              </div>
              <div className="flex gap-2">
                <button 
                  type="button" 
                  onClick={() => setStatus('RECEIVED')} 
                  className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase border-2 transition-all ${
                    status === 'RECEIVED' ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-slate-300 text-black'
                  }`}
                >
                  Recebido
                </button>
                <button 
                  type="button" 
                  onClick={() => setStatus('PENDING')} 
                  className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase border-2 transition-all ${
                    status === 'PENDING' ? 'bg-amber-500 border-amber-500 text-white shadow-lg' : 'bg-white border-slate-300 text-black'
                  }`}
                >
                  Pendente
                </button>
              </div>
            </div>
          )}

          {/* Notas */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Observações</label>
            <textarea 
              value={notes} 
              onChange={e => setNotes(e.target.value)} 
              rows={2} 
              placeholder="Notas adicionais..."
              className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all resize-none placeholder:text-slate-300" 
            />
          </div>

          {/* Resumo e Botão Final */}
          <div className="pt-6 border-t border-slate-200 flex items-center justify-between bg-white pb-8">
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Valor Total</span>
              <span className="text-3xl font-black text-black">R$ {totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
            </div>
            <button 
              type="submit" 
              className="px-10 py-5 bg-black text-white font-black rounded-2xl shadow-xl active:scale-95 uppercase tracking-widest text-[13px] hover:bg-slate-900 transition-all"
            >
              Salvar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location, PaymentMethod } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { LocationManager } from './components/LocationManager';
import { Reports } from './components/Reports';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Fuel, Wrench, Gauge, MapPin, Navigation, MessageSquare, FileText, Printer, ChevronRight, CheckCircle2, Clock, Zap, CreditCard, Wallet } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'locations' | 'reports'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleAddExpense = (newExpense: Omit<Expense, 'id'>) => {
    const expense: Expense = {
      ...newExpense,
      id: crypto.randomUUID(),
    };
    setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  const getPaymentMethodLabel = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return { label: 'PIX', icon: <Zap size={10} /> };
      case 'CREDITO': return { label: 'Crédito', icon: <CreditCard size={10} /> };
      case 'DEBITO': return { label: 'Débito', icon: <CreditCard size={10} /> };
      case 'DINHEIRO': return { label: 'Dinheiro', icon: <Wallet size={10} /> };
      case 'NOTA_PRAZO': return { label: 'Nota a Prazo', icon: <FileText size={10} /> };
      default: return { label: '-', icon: null };
    }
  };

  const NavItem = ({ id, icon: Icon, label }: { id: any, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center gap-1 flex-1 py-1 transition-all rounded-xl ${
        activeTab === id ? 'text-blue-600 bg-blue-50/50' : 'text-slate-500 hover:text-slate-700'
      }`}
    >
      <Icon size={20} className={activeTab === id ? 'scale-110' : ''} />
      <span className="text-[9px] font-black uppercase tracking-tighter">{label}</span>
    </button>
  );

  return (
    <div className="flex min-h-screen bg-[#F8FAFC] w-full overflow-x-hidden">
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-200 flex items-center justify-between z-[90] no-print safe-pb shadow-[0_-8px_30px_rgb(0,0,0,0.08)] h-16 px-4 max-w-lg mx-auto md:rounded-t-[32px]">
        <NavItem id="dashboard" icon={LayoutDashboard} label="Início" />
        <NavItem id="history" icon={History} label="Histórico" />

        <div className="relative -top-6">
          <button 
            onClick={() => setIsFormOpen(true)}
            className="w-14 h-14 bg-blue-600 text-white rounded-2xl shadow-xl flex items-center justify-center active:scale-90 hover:bg-blue-700 transition-all border-4 border-[#F8FAFC]"
          >
            <Plus size={28} strokeWidth={3} />
          </button>
        </div>

        <NavItem id="reports" icon={FileText} label="Relatórios" />
        <NavItem id="locations" icon={MapPin} label="Locais" />
      </nav>

      <div className="flex-1 transition-all duration-300 pb-24 w-full overflow-x-hidden">
        <header className="bg-white/90 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40 no-print">
          <div className="max-w-4xl mx-auto px-4 py-4 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-md">
                <Gauge size={18} />
              </div>
              <h2 className="text-sm md:text-base font-black text-black uppercase tracking-tight truncate">
                {activeTab === 'dashboard' && 'Visão Geral'}
                {activeTab === 'history' && 'Histórico'}
                {activeTab === 'reports' && 'Relatórios'}
                {activeTab === 'locations' && 'Locais'}
              </h2>
            </div>

            <div className="flex items-center gap-2 shrink-0">
              <span className="text-[9px] md:text-xs font-black text-black uppercase tracking-widest bg-slate-100 px-2.5 py-1.5 rounded-xl border border-slate-300">
                KM: {lastOdometer.toLocaleString()}
              </span>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 md:px-6 py-6 w-full">
          {activeTab === 'dashboard' && (
            <div className="no-print animate-in fade-in duration-500 w-full overflow-x-hidden">
              {expenses.length >= 2 && (
                <div className="mb-6 bg-gradient-to-br from-blue-700 to-indigo-800 rounded-[28px] p-6 text-white shadow-xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                  <div className="relative z-10">
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center space-x-2">
                        <Sparkles size={16} className="text-yellow-300" />
                        <h2 className="font-black text-xs md:text-sm uppercase tracking-tight">Sugestões de Economia</h2>
                      </div>
                      <button 
                        onClick={fetchAIInsights}
                        disabled={loadingInsights}
                        className="text-[9px] font-black uppercase tracking-widest bg-white/20 px-3 py-1.5 rounded-lg border border-white/10"
                      >
                        {loadingInsights ? "..." : "Atualizar"}
                      </button>
                    </div>
                    {insights.length > 0 ? (
                      <div className="space-y-2">
                        {insights.slice(0, 2).map((tip, idx) => (
                          <div key={idx} className="bg-white/10 backdrop-blur-md p-3 rounded-xl text-[10px] md:text-[11px] font-bold border border-white/5 shadow-sm">
                            {tip}
                          </div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-white/70 text-[10px] font-bold">Gerencie suas despesas e peça dicas à IA.</p>
                    )}
                  </div>
                </div>
              )}
              <Dashboard expenses={expenses} />
            </div>
          )}

          {activeTab === 'locations' && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <LocationManager locations={locations} onAdd={handleAddLocation} onRemove={handleRemoveLocation} />
            </div>
          )}

          {activeTab === 'reports' && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Reports expenses={expenses} locations={locations} />
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-4 animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <div className="flex justify-between items-center mb-4 no-print px-1">
                <h3 className="text-xl font-black text-black tracking-tight">Atividades</h3>
                <button onClick={() => window.print()} className="p-2.5 bg-white border border-slate-300 rounded-xl text-black hover:bg-slate-50 transition-all shadow-sm"><Printer size={18} /></button>
              </div>

              {expenses.length === 0 ? (
                <div className="bg-white p-12 text-center text-slate-400 rounded-[32px] border-2 border-dashed border-slate-200">
                  <History size={40} className="mx-auto mb-4 opacity-20" />
                  <p className="text-sm font-bold">Nenhum lançamento encontrado.</p>
                </div>
              ) : (
                expenses.map(expense => (
                  <div key={expense.id} className="bg-white rounded-[24px] p-4 md:p-5 shadow-md border border-slate-200 flex items-center gap-4 group active:scale-[0.98] transition-all w-full hover:shadow-lg">
                    <div className={`p-3 rounded-2xl shrink-0 ${
                      expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-700' : 
                      expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-700' :
                      'bg-emerald-50 text-emerald-700'
                    }`}>
                      {expense.type === ExpenseType.FUEL ? <Fuel size={20} /> : 
                       expense.type === ExpenseType.MAINTENANCE ? <Wrench size={20} /> : 
                       <Navigation size={20} />}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] md:text-[10px] font-black uppercase text-slate-600">{new Date(expense.date).toLocaleDateString()}</span>
                        {expense.type === ExpenseType.SERVICE_REVENUE && (
                          <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded-md ${
                            expense.status === 'RECEIVED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                          }`}>
                            {expense.status === 'RECEIVED' ? 'OK' : 'PENDENTE'}
                          </span>
                        )}
                      </div>
                      <h4 className="font-black text-black text-sm md:text-base tracking-tight truncate">
                        {expense.type === ExpenseType.FUEL ? expense.fuelType : 
                         expense.type === ExpenseType.SERVICE_REVENUE ? 'Serviço Realizado' : 'Manutenção'}
                      </h4>
                      <div className="flex flex-wrap gap-2 mt-0.5">
                        <p className="text-[10px] md:text-[11px] font-bold text-slate-700 truncate flex items-center gap-1">
                          <MapPin size={8} /> {getLocationName(expense.locationId)}
                        </p>
                        <span className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-1 bg-blue-50 px-1.5 rounded-md">
                          {getPaymentMethodLabel(expense.paymentMethod).icon}
