        <div className="grid grid-cols-1 gap-2">
          {[
            { label: 'Abastecimento', desc: 'Controle de litros e KM', color: 'bg-blue-600' },
            { label: 'Manutenção (Oficina)', desc: 'Peças e serviços mecânicos', color: 'bg-orange-600' },
            { label: 'Serviço Realizado', desc: 'Ganhos baseados em KM rodado', color: 'bg-emerald-600' }
          ].map((cat, i) => (
            <div key={i} className="flex items-center gap-4 p-4 rounded-2xl border border-slate-100">
              <div className={`w-2 h-10 rounded-full ${cat.color}`}></div>
              <div>
                <p className="text-sm font-black text-black uppercase">{cat.label}</p>
                <p className="text-[10px] font-bold text-slate-500 uppercase">{cat.desc}</p>
