                <Gauge size={18} />
              </div>
              <h2 className="text-sm md:text-base font-black text-black uppercase tracking-tight truncate">
                {activeTab === 'dashboard' && 'Visão Geral'}
                {activeTab === 'history' && 'Histórico'}
                {activeTab === 'reports' && 'Relatórios'}
                {activeTab === 'settings' && 'Configurações'}
              </h2>
            </div>

            <div className="flex items-center gap-2 shrink-0">
              <span className="text-[9px] md:text-xs font-black text-black uppercase tracking-widest bg-slate-100 px-2.5 py-1.5 rounded-xl border border-slate-300">
                KM: {lastOdometer.toLocaleString()}
              </span>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 md:px-6 py-6 w-full">
          {activeTab === 'dashboard' && (
            <div className="no-print animate-in fade-in duration-500 w-full overflow-x-hidden">
              {expenses.length >= 2 && (
                <div className="mb-6 bg-gradient-to-br from-blue-700 to-indigo-800 rounded-[28px] p-6 text-white shadow-xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                  <div className="relative z-10">
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center space-x-2">
                        <Sparkles size={16} className="text-yellow-300" />
                        <h2 className="font-black text-xs md:text-sm uppercase tracking-tight">Sugestões de Economia</h2>
                      </div>
                      <button 
                        onClick={fetchAIInsights}
                        disabled={loadingInsights}
                        className="text-[9px] font-black uppercase tracking-widest bg-white/20 px-3 py-1.5 rounded-lg border border-white/10"
                      >
                        {loadingInsights ? "..." : "Atualizar"}
                      </button>
                    </div>
                    {insights.length > 0 ? (
                      <div className="space-y-2">
                        {insights.slice(0, 2).map((tip, idx) => (
                          <div key={idx} className="bg-white/10 backdrop-blur-md p-3 rounded-xl text-[10px] md:text-[11px] font-bold border border-white/5 shadow-sm">
                            {tip}
                          </div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-white/70 text-[10px] font-bold">Gerencie suas despesas e peça dicas à IA.</p>
                    )}
                  </div>
                </div>
              )}
              <Dashboard expenses={expenses} />
            </div>
          )}

          {activeTab === 'settings' && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Settings locations={locations} onAddLocation={handleAddLocation} onRemoveLocation={handleRemoveLocation} />
            </div>
          )}

          {activeTab === 'reports' && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Reports expenses={expenses} locations={locations} />
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-4 animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <div className="flex justify-between items-center mb-4 no-print px-1">
                <h3 className="text-xl font-black text-black tracking-tight">Atividades</h3>
                <button onClick={() => window.print()} className="p-2.5 bg-white border border-slate-300 rounded-xl text-black hover:bg-slate-50 transition-all shadow-sm"><Printer size={18} /></button>
              </div>

              {expenses.length === 0 ? (
                <div className="bg-white p-12 text-center text-slate-400 rounded-[32px] border-2 border-dashed border-slate-200">
                  <History size={40} className="mx-auto mb-4 opacity-20" />
                  <p className="text-sm font-bold">Nenhum lançamento encontrado.</p>
                </div>
              ) : (
                expenses.map(expense => (
                  <div key={expense.id} className="bg-white rounded-[24px] p-4 md:p-5 shadow-md border border-slate-200 flex items-center gap-4 group active:scale-[0.98] transition-all w-full hover:shadow-lg">
                    <div className={`p-3 rounded-2xl shrink-0 ${
                      expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-700' : 
                      expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-700' :
                      'bg-emerald-50 text-emerald-700'
                    }`}>
                      {expense.type === ExpenseType.FUEL ? <Fuel size={20} /> : 
                       expense.type === ExpenseType.MAINTENANCE ? <Wrench size={20} /> : 
                       <Navigation size={20} />}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] md:text-[10px] font-black uppercase text-slate-600">{new Date(expense.date).toLocaleDateString()}</span>
                        {expense.type === ExpenseType.SERVICE_REVENUE && (
                          <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded-md ${
                            expense.status === 'RECEIVED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                          }`}>
                            {expense.status === 'RECEIVED' ? 'OK' : 'PENDENTE'}
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-2 mb-0.5">
                        <h4 className="font-black text-black text-sm md:text-base tracking-tight truncate">
                          {expense.type === ExpenseType.FUEL ? expense.fuelType : 
                          expense.type === ExpenseType.SERVICE_REVENUE ? 'Serviço Realizado' : 'Manutenção'}
                        </h4>
                        {expense.type === ExpenseType.FUEL && expense.liters && expense.liters > 0 && (
                          <span className="text-[9px] font-black text-slate-600 bg-slate-100 px-1.5 py-0.5 rounded-md whitespace-nowrap border border-slate-200">
                            R$ {(expense.value / expense.liters).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} /L
                          </span>
                        )}
                      </div>
                      <div className="flex flex-wrap gap-2 mt-0.5">
                        <p className="text-[10px] md:text-[11px] font-bold text-slate-700 truncate flex items-center gap-1">
                          <MapPin size={8} /> {getLocationName(expense.locationId)}
                        </p>
                        <span className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-1 bg-blue-50 px-1.5 rounded-md">
                          {getPaymentMethodLabel(expense.paymentMethod).icon}
                          {getPaymentMethodLabel(expense.paymentMethod).label}
                        </span>
                        {expense.type === ExpenseType.FUEL && expense.liters && (
                          <span className="text-[9px] font-black text-slate-500 uppercase bg-slate-50 px-1.5 rounded-md border border-slate-100">
                            {expense.liters.toLocaleString('pt-BR')}L
                          </span>
                        )}
                      </div>
                    </div>

                    <div className="text-right shrink-0">
                      <div className={`text-base md:text-lg font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-700' : 'text-black'}`}>
                        {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </div>
                      <div className="flex items-center justify-end gap-2 mt-1">
                         <span className="text-[9px] font-black uppercase text-slate-500">{expense.odometer.toLocaleString()} KM</span>
                         <button onClick={() => handleDeleteExpense(expense.id)} className="text-slate-300 hover:text-red-500 transition-colors p-1"><Trash2 size={16} /></button>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </main>
      </div>

      {isFormOpen && (
        <ExpenseForm lastOdometer={lastOdometer} locations={locations} onAdd={handleAddExpense} onClose={() => setIsFormOpen(false)} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { ExpenseType, Expense, Location, FuelType, MaintenanceItem, PaymentMethod } from '../types';
import { Plus, X, Trash2, CreditCard, Wallet, Zap, FileText, Save } from 'lucide-react';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'> | Expense) => void;
  onClose: () => void;
  lastOdometer: number;
  locations: Location[];
  initialData?: Expense | null;
}

export const ExpenseForm: React.FC<ExpenseFormProps> = ({ onAdd, onClose, lastOdometer, locations, initialData }) => {
  const [type, setType] = useState<ExpenseType>(initialData?.type || ExpenseType.FUEL);
  const [date, setDate] = useState(initialData?.date || new Date().toISOString().split('T')[0]);
  const [locationId, setLocationId] = useState<string>(initialData?.locationId || '');
  const [notes, setNotes] = useState(initialData?.notes || '');
  const [status, setStatus] = useState<'RECEIVED' | 'PENDING'>(initialData?.status || 'RECEIVED');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>(initialData?.paymentMethod || 'PIX');
  const [odometer, setOdometer] = useState<string>(initialData?.odometer.toString() || lastOdometer.toString());
  const [fuelType, setFuelType] = useState<FuelType>(initialData?.fuelType || 'Gasolina');
  const [fuelValue, setFuelValue] = useState<string>(initialData?.type === ExpenseType.FUEL ? initialData.value.toString() : '');
  const [liters, setLiters] = useState<string>(initialData?.liters?.toString() || '');
  const [maintItems, setMaintItems] = useState<MaintenanceItem[]>(
    initialData?.maintenanceItems || [{ id: crypto.randomUUID(), description: '', value: 0 }]
  );
  const [odometerStart, setOdometerStart] = useState<string>(initialData?.odometerStart?.toString() || lastOdometer.toString());
  const [ratePerKm, setRatePerKm] = useState<string>(initialData?.ratePerKm?.toString() || '0.00');

  const totalValue = useMemo(() => {
    if (type === ExpenseType.FUEL) return parseFloat(fuelValue) || 0;
    if (type === ExpenseType.MAINTENANCE) return maintItems.reduce((acc, item) => acc + (item.value || 0), 0);
    if (type === ExpenseType.SERVICE_REVENUE) {
      const dist = (parseFloat(odometer) || 0) - (parseFloat(odometerStart) || 0);
      return Math.max(0, dist * (parseFloat(ratePerKm) || 0));
    }
    return 0;
  }, [type, fuelValue, maintItems, odometer, odometerStart, ratePerKm]);

  const addMaintItem = () => {
    setMaintItems([...maintItems, { id: crypto.randomUUID(), description: '', value: 0 }]);
  };

  const updateMaintItem = (id: string, field: 'description' | 'value', val: any) => {
    setMaintItems(maintItems.map(item => 
      item.id === id ? { ...item, [field]: field === 'value' ? parseFloat(val) || 0 : val } : item
    ));
  };

  const removeMaintItem = (id: string) => {
    if (maintItems.length > 1) {
      setMaintItems(maintItems.filter(item => item.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!locationId) {
      alert("Por favor, selecione um local ou empresa.");
      return;
    }

    const basePayload = {
      type, 
      date, 
      odometer: parseFloat(odometer) || 0, 
      value: totalValue, 
      locationId, 
      notes: notes.trim(), 
      paymentMethod,
      description: type === ExpenseType.FUEL ? fuelType : (type === ExpenseType.SERVICE_REVENUE ? 'Km Rodado' : 'Manutenção'),
    };

    let payload: any = { ...basePayload };
    if (initialData?.id) payload.id = initialData.id;

    if (type === ExpenseType.FUEL) { 
      payload.fuelType = fuelType; 
      payload.liters = parseFloat(liters) || 0; 
    }
    else if (type === ExpenseType.MAINTENANCE) {
      payload.maintenanceItems = maintItems.filter(i => i.description.trim() !== '');
    }
    else if (type === ExpenseType.SERVICE_REVENUE) { 
      payload.odometerStart = parseFloat(odometerStart) || 0; 
      payload.ratePerKm = parseFloat(ratePerKm) || 0; 
      payload.status = status; 
    }

    onAdd(payload);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-end md:items-center justify-center p-0 md:p-4 overflow-hidden">
      <div className="bg-white rounded-t-[28px] md:rounded-[28px] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[92vh]">
        <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-white shrink-0">
          <div className="flex items-center gap-3">
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${initialData ? 'bg-amber-100 text-amber-700' : 'bg-blue-100 text-blue-700'}`}>
              {initialData ? <Save size={20} /> : <Plus size={20} />}
            </div>
            <div>
              <h3 className="text-xl font-black text-black uppercase tracking-tight">
                {initialData ? 'Editar Registro' : 'Novo Registro'}
              </h3>
              <p className="text-[10px] font-bold text-slate-500 uppercase">
                {initialData ? `ID: ${initialData.id.slice(0, 8)}` : 'Preencha os dados abaixo'}
              </p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-black transition-colors">
            <X size={28} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 overflow-y-auto pb-6 scrollbar-hide">
          {/* Tipo de Lançamento (Desativado se estiver editando para manter integridade) */}
          <div className={`flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200 ${initialData ? 'opacity-60 pointer-events-none' : ''}`}>
            {(['FUEL', 'MAINTENANCE', 'SERVICE_REVENUE'] as ExpenseType[]).map((t) => (
              <button 
                key={t} 
                type="button" 
                onClick={() => setType(t)} 
                className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase tracking-tight transition-all ${
                  type === t ? 'bg-white text-black shadow-md border border-slate-200' : 'text-slate-500 hover:text-black'
                }`}
              >
                {t === 'FUEL' ? 'Abastecer' : t === 'MAINTENANCE' ? 'Oficina' : 'Serviço'}
              </button>
            ))}
          </div>

          {/* Data e KM */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Data</label>
              <input 
                type="date" 
                value={date} 
                onChange={e => setDate(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all" 
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">KM Final</label>
              <input 
                type="number" 
                inputMode="numeric" 
                value={odometer} 
                onChange={e => setOdometer(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all" 
              />
            </div>
          </div>

          {/* Local */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Local / Empresa</label>
            <div className="relative">
              <select 
                value={locationId} 
                onChange={e => setLocationId(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all appearance-none"
              >
                <option value="">Selecione...</option>
                {locations.filter(l => (type === 'FUEL' && l.type === 'POSTO') || (type === 'MAINTENANCE' && l.type === 'OFICINA') || (type === 'SERVICE_REVENUE' && l.type === 'CLIENTE')).map(loc => (
                  <option key={loc.id} value={loc.id} className="font-bold text-black">{loc.name}</option>
                ))}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-black">
                <Plus size={20} />
              </div>
            </div>
          </div>

          {/* Pagamento */}
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Pagamento</label>
            <div className="grid grid-cols-2 xs:grid-cols-3 sm:grid-cols-5 gap-2">
              {(['PIX', 'CREDITO', 'DEBITO', 'DINHEIRO', 'NOTA_PRAZO'] as PaymentMethod[]).map(pm => (
                <button 
                  key={pm} 
                  type="button" 
                  onClick={() => setPaymentMethod(pm)} 
                  className={`py-4 rounded-2xl flex flex-col items-center justify-center gap-1 border-2 transition-all ${
                    paymentMethod === pm ? 'bg-black border-black text-white shadow-lg scale-105' : 'bg-white border-slate-300 text-black hover:border-slate-400'
                  }`}
                >
                  {pm === 'PIX' ? <Zap size={18} /> : pm === 'DINHEIRO' ? <Wallet size={18} /> : pm === 'NOTA_PRAZO' ? <FileText size={18} /> : <CreditCard size={18} />}
                  <span className="text-[9px] font-black uppercase tracking-tight">
                    {pm === 'NOTA_PRAZO' ? 'A Prazo' : pm}
                  </span>
                </button>
              ))}
            </div>
          </div>

          {/* Abastecimento */}
          {type === 'FUEL' && (
            <div className="grid grid-cols-2 gap-4 p-5 bg-blue-50/50 rounded-[28px] border-2 border-blue-100">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-black ml-1">Valor (R$)</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={fuelValue} 
                  onChange={e => setFuelValue(e.target.value)} 
                  placeholder="0,00"
                  className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-black ml-1">Litros</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={liters} 
                  onChange={e => setLiters(e.target.value)} 
                  placeholder="0.00"
                  className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
            </div>
          )}

          {/* Oficina */}
          {type === 'MAINTENANCE' && (
            <div className="space-y-4 p-5 bg-orange-50/50 rounded-[28px] border-2 border-orange-100">
              <div className="flex justify-between items-center mb-2">
                <label className="text-[10px] font-black uppercase text-black ml-1">Itens da Manutenção</label>
                <button 
                  type="button" 
                  onClick={addMaintItem}
                  className="text-[9px] font-black uppercase bg-black text-white px-3 py-1.5 rounded-lg flex items-center gap-1 shadow-md active:scale-95"
                >
                  <Plus size={12} /> Add Item
                </button>
              </div>

              <div className="space-y-3">
                {maintItems.map((item) => (
                  <div key={item.id} className="flex gap-2 items-start">
                    <div className="flex-1">
                      <input 
                        type="text" 
                        placeholder="Peça ou Serviço" 
                        value={item.description}
                        onChange={(e) => updateMaintItem(item.id, 'description', e.target.value)}
                        className="w-full p-3 bg-white border-2 border-slate-300 rounded-xl text-xs font-black text-black focus:border-orange-600 outline-none transition-all"
                      />
                    </div>
                    <div className="w-24">
                      <input 
                        type="number" 
                        inputMode="decimal"
                        step="0.01"
                        placeholder="Valor"
                        value={item.value || ''}
                        onChange={(e) => updateMaintItem(item.id, 'value', e.target.value)}
                        className="w-full p-3 bg-white border-2 border-slate-300 rounded-xl text-xs font-black text-black focus:border-orange-600 outline-none transition-all"
                      />
                    </div>
                    {maintItems.length > 1 && (
                      <button 
                        type="button" 
                        onClick={() => removeMaintItem(item.id)}
                        className="p-3 text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                      >
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Serviço */}
          {type === 'SERVICE_REVENUE' && (
            <div className="space-y-4 p-5 bg-emerald-50/50 rounded-[28px] border-2 border-emerald-100">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black uppercase text-black ml-1">KM Inicial</label>
                  <input 
                    type="number" 
                    inputMode="numeric" 
                    value={odometerStart} 
                    onChange={e => setOdometerStart(e.target.value)} 
                    className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-emerald-600 outline-none transition-all" 
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black uppercase text-black ml-1">Taxa/KM (R$)</label>
                  <input 
                    type="number" 
                    inputMode="decimal" 
                    step="0.01" 
                    value={ratePerKm} 
                    onChange={e => setRatePerKm(e.target.value)} 
                    className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-emerald-600 outline-none transition-all" 
                  />
                </div>
              </div>
              <div className="flex gap-2">
                <button 
                  type="button" 
                  onClick={() => setStatus('RECEIVED')} 
                  className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase border-2 transition-all ${
                    status === 'RECEIVED' ? 'bg-emerald-600 border-emerald-600 text-white shadow-lg' : 'bg-white border-slate-300 text-black'
                  }`}
                >
                  Recebido
                </button>
                <button 
                  type="button" 
                  onClick={() => setStatus('PENDING')} 
                  className={`flex-1 py-4 rounded-2xl text-[10px] font-black uppercase border-2 transition-all ${
                    status === 'PENDING' ? 'bg-amber-500 border-amber-500 text-white shadow-lg' : 'bg-white border-slate-300 text-black'
                  }`}
                >
                  Pendente
                </button>
              </div>
            </div>
          )}

          {/* Notas */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Observações</label>
            <textarea 
              value={notes} 
              onChange={e => setNotes(e.target.value)} 
              rows={2} 
              placeholder="Notas adicionais..."
              className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all resize-none placeholder:text-slate-300" 
            />
          </div>

          {/* Resumo e Botão Final */}
          <div className="pt-6 border-t border-slate-200 flex items-center justify-between bg-white pb-8">
            <div className="flex flex-col">
              <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest">Valor Total</span>
              <span className="text-3xl font-black text-black">R$ {totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
            </div>
            <button 
              type="submit" 
              className={`px-10 py-5 font-black rounded-2xl shadow-xl active:scale-95 uppercase tracking-widest text-[13px] transition-all flex items-center gap-2 ${
                initialData ? 'bg-amber-600 hover:bg-amber-700 text-white' : 'bg-black hover:bg-slate-900 text-white'
              }`}
            >
              {initialData ? <><Save size={18} /> Atualizar</> : 'Salvar'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location, PaymentMethod } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { Settings } from './components/Settings';
import { Reports } from './components/Reports';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Pencil, Fuel, Wrench, Gauge, MapPin, Navigation, FileText, Printer, Zap, CreditCard, Wallet, Settings as SettingsIcon } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'settings' | 'reports'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleSaveExpense = (data: Omit<Expense, 'id'> | Expense) => {
    if ('id' in data) {
      // Edição
      setExpenses(prev => 
        prev.map(e => e.id === data.id ? (data as Expense) : e)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
      );
    } else {
      // Novo
      const expense: Expense = {
        ...data,
        id: crypto.randomUUID(),
      };
      setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
    }
    setIsFormOpen(false);
    setEditingExpense(null);
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const handleEditExpense = (expense: Expense) => {
    setEditingExpense(expense);
    setIsFormOpen(true);
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  const getPaymentMethodLabel = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return { label: 'PIX', icon: <Zap size={10} /> };
      case 'CREDITO': return { label: 'Crédito', icon: <CreditCard size={10} /> };
      case 'DEBITO': return { label: 'Débito', icon: <CreditCard size={10} /> };
      case 'DINHEIRO': return { label: 'Dinheiro', icon: <Wallet size={10} /> };
      case 'NOTA_PRAZO': return { label: 'Nota a Prazo', icon: <FileText size={10} /> };
      default: return { label: '-', icon: null };
    }
  };

  const NavItem = ({ id, icon: Icon, label }: { id: any, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center gap-1 flex-1 py-1 transition-all rounded-xl ${
        activeTab === id ? 'text-blue-600 bg-blue-50/50' : 'text-slate-500 hover:text-slate-700'
      }`}
    >
      <Icon size={20} className={activeTab === id ? 'scale-110' : ''} />
      <span className="text-[9px] font-black uppercase tracking-tighter">{label}</span>
    </button>
  );

  return (
    <div className="flex min-h-screen bg-[#F8FAFC] w-full overflow-x-hidden">
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-200 flex items-center justify-between z-[90] no-print safe-pb shadow-[0_-8px_30px_rgb(0,0,0,0.08)] h-16 px-4 max-w-lg mx-auto md:rounded-t-[32px]">
        <NavItem id="dashboard" icon={LayoutDashboard} label="Início" />
        <NavItem id="history" icon={History} label="Histórico" />

        <div className="relative -top-6">
          <button 
            onClick={() => {
              setEditingExpense(null);
              setIsFormOpen(true);
            }}
            className="w-14 h-14 bg-blue-600 text-white rounded-2xl shadow-xl flex items-center justify-center active:scale-90 hover:bg-blue-700 transition-all border-4 border-[#F8FAFC]"
          >
            <Plus size={28} strokeWidth={3} />
          </button>
        </div>

        <NavItem id="reports" icon={FileText} label="Relatórios" />
        <NavItem id="settings" icon={SettingsIcon} label="Ajustes" />
      </nav>

      <div className="flex-1 transition-all duration-300 pb-24 w-full overflow-x-hidden">
        <header className="bg-white/90 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40 no-print">
          <div className="max-w-4xl mx-auto px-4 py-4 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-md">
                <Gauge size={18} />
              </div>
              <h2 className="text-sm md:text-base font-black text-black uppercase tracking-tight truncate">
                {activeTab === 'dashboard' && 'Visão Geral'}
                {activeTab === 'history' && 'Histórico'}
                {activeTab === 'reports' && 'Relatórios'}
                {activeTab === 'settings' && 'Configurações'}
              </h2>
            </div>

            <div className="flex items-center gap-2 shrink-0">
              <span className="text-[9px] md:text-xs font-black text-black uppercase tracking-widest bg-slate-100 px-2.5 py-1.5 rounded-xl border border-slate-300">
                KM: {lastOdometer.toLocaleString()}
              </span>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 md:px-6 py-6 w-full">
          {activeTab === 'dashboard' && (
            <div className="no-print animate-in fade-in duration-500 w-full overflow-x-hidden">
              {expenses.length >= 2 && (
                <div className="mb-6 bg-gradient-to-br from-blue-700 to-indigo-800 rounded-[28px] p-6 text-white shadow-xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                  <div className="relative z-10">
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center space-x-2">
                        <Sparkles size={16} className="text-yellow-300" />
                        <h2 className="font-black text-xs md:text-sm uppercase tracking-tight">Sugestões de Economia</h2>
                      </div>
                      <button 
                        onClick={fetchAIInsights}
                        disabled={loadingInsights}
                        className="text-[9px] font-black uppercase tracking-widest bg-white/20 px-3 py-1.5 rounded-lg border border-white/10"
                      >
                        {loadingInsights ? "..." : "Atualizar"}
                      </button>
                    </div>
                    {insights.length > 0 ? (
                      <div className="space-y-2">
                        {insights.slice(0, 2).map((tip, idx) => (
                          <div key={idx} className="bg-white/10 backdrop-blur-md p-3 rounded-xl text-[10px] md:text-[11px] font-bold border border-white/5 shadow-sm">
                            {tip}
                          </div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-white/70 text-[10px] font-bold">Gerencie suas despesas e peça dicas à IA.</p>
                    )}
                  </div>
                </div>
              )}
              <Dashboard expenses={expenses} />
            </div>
          )}

          {activeTab === 'settings' && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Settings locations={locations} onAddLocation={handleAddLocation} onRemoveLocation={handleRemoveLocation} />
            </div>
          )}

          {activeTab === 'reports' && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Reports expenses={expenses} locations={locations} />
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-4 animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <div className="flex justify-between items-center mb-4 no-print px-1">
                <h3 className="text-xl font-black text-black tracking-tight">Atividades</h3>
                <button onClick={() => window.print()} className="p-2.5 bg-white border border-slate-300 rounded-xl text-black hover:bg-slate-50 transition-all shadow-sm"><Printer size={18} /></button>
              </div>

              {expenses.length === 0 ? (
                <div className="bg-white p-12 text-center text-slate-400 rounded-[32px] border-2 border-dashed border-slate-200">
                  <History size={40} className="mx-auto mb-4 opacity-20" />
                  <p className="text-sm font-bold">Nenhum lançamento encontrado.</p>
                </div>
              ) : (
                expenses.map(expense => (
                  <div key={expense.id} className="bg-white rounded-[24px] p-4 md:p-5 shadow-md border border-slate-200 flex items-center gap-4 group active:scale-[0.98] transition-all w-full hover:shadow-lg">
                    <div className={`p-3 rounded-2xl shrink-0 ${
                      expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-700' : 
                      expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-700' :
                      'bg-emerald-50 text-emerald-700'
                    }`}>
                      {expense.type === ExpenseType.FUEL ? <Fuel size={20} /> : 
                       expense.type === ExpenseType.MAINTENANCE ? <Wrench size={20} /> : 
                       <Navigation size={20} />}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] md:text-[10px] font-black uppercase text-slate-600">{new Date(expense.date).toLocaleDateString()}</span>
                        {expense.type === ExpenseType.SERVICE_REVENUE && (
                          <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded-md ${
                            expense.status === 'RECEIVED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                          }`}>
                            {expense.status === 'RECEIVED' ? 'OK' : 'PENDENTE'}
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-2 mb-0.5">
                        <h4 className="font-black text-black text-sm md:text-base tracking-tight truncate">
                          {expense.type === ExpenseType.FUEL ? expense.fuelType : 
                          expense.type === ExpenseType.SERVICE_REVENUE ? 'Serviço Realizado' : 'Manutenção'}
                        </h4>
                        {expense.type === ExpenseType.FUEL && expense.liters && expense.liters > 0 && (
                          <span className="text-[9px] font-black text-slate-600 bg-slate-100 px-1.5 py-0.5 rounded-md whitespace-nowrap border border-slate-200">
                            R$ {(expense.value / expense.liters).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })} /L
                          </span>
                        )}
                      </div>
                      <div className="flex flex-wrap gap-2 mt-0.5">
                        <p className="text-[10px] md:text-[11px] font-bold text-slate-700 truncate flex items-center gap-1">
                          <MapPin size={8} /> {getLocationName(expense.locationId)}
                        </p>
                        <span className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-1 bg-blue-50 px-1.5 rounded-md">
                          {getPaymentMethodLabel(expense.paymentMethod).icon}
                          {getPaymentMethodLabel(expense.paymentMethod).label}
                        </span>
                        {expense.type === ExpenseType.FUEL && expense.liters && (
                          <span className="text-[9px] font-black text-slate-500 uppercase bg-slate-50 px-1.5 rounded-md border border-slate-100">
                            {expense.liters.toLocaleString('pt-BR')}L
                          </span>
                        )}
                      </div>
                    </div>

                    <div className="text-right shrink-0">
                      <div className={`text-base md:text-lg font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-700' : 'text-black'}`}>
                        {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </div>
                      <div className="flex items-center justify-end gap-1.5 mt-1">
                         <span className="text-[9px] font-black uppercase text-slate-500 mr-1">{expense.odometer.toLocaleString()} KM</span>
                         <button onClick={() => handleEditExpense(expense)} className="text-slate-400 hover:text-amber-600 transition-colors p-1.5 bg-slate-50 rounded-lg"><Pencil size={14} /></button>
                         <button onClick={() => handleDeleteExpense(expense.id)} className="text-slate-400 hover:text-red-500 transition-colors p-1.5 bg-slate-50 rounded-lg"><Trash2 size={14} /></button>
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </main>
      </div>

      {isFormOpen && (
        <ExpenseForm 
          lastOdometer={lastOdometer} 
          locations={locations} 
          onAdd={handleSaveExpense} 
          onClose={() => {
            setIsFormOpen(false);
            setEditingExpense(null);
          }}
          initialData={editingExpense}
        />
      )}
    </div>
  );
};

export default App;

export enum ExpenseType {
  FUEL = 'FUEL',
  MAINTENANCE = 'MAINTENANCE',
  SERVICE_REVENUE = 'SERVICE_REVENUE',
  OTHER = 'OTHER'
}

export type FuelType = 'Gasolina' | 'Etanol' | 'Diesel' | 'GNV';

export type PaymentMethod = 'DINHEIRO' | 'CREDITO' | 'DEBITO' | 'PIX' | 'NOTA_PRAZO';

export enum UserRole {
  ADMIN = 'ADMIN',
  STANDARD = 'STANDARD',
  SIMPLE = 'SIMPLE'
}

export interface User {
  id: string;
  name: string;
  username: string;
  role: UserRole;
  password?: string;
}

export interface MaintenanceItem {
  id: string;
  description: string;
  value: number;
}

export interface Location {
  id: string;
  name: string;
  type: 'POSTO' | 'OFICINA' | 'CLIENTE';
}

export interface Expense {
  id: string;
  date: string;
  type: ExpenseType;
  odometer: number;
  odometerStart?: number;
  value: number;
  locationId?: string;
  fuelType?: FuelType;
  liters?: number;
  description: string;
  notes?: string;
  maintenanceItems?: MaintenanceItem[];
  ratePerKm?: number;
  status?: 'RECEIVED' | 'PENDING';
  paymentMethod?: PaymentMethod;
  userId?: string; // Quem lançou
}

export interface CarStats {
  totalSpent: number;
  totalLiters: number;
  averageConsumption: number;
  totalDistance: number;
  lastOdometer: number;
  totalServiceRevenue: number;
  pendingServiceRevenue: number;
}

import React, { useState } from 'react';
import { User, UserRole } from '../types';
import { Gauge, Lock, User as UserIcon, ArrowRight } from 'lucide-react';

interface LoginProps {
  onLogin: (user: User) => void;
  availableUsers: User[];
}

export const Login: React.FC<LoginProps> = ({ onLogin, availableUsers }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = availableUsers.find(u => u.username === username && u.password === password);
    if (user) {
      onLogin(user);
    } else {
      setError('Usuário ou senha inválidos.');
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-50 flex items-center justify-center p-4 z-[200]">
      <div className="w-full max-w-md">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-black rounded-3xl flex items-center justify-center text-white shadow-2xl mx-auto mb-6">
            <Gauge size={40} />
          </div>
          <h1 className="text-3xl font-black text-black tracking-tight uppercase">AutoGasto</h1>
          <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mt-2">Gestão de Frotas e Despesas</p>
        </div>

        <div className="bg-white p-8 rounded-[40px] shadow-xl border border-slate-100">
          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-black uppercase ml-1 tracking-widest">Usuário</label>
              <div className="relative">
                <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input
                  type="text"
                  value={username}
                  onChange={e => setUsername(e.target.value)}
                  placeholder="Seu usuário"
                  className="w-full p-4 pl-12 bg-slate-50 border-2 border-slate-200 rounded-2xl focus:border-black outline-none transition-all font-bold text-black"
                  required
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-black uppercase ml-1 tracking-widest">Senha</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input
                  type="password"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  placeholder="••••••••"
                  className="w-full p-4 pl-12 bg-slate-50 border-2 border-slate-200 rounded-2xl focus:border-black outline-none transition-all font-bold text-black"
                  required
                />
              </div>
            </div>

            {error && <p className="text-[10px] font-bold text-red-600 uppercase text-center">{error}</p>}

            <button
              type="submit"
              className="w-full bg-black text-white py-5 rounded-2xl font-black uppercase text-[13px] tracking-widest shadow-xl hover:bg-slate-900 active:scale-[0.98] transition-all flex items-center justify-center gap-2"
            >
              Acessar Sistema <ArrowRight size={18} />
            </button>
          </form>
        </div>

        <div className="mt-8 text-center">
          <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">Acesso restrito para pessoal autorizado</p>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Location, User, UserRole } from '../types';
import { Plus, Trash2, Fuel, Wrench, Building2, Sliders, Users, ShieldCheck, UserCheck, User as UserIcon } from 'lucide-react';

interface SettingsProps {
  locations: Location[];
  onAddLocation: (location: Omit<Location, 'id'>) => void;
  onRemoveLocation: (id: string) => void;
  users: User[];
  onAddUser: (user: Omit<User, 'id'>) => void;
  onRemoveUser: (id: string) => void;
  currentUserRole: UserRole;
}

export const Settings: React.FC<SettingsProps> = ({ 
  locations, onAddLocation, onRemoveLocation, 
  users, onAddUser, onRemoveUser, 
  currentUserRole 
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'LOCATIONS' | 'USERS'>('LOCATIONS');

  const [name, setName] = useState('');
  const [locType, setLocType] = useState<'POSTO' | 'OFICINA' | 'CLIENTE'>('POSTO');

  const [userName, setUserName] = useState('');
  const [userUsername, setUserUsername] = useState('');
  const [userPass, setUserPass] = useState('');
  const [userRole, setUserRole] = useState<UserRole>(UserRole.STANDARD);

  const [isAdding, setIsAdding] = useState(false);

  const handleSubmitLocation = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;
    onAddLocation({ name, type: locType });
    setName('');
    setIsAdding(false);
  };

  const handleSubmitUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userName.trim() || !userUsername.trim()) return;
    onAddUser({ name: userName, username: userUsername, password: userPass, role: userRole });
    setUserName('');
    setUserUsername('');
    setUserPass('');
    setIsAdding(false);
  };

  const groupedLocations = {
    POSTO: locations.filter(l => l.type === 'POSTO'),
    OFICINA: locations.filter(l => l.type === 'OFICINA'),
    CLIENTE: locations.filter(l => l.type === 'CLIENTE'),
  };

  const SectionHeader = ({ title, icon: Icon, colorClass, count }: { title: string, icon: any, colorClass: string, count: number }) => (
    <div className="flex items-center justify-between mb-4 mt-6 first:mt-0">
      <div className="flex items-center gap-2">
        <div className={`p-2 rounded-xl ${colorClass}`}>
          <Icon size={18} />
        </div>
        <h3 className="text-sm font-black text-black uppercase tracking-widest">{title}</h3>
      </div>
      <span className="text-[10px] font-black text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">
        {count}
      </span>
    </div>
  );

  return (
    <div className="space-y-6 pb-12">
      {/* Sub-navegação de Configurações */}
      <div className="flex bg-white p-1.5 rounded-2xl border border-slate-200 mb-6">
        <button 
          onClick={() => { setActiveSubTab('LOCATIONS'); setIsAdding(false); }}
          className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-tight transition-all flex items-center justify-center gap-2 ${
            activeSubTab === 'LOCATIONS' ? 'bg-black text-white shadow-md' : 'text-slate-500 hover:text-black'
          }`}
        >
          <Building2 size={16} /> Locais
        </button>
        {currentUserRole === UserRole.ADMIN && (
          <button 
            onClick={() => { setActiveSubTab('USERS'); setIsAdding(false); }}
            className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-tight transition-all flex items-center justify-center gap-2 ${
              activeSubTab === 'USERS' ? 'bg-black text-white shadow-md' : 'text-slate-500 hover:text-black'
            }`}
          >
            <Users size={16} /> Usuários
          </button>
        )}
      </div>

      {activeSubTab === 'LOCATIONS' && (
        <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-200">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h2 className="text-xl font-black text-black tracking-tight">Locais e Empresas</h2>
              <p className="text-[10px] font-bold text-slate-500 uppercase">Postos, Oficinas e Clientes</p>
            </div>
            <button 
              onClick={() => setIsAdding(!isAdding)}
              className={`p-3 rounded-2xl transition-all shadow-md active:scale-95 ${
                isAdding ? 'bg-red-50 text-red-600' : 'bg-black text-white'
              }`}
            >
              {isAdding ? <Plus className="rotate-45" size={20} /> : <Plus size={20} />}
            </button>
          </div>

          {isAdding && (
            <form onSubmit={handleSubmitLocation} className="space-y-4 animate-in fade-in zoom-in duration-200 mb-6 bg-slate-50 p-5 rounded-2xl border border-slate-200">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-black uppercase ml-1">Nome</label>
                  <input
                    type="text"
                    placeholder="Ex: Posto Ipiranga"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl focus:border-black outline-none transition-all text-sm font-bold text-black"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-black uppercase ml-1">Categoria</label>
                  <select
                    value={locType}
                    onChange={(e) => setLocType(e.target.value as any)}
                    className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl outline-none text-sm font-bold text-black appearance-none"
                  >
                    <option value="POSTO">Posto</option>
                    <option value="OFICINA">Oficina</option>
                    <option value="CLIENTE">Cliente</option>
                  </select>
                </div>
              </div>
              <button type="submit" className="w-full bg-black text-white py-4 rounded-xl font-black uppercase text-[11px] tracking-widest shadow-xl">Salvar Local</button>
            </form>
