                <span className="text-sm font-bold text-black">{l.name}</span>
                <button onClick={() => onRemoveLocation(l.id)} className="text-slate-300 hover:text-red-500"><Trash2 size={16} /></button>
              </div>
            ))}

            <SectionHeader title="Oficinas" icon={Wrench} colorClass="bg-orange-50 text-orange-600" count={groupedLocations.OFICINA.length} />
            {groupedLocations.OFICINA.map(l => (
              <div key={l.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <span className="text-sm font-bold text-black">{l.name}</span>
                <button onClick={() => onRemoveLocation(l.id)} className="text-slate-300 hover:text-red-500"><Trash2 size={16} /></button>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'USERS' && currentUserRole === UserRole.ADMIN && (
        <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-200">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h2 className="text-xl font-black text-black tracking-tight">Gestão de Equipe</h2>
              <p className="text-[10px] font-bold text-slate-500 uppercase">Usuários e Permissões</p>
            </div>
            <button 
              onClick={() => setIsAdding(!isAdding)}
              className={`p-3 rounded-2xl transition-all shadow-md active:scale-95 ${
                isAdding ? 'bg-red-50 text-red-600' : 'bg-black text-white'
              }`}
            >
              {isAdding ? <Plus className="rotate-45" size={20} /> : <Plus size={20} />}
            </button>
          </div>

          {isAdding && (
            <form onSubmit={handleSubmitUser} className="space-y-4 animate-in fade-in zoom-in duration-200 mb-6 bg-slate-50 p-5 rounded-2xl border border-slate-200">
              <div className="grid grid-cols-1 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-black uppercase ml-1">Nome Completo</label>
                  <input type="text" value={userName} onChange={e => setUserName(e.target.value)} className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl focus:border-black outline-none font-bold text-black" placeholder="Ex: João Silva" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-black uppercase ml-1">Login</label>
                    <input type="text" value={userUsername} onChange={e => setUserUsername(e.target.value)} className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl focus:border-black outline-none font-bold text-black" placeholder="joao.silva" />
                  </div>
                   <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-black uppercase ml-1">Senha</label>
                    <input type="password" value={userPass} onChange={e => setUserPass(e.target.value)} className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl focus:border-black outline-none font-bold text-black" placeholder="••••" />
                  </div>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-black uppercase ml-1">Nível de Acesso</label>
                  <select value={userRole} onChange={e => setUserRole(e.target.value as UserRole)} className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl outline-none font-bold text-black">
                    <option value={UserRole.ADMIN}>Administrador</option>
                    <option value={UserRole.STANDARD}>Usuário Padrão</option>
                    <option value={UserRole.SIMPLE}>Usuário Simples</option>
                  </select>
                </div>
              </div>
              <button type="submit" className="w-full bg-black text-white py-4 rounded-xl font-black uppercase text-[11px] tracking-widest shadow-xl">Cadastrar Usuário</button>
            </form>
          )}

          <div className="space-y-3">
            {users.map(u => (
              <div key={u.id} className="flex items-center justify-between p-5 bg-slate-50 rounded-2xl border border-slate-100 shadow-sm">
                <div className="flex items-center gap-4">
                  <div className={`p-3 rounded-xl ${u.role === UserRole.ADMIN ? 'bg-black text-white' : u.role === UserRole.STANDARD ? 'bg-blue-100 text-blue-600' : 'bg-slate-200 text-slate-500'}`}>
                    {u.role === UserRole.ADMIN ? <ShieldCheck size={20} /> : u.role === UserRole.STANDARD ? <UserCheck size={20} /> : <UserIcon size={20} />}
                  </div>
                  <div>
                    <h4 className="text-sm font-black text-black">{u.name}</h4>
                    <div className="flex items-center gap-2">
                      <span className="text-[9px] font-black uppercase text-slate-400">@{u.username}</span>
                      <span className="text-[8px] font-black uppercase bg-slate-200 px-1.5 py-0.5 rounded text-slate-600">{u.role}</span>
                    </div>
                  </div>
                </div>
                {u.username !== 'admin' && (
                   <button onClick={() => onRemoveUser(u.id)} className="text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={18} /></button>
                )}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location, PaymentMethod, User, UserRole } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { Settings } from './components/Settings';
import { Reports } from './components/Reports';
import { Login } from './components/Login';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Pencil, Fuel, Wrench, Gauge, MapPin, Navigation, FileText, Printer, Zap, CreditCard, Wallet, Settings as SettingsIcon, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('autoGasto_loggedUser');
    return saved ? JSON.parse(saved) : null;
  });

  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('autoGasto_users');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Administrador', username: 'admin', role: UserRole.ADMIN, password: '123' }
    ];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'settings' | 'reports'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem('autoGasto_loggedUser', JSON.stringify(currentUser));
  }, [currentUser]);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  const handleSaveExpense = (data: Omit<Expense, 'id'> | Expense) => {
    if ('id' in data) {
      setExpenses(prev => 
        prev.map(e => e.id === data.id ? (data as Expense) : e)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
      );
    } else {
      const expense: Expense = {
        ...data,
        id: crypto.randomUUID(),
        userId: currentUser?.id
      };
      setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
    }
    setIsFormOpen(false);
    setEditingExpense(null);
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleAddUser = (user: Omit<User, 'id'>) => {
    setUsers([...users, { ...user, id: crypto.randomUUID() }]);
  };

  const handleRemoveUser = (id: string) => {
    setUsers(users.filter(u => u.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const handleEditExpense = (expense: Expense) => {
    if (currentUser?.role === UserRole.SIMPLE && expense.userId !== currentUser.id) {
      alert("Acesso negado: você só pode editar seus próprios registros.");
      return;
    }
    setEditingExpense(expense);
    setIsFormOpen(true);
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  const getPaymentMethodLabel = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return { label: 'PIX', icon: <Zap size={10} /> };
      case 'CREDITO': return { label: 'Crédito', icon: <CreditCard size={10} /> };
      case 'DEBITO': return { label: 'Débito', icon: <CreditCard size={10} /> };
      case 'DINHEIRO': return { label: 'Dinheiro', icon: <Wallet size={10} /> };
      case 'NOTA_PRAZO': return { label: 'Nota a Prazo', icon: <FileText size={10} /> };
      default: return { label: '-', icon: null };
    }
  };

  const NavItem = ({ id, icon: Icon, label }: { id: any, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center gap-1 flex-1 py-1 transition-all rounded-xl ${
        activeTab === id ? 'text-blue-600 bg-blue-50/50' : 'text-slate-500 hover:text-slate-700'
      }`}
    >
      <Icon size={20} className={activeTab === id ? 'scale-110' : ''} />
      <span className="text-[9px] font-black uppercase tracking-tighter">{label}</span>
    </button>
  );

  if (!currentUser) {
    return <Login onLogin={handleLogin} availableUsers={users} />;
  }

  return (
    <div className="flex min-h-screen bg-[#F8FAFC] w-full overflow-x-hidden">
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-200 flex items-center justify-between z-[90] no-print safe-pb shadow-[0_-8px_30px_rgb(0,0,0,0.08)] h-16 px-4 max-w-lg mx-auto md:rounded-t-[32px]">
        <NavItem id="dashboard" icon={LayoutDashboard} label="Início" />
        <NavItem id="history" icon={History} label="Histórico" />

        <div className="relative -top-6">
          <button 
            onClick={() => {
              setEditingExpense(null);
              setIsFormOpen(true);
            }}
            className="w-14 h-14 bg-blue-600 text-white rounded-2xl shadow-xl flex items-center justify-center active:scale-90 hover:bg-blue-700 transition-all border-4 border-[#F8FAFC]"
          >
            <Plus size={28} strokeWidth={3} />
          </button>
        </div>

        {currentUser.role !== UserRole.SIMPLE && <NavItem id="reports" icon={FileText} label="Relatórios" />}
        {currentUser.role !== UserRole.SIMPLE && <NavItem id="settings" icon={SettingsIcon} label="Ajustes" />}
      </nav>

      <div className="flex-1 transition-all duration-300 pb-24 w-full overflow-x-hidden">
        <header className="bg-white/90 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40 no-print">
          <div className="max-w-4xl mx-auto px-4 py-4 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-md">
                <Gauge size={18} />
              </div>
              <div className="min-w-0">
                <h2 className="text-xs md:text-sm font-black text-black uppercase tracking-tight truncate leading-none mb-1">
                  {currentUser.name}
                </h2>
                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{currentUser.role}</span>
              </div>
            </div>

            <div className="flex items-center gap-2 shrink-0">
              <span className="text-[9px] font-black text-black uppercase tracking-widest bg-slate-100 px-2.5 py-1.5 rounded-xl border border-slate-300">
                KM: {lastOdometer.toLocaleString()}
              </span>
              <button onClick={handleLogout} className="p-2 bg-slate-100 rounded-xl text-slate-500 hover:text-red-600 border border-slate-300">
                <LogOut size={16} />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 md:px-6 py-6 w-full">
          {activeTab === 'dashboard' && (
            <div className="no-print animate-in fade-in duration-500 w-full overflow-x-hidden">
              {expenses.length >= 2 && currentUser.role === UserRole.ADMIN && (
                <div className="mb-6 bg-gradient-to-br from-blue-700 to-indigo-800 rounded-[28px] p-6 text-white shadow-xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                  <div className="relative z-10">
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center space-x-2">
                        <Sparkles size={16} className="text-yellow-300" />
                        <h2 className="font-black text-xs md:text-sm uppercase tracking-tight">Sugestões de Economia</h2>
                      </div>
                      <button onClick={fetchAIInsights} disabled={loadingInsights} className="text-[9px] font-black uppercase tracking-widest bg-white/20 px-3 py-1.5 rounded-lg border border-white/10">
                        {loadingInsights ? "..." : "Atualizar"}
                      </button>
                    </div>
                    {insights.length > 0 ? (
                      <div className="space-y-2">
                        {insights.slice(0, 2).map((tip, idx) => (
                          <div key={idx} className="bg-white/10 backdrop-blur-md p-3 rounded-xl text-[10px] md:text-[11px] font-bold border border-white/5 shadow-sm">{tip}</div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-white/70 text-[10px] font-bold">Gerencie suas despesas e peça dicas à IA.</p>
                    )}
                  </div>
                </div>
              )}
              <Dashboard expenses={expenses} />
            </div>
          )}

          {activeTab === 'settings' && currentUser.role !== UserRole.SIMPLE && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Settings 
                locations={locations} onAddLocation={handleAddLocation} onRemoveLocation={handleRemoveLocation} 
                users={users} onAddUser={handleAddUser} onRemoveUser={handleRemoveUser}
                currentUserRole={currentUser.role}
              />
            </div>
          )}

          {activeTab === 'reports' && currentUser.role !== UserRole.SIMPLE && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Reports expenses={expenses} locations={locations} />
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-4 animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <div className="flex justify-between items-center mb-4 no-print px-1">
                <h3 className="text-xl font-black text-black tracking-tight">Atividades</h3>
                <button onClick={() => window.print()} className="p-2.5 bg-white border border-slate-300 rounded-xl text-black hover:bg-slate-50 transition-all shadow-sm"><Printer size={18} /></button>
              </div>

              {expenses.length === 0 ? (
                <div className="bg-white p-12 text-center text-slate-400 rounded-[32px] border-2 border-dashed border-slate-200">
                  <History size={40} className="mx-auto mb-4 opacity-20" />
                  <p className="text-sm font-bold">Nenhum lançamento encontrado.</p>
                </div>
              ) : (
                expenses.map(expense => (
                  <div key={expense.id} className="bg-white rounded-[24px] p-4 md:p-5 shadow-md border border-slate-200 flex items-center gap-4 group active:scale-[0.98] transition-all w-full hover:shadow-lg">
                    <div className={`p-3 rounded-2xl shrink-0 ${
                      expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-700' : 
                      expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-700' :
                      'bg-emerald-50 text-emerald-700'
                    }`}>
                      {expense.type === ExpenseType.FUEL ? <Fuel size={20} /> : 
                       expense.type === ExpenseType.MAINTENANCE ? <Wrench size={20} /> : 
                       <Navigation size={20} />}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] md:text-[10px] font-black uppercase text-slate-600">{new Date(expense.date).toLocaleDateString()}</span>
                        {expense.type === ExpenseType.SERVICE_REVENUE && (
                          <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded-md ${
                            expense.status === 'RECEIVED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                          }`}>
                            {expense.status === 'RECEIVED' ? 'OK' : 'PENDENTE'}
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-2 mb-0.5">
                        <h4 className="font-black text-black text-sm md:text-base tracking-tight truncate">
                          {expense.type === ExpenseType.FUEL ? expense.fuelType : 
                          expense.type === ExpenseType.SERVICE_REVENUE ? 'Serviço Realizado' : 'Manutenção'}
                        </h4>
                        {expense.type === ExpenseType.FUEL && expense.liters && expense.liters > 0 && (
                          <span className="text-[9px] font-black text-slate-600 bg-slate-100 px-1.5 py-0.5 rounded-md border border-slate-200">
                            R$ {(expense.value / expense.liters).toLocaleString('pt-BR', { minimumFractionDigits: 2 })} /L
                          </span>
                        )}
                      </div>
                      <div className="flex flex-wrap gap-2 mt-0.5">
                        <p className="text-[10px] md:text-[11px] font-bold text-slate-700 truncate flex items-center gap-1">
                          <MapPin size={8} /> {getLocationName(expense.locationId)}
                        </p>
                        <span className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-1 bg-blue-50 px-1.5 rounded-md">
                          {getPaymentMethodLabel(expense.paymentMethod).icon}
                          {getPaymentMethodLabel(expense.paymentMethod).label}
                        </span>
                      </div>
                    </div>

                    <div className="text-right shrink-0">
                      <div className={`text-base md:text-lg font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-700' : 'text-black'}`}>
                        {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </div>
                      <div className="flex items-center justify-end gap-1.5 mt-1">
                         <span className="text-[9px] font-black uppercase text-slate-500 mr-1">{expense.odometer.toLocaleString()} KM</span>
                         {(currentUser.role !== UserRole.SIMPLE || expense.userId === currentUser.id) && (
                           <>
                            <button onClick={() => handleEditExpense(expense)} className="text-slate-400 hover:text-amber-600 transition-colors p-1.5 bg-slate-50 rounded-lg"><Pencil size={14} /></button>
                            <button onClick={() => handleDeleteExpense(expense.id)} className="text-slate-400 hover:text-red-500 transition-colors p-1.5 bg-slate-50 rounded-lg"><Trash2 size={14} /></button>
                           </>
                         )}
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </main>
      </div>

      {isFormOpen && (
        <ExpenseForm 
          lastOdometer={lastOdometer} 
          locations={locations} 
          onAdd={handleSaveExpense} 
          onClose={() => { setIsFormOpen(false); setEditingExpense(null); }}
          initialData={editingExpense}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location, PaymentMethod, User, UserRole } from './types';
import { Dashboard } from './components/Dashboard';
