import { Plus, LayoutDashboard, History, Sparkles, Trash2, Pencil, Fuel, Wrench, Gauge, MapPin, Navigation, FileText, Printer, Zap, CreditCard, Wallet, Settings as SettingsIcon, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('autoGasto_loggedUser');
    return saved ? JSON.parse(saved) : null;
  });

  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('autoGasto_users');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Administrador', username: 'admin', role: UserRole.ADMIN, password: '123' },
      { id: '2', name: 'Usuário Padrão', username: 'padrao', role: UserRole.STANDARD, password: '123' },
      { id: '3', name: 'Usuário Simples', username: 'simples', role: UserRole.SIMPLE, password: '123' }
    ];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'settings' | 'reports'>('dashboard');
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem('autoGasto_loggedUser', JSON.stringify(currentUser));
  }, [currentUser]);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleLogin = (user: User) => {
    // Se o usuário for novo (criado no Login livre), salva ele na lista global para persistência
    setUsers(prev => {
      if (!prev.find(u => u.username.toLowerCase() === user.username.toLowerCase())) {
        return [...prev, user];
      }
      return prev;
    });
    setCurrentUser(user);
    setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  const handleSaveExpense = (data: Omit<Expense, 'id'> | Expense) => {
    if ('id' in data) {
      setExpenses(prev => 
        prev.map(e => e.id === data.id ? (data as Expense) : e)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
      );
    } else {
      const expense: Expense = {
        ...data,
        id: crypto.randomUUID(),
        userId: currentUser?.id
      };
      setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
    }
    setIsFormOpen(false);
    setEditingExpense(null);
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleAddUser = (user: Omit<User, 'id'>) => {
    setUsers([...users, { ...user, id: crypto.randomUUID() }]);
  };

  const handleRemoveUser = (id: string) => {
    setUsers(users.filter(u => u.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const handleEditExpense = (expense: Expense) => {
    if (currentUser?.role === UserRole.SIMPLE && expense.userId !== currentUser.id) {
      alert("Acesso negado: você só pode editar seus próprios registros.");
      return;
    }
    setEditingExpense(expense);
    setIsFormOpen(true);
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  const getPaymentMethodLabel = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return { label: 'PIX', icon: <Zap size={10} /> };
      case 'CREDITO': return { label: 'Crédito', icon: <CreditCard size={10} /> };
      case 'DEBITO': return { label: 'Débito', icon: <CreditCard size={10} /> };
      case 'DINHEIRO': return { label: 'Dinheiro', icon: <Wallet size={10} /> };
      case 'NOTA_PRAZO': return { label: 'Nota a Prazo', icon: <FileText size={10} /> };
      default: return { label: '-', icon: null };
    }
  };

  const NavItem = ({ id, icon: Icon, label }: { id: any, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center gap-1 flex-1 py-1 transition-all rounded-xl ${
        activeTab === id ? 'text-blue-600 bg-blue-50/50' : 'text-slate-500 hover:text-slate-700'
      }`}
    >
      <Icon size={20} className={activeTab === id ? 'scale-110' : ''} />
      <span className="text-[9px] font-black uppercase tracking-tighter">{label}</span>
    </button>
  );

  if (!currentUser) {
    return <Login onLogin={handleLogin} availableUsers={users} />;
  }

  return (
    <div className="flex min-h-screen bg-[#F8FAFC] w-full overflow-x-hidden">
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-200 flex items-center justify-between z-[90] no-print safe-pb shadow-[0_-8px_30px_rgb(0,0,0,0.08)] h-16 px-4 max-w-lg mx-auto md:rounded-t-[32px]">
        <NavItem id="dashboard" icon={LayoutDashboard} label="Início" />
        <NavItem id="history" icon={History} label="Histórico" />

        <div className="relative -top-6">
          <button 
            onClick={() => {
              setEditingExpense(null);
              setIsFormOpen(true);
            }}
            className="w-14 h-14 bg-blue-600 text-white rounded-2xl shadow-xl flex items-center justify-center active:scale-90 hover:bg-blue-700 transition-all border-4 border-[#F8FAFC]"
          >
            <Plus size={28} strokeWidth={3} />
          </button>
        </div>

        {currentUser.role !== UserRole.SIMPLE && <NavItem id="reports" icon={FileText} label="Relatórios" />}
        {currentUser.role !== UserRole.SIMPLE && <NavItem id="settings" icon={SettingsIcon} label="Ajustes" />}
      </nav>

      <div className="flex-1 transition-all duration-300 pb-24 w-full overflow-x-hidden">
        <header className="bg-white/90 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40 no-print">
          <div className="max-w-4xl mx-auto px-4 py-4 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-md">
                <Gauge size={18} />
              </div>
              <div className="min-w-0">
                <h2 className="text-xs md:text-sm font-black text-black uppercase tracking-tight truncate leading-none mb-1">
                  {currentUser.name}
                </h2>
                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">{currentUser.role}</span>
              </div>
            </div>

            <div className="flex items-center gap-2 shrink-0">
              <span className="text-[9px] font-black text-black uppercase tracking-widest bg-slate-100 px-2.5 py-1.5 rounded-xl border border-slate-300">
                KM: {lastOdometer.toLocaleString()}
              </span>
              <button onClick={handleLogout} className="p-2 bg-slate-100 rounded-xl text-slate-500 hover:text-red-600 border border-slate-300">
                <LogOut size={16} />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 md:px-6 py-6 w-full">
          {activeTab === 'dashboard' && (
            <div className="no-print animate-in fade-in duration-500 w-full overflow-x-hidden">
              {expenses.length >= 2 && currentUser.role === UserRole.ADMIN && (
                <div className="mb-6 bg-gradient-to-br from-blue-700 to-indigo-800 rounded-[28px] p-6 text-white shadow-xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                  <div className="relative z-10">
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center space-x-2">
                        <Sparkles size={16} className="text-yellow-300" />
                        <h2 className="font-black text-xs md:text-sm uppercase tracking-tight">Sugestões de Economia</h2>
                      </div>
                      <button onClick={fetchAIInsights} disabled={loadingInsights} className="text-[9px] font-black uppercase tracking-widest bg-white/20 px-3 py-1.5 rounded-lg border border-white/10">
                        {loadingInsights ? "..." : "Atualizar"}
                      </button>
                    </div>
                    {insights.length > 0 ? (
                      <div className="space-y-2">
                        {insights.slice(0, 2).map((tip, idx) => (
                          <div key={idx} className="bg-white/10 backdrop-blur-md p-3 rounded-xl text-[10px] md:text-[11px] font-bold border border-white/5 shadow-sm">{tip}</div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-white/70 text-[10px] font-bold">Gerencie suas despesas e peça dicas à IA.</p>
                    )}
                  </div>
                </div>
              )}
              <Dashboard expenses={expenses} />
            </div>
          )}

          {activeTab === 'settings' && currentUser.role !== UserRole.SIMPLE && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Settings 
                locations={locations} onAddLocation={handleAddLocation} onRemoveLocation={handleRemoveLocation} 
                users={users} onAddUser={handleAddUser} onRemoveUser={handleRemoveUser}
                currentUserRole={currentUser.role}
              />
            </div>
          )}

          {activeTab === 'reports' && currentUser.role !== UserRole.SIMPLE && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Reports expenses={expenses} locations={locations} />
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-4 animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <div className="flex justify-between items-center mb-4 no-print px-1">
                <h3 className="text-xl font-black text-black tracking-tight">Atividades</h3>
                <button onClick={() => window.print()} className="p-2.5 bg-white border border-slate-300 rounded-xl text-black hover:bg-slate-50 transition-all shadow-sm"><Printer size={18} /></button>
              </div>

              {expenses.length === 0 ? (
                <div className="bg-white p-12 text-center text-slate-400 rounded-[32px] border-2 border-dashed border-slate-200">
                  <History size={40} className="mx-auto mb-4 opacity-20" />
                  <p className="text-sm font-bold">Nenhum lançamento encontrado.</p>
                </div>
              ) : (
                expenses.map(expense => (
                  <div key={expense.id} className="bg-white rounded-[24px] p-4 md:p-5 shadow-md border border-slate-200 flex items-center gap-4 group active:scale-[0.98] transition-all w-full hover:shadow-lg">
                    <div className={`p-3 rounded-2xl shrink-0 ${
                      expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-700' : 
                      expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-700' :
                      'bg-emerald-50 text-emerald-700'
                    }`}>
                      {expense.type === ExpenseType.FUEL ? <Fuel size={20} /> : 
                       expense.type === ExpenseType.MAINTENANCE ? <Wrench size={20} /> : 
                       <Navigation size={20} />}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] md:text-[10px] font-black uppercase text-slate-600">{new Date(expense.date).toLocaleDateString()}</span>
                        {expense.type === ExpenseType.SERVICE_REVENUE && (
                          <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded-md ${
                            expense.status === 'RECEIVED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                          }`}>
                            {expense.status === 'RECEIVED' ? 'OK' : 'PENDENTE'}
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-2 mb-0.5">
                        <h4 className="font-black text-black text-sm md:text-base tracking-tight truncate">
                          {expense.type === ExpenseType.FUEL ? expense.fuelType : 
                          expense.type === ExpenseType.SERVICE_REVENUE ? 'Serviço Realizado' : 'Manutenção'}
                        </h4>
                        {expense.type === ExpenseType.FUEL && expense.liters && expense.liters > 0 && (
                          <span className="text-[9px] font-black text-slate-600 bg-slate-100 px-1.5 py-0.5 rounded-md border border-slate-200">
                            R$ {(expense.value / expense.liters).toLocaleString('pt-BR', { minimumFractionDigits: 2 })} /L
                          </span>
                        )}
                      </div>
                      <div className="flex flex-wrap gap-2 mt-0.5">
                        <p className="text-[10px] md:text-[11px] font-bold text-slate-700 truncate flex items-center gap-1">
                          <MapPin size={8} /> {getLocationName(expense.locationId)}
                        </p>
                        <span className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-1 bg-blue-50 px-1.5 rounded-md">
                          {getPaymentMethodLabel(expense.paymentMethod).icon}
                          {getPaymentMethodLabel(expense.paymentMethod).label}
                        </span>
                      </div>
                    </div>

                    <div className="text-right shrink-0">
                      <div className={`text-base md:text-lg font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-700' : 'text-black'}`}>
                        {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </div>
                      <div className="flex items-center justify-end gap-1.5 mt-1">
                         <span className="text-[9px] font-black uppercase text-slate-500 mr-1">{expense.odometer.toLocaleString()} KM</span>
                         {(currentUser.role !== UserRole.SIMPLE || expense.userId === currentUser.id) && (
                           <>
                            <button onClick={() => handleEditExpense(expense)} className="text-slate-400 hover:text-amber-600 transition-colors p-1.5 bg-slate-50 rounded-lg"><Pencil size={14} /></button>
                            <button onClick={() => handleDeleteExpense(expense.id)} className="text-slate-400 hover:text-red-500 transition-colors p-1.5 bg-slate-50 rounded-lg"><Trash2 size={14} /></button>
                           </>
                         )}
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </main>
      </div>

      {isFormOpen && (
        <ExpenseForm 
          lastOdometer={lastOdometer} 
          locations={locations} 
          onAdd={handleSaveExpense} 
          onClose={() => { setIsFormOpen(false); setEditingExpense(null); }}
          initialData={editingExpense}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User, UserRole } from '../types';
import { Gauge, Lock, User as UserIcon, ArrowRight, ShieldAlert } from 'lucide-react';

interface LoginProps {
  onLogin: (user: User) => void;
  availableUsers: User[];
}

export const Login: React.FC<LoginProps> = ({ onLogin, availableUsers }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!username.trim()) return;

    // Tenta encontrar um usuário pré-existente (como admin, padrao ou simples)
    const existingUser = availableUsers.find(u => u.username.toLowerCase() === username.toLowerCase());

    if (existingUser) {
      // Se existe, faz o login imediato com as permissões originais
      onLogin(existingUser);
    } else {
      // Se for um nome novo, cria um usuário Admin na hora para acesso livre
      const newUser: User = {
        id: crypto.randomUUID(),
        name: username.split('.')[0].charAt(0).toUpperCase() + username.split('.')[0].slice(1),
        username: username.toLowerCase(),
        role: UserRole.ADMIN, // Admin por padrão para novas contas em modo livre
      };
      onLogin(newUser);
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-50 flex items-center justify-center p-4 z-[200]">
      <div className="w-full max-w-md">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-black rounded-3xl flex items-center justify-center text-white shadow-2xl mx-auto mb-6">
            <Gauge size={40} />
          </div>
          <h1 className="text-3xl font-black text-black tracking-tight uppercase">AutoGasto</h1>
          <p className="text-xs font-bold text-slate-500 uppercase tracking-widest mt-2">Gestão de Frotas e Despesas</p>
        </div>

        <div className="bg-white p-8 rounded-[40px] shadow-xl border border-slate-100">
          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-black uppercase ml-1 tracking-widest">Usuário</label>
              <div className="relative">
                <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input
                  type="text"
                  value={username}
                  onChange={e => setUsername(e.target.value)}
                  placeholder="Ex: admin ou seu nome"
                  className="w-full p-4 pl-12 bg-slate-50 border-2 border-slate-200 rounded-2xl focus:border-black outline-none transition-all font-bold text-black"
                  required
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-black uppercase ml-1 tracking-widest">Senha</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input
                  type="password"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  placeholder="Qualquer senha"
                  className="w-full p-4 pl-12 bg-slate-50 border-2 border-slate-200 rounded-2xl focus:border-black outline-none transition-all font-bold text-black"
                  required
                />
              </div>
            </div>

            <div className="bg-blue-50 p-4 rounded-2xl border border-blue-100 flex items-start gap-3">
              <div className="mt-0.5 text-blue-600"><ShieldAlert size={16} /></div>
              <p className="text-[10px] font-black text-blue-700 uppercase leading-relaxed">
                Modo de acesso livre ativado. <br/> Use qualquer usuário e senha para entrar.
              </p>
            </div>

            <button
              type="submit"
              className="w-full bg-black text-white py-5 rounded-2xl font-black uppercase text-[13px] tracking-widest shadow-xl hover:bg-slate-900 active:scale-[0.98] transition-all flex items-center justify-center gap-2"
            >
              Entrar no Sistema <ArrowRight size={18} />
            </button>
          </form>
        </div>

        <div className="mt-8 grid grid-cols-3 gap-2 px-4">
          <div className="text-center">
            <p className="text-[8px] font-black text-slate-400 uppercase">Admin</p>
            <p className="text-[9px] font-bold text-slate-600">admin</p>
          </div>
          <div className="text-center">
            <p className="text-[8px] font-black text-slate-400 uppercase">Padrão</p>
            <p className="text-[9px] font-bold text-slate-600">padrao</p>
          </div>
          <div className="text-center">
            <p className="text-[8px] font-black text-slate-400 uppercase">Simples</p>
            <p className="text-[9px] font-bold text-slate-600">simples</p>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Location, User, UserRole } from '../types';
import { Plus, Trash2, Fuel, Wrench, Building2, Sliders, Users, ShieldCheck, UserCheck, User as UserIcon, Pencil, Save, X } from 'lucide-react';

interface SettingsProps {
  locations: Location[];
  onAddLocation: (location: Omit<Location, 'id'>) => void;
  onRemoveLocation: (id: string) => void;
  users: User[];
  onAddUser: (user: Omit<User, 'id'>) => void;
  onUpdateUser: (user: User) => void;
  onRemoveUser: (id: string) => void;
  currentUserRole: UserRole;
}

export const Settings: React.FC<SettingsProps> = ({ 
  locations, onAddLocation, onRemoveLocation, 
  users, onAddUser, onUpdateUser, onRemoveUser, 
  currentUserRole 
}) => {
  const [activeSubTab, setActiveSubTab] = useState<'LOCATIONS' | 'USERS'>('LOCATIONS');

  const [name, setName] = useState('');
  const [locType, setLocType] = useState<'POSTO' | 'OFICINA' | 'CLIENTE'>('POSTO');

  const [userName, setUserName] = useState('');
  const [userUsername, setUserUsername] = useState('');
  const [userPass, setUserPass] = useState('');
  const [userRole, setUserRole] = useState<UserRole>(UserRole.STANDARD);

  const [isAdding, setIsAdding] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);

  const handleSubmitLocation = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;
    onAddLocation({ name, type: locType });
    setName('');
    setIsAdding(false);
  };

  const handleEditUser = (user: User) => {
    setEditingUserId(user.id);
    setUserName(user.name);
    setUserUsername(user.username);
    setUserPass(user.password || '');
    setUserRole(user.role);
    setIsAdding(true);
  };

  const cancelUserEdit = () => {
    setEditingUserId(null);
    setUserName('');
    setUserUsername('');
    setUserPass('');
    setUserRole(UserRole.STANDARD);
    setIsAdding(false);
  };

  const handleSubmitUser = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userName.trim() || !userUsername.trim()) return;

    if (editingUserId) {
      onUpdateUser({
        id: editingUserId,
        name: userName,
        username: userUsername,
        password: userPass,
        role: userRole
      });
    } else {
      onAddUser({ name: userName, username: userUsername, password: userPass, role: userRole });
    }

    cancelUserEdit();
  };

  const groupedLocations = {
    POSTO: locations.filter(l => l.type === 'POSTO'),
    OFICINA: locations.filter(l => l.type === 'OFICINA'),
    CLIENTE: locations.filter(l => l.type === 'CLIENTE'),
  };

  const SectionHeader = ({ title, icon: Icon, colorClass, count }: { title: string, icon: any, colorClass: string, count: number }) => (
    <div className="flex items-center justify-between mb-4 mt-6 first:mt-0">
      <div className="flex items-center gap-2">
        <div className={`p-2 rounded-xl ${colorClass}`}>
          <Icon size={18} />
        </div>
        <h3 className="text-sm font-black text-black uppercase tracking-widest">{title}</h3>
      </div>
      <span className="text-[10px] font-black text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">
        {count}
      </span>
    </div>
  );

  return (
    <div className="space-y-6 pb-12">
      <div className="flex bg-white p-1.5 rounded-2xl border border-slate-200 mb-6">
        <button 
          onClick={() => { setActiveSubTab('LOCATIONS'); cancelUserEdit(); }}
          className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-tight transition-all flex items-center justify-center gap-2 ${
            activeSubTab === 'LOCATIONS' ? 'bg-black text-white shadow-md' : 'text-slate-500 hover:text-black'
          }`}
        >
          <Building2 size={16} /> Locais
        </button>
        {currentUserRole === UserRole.ADMIN && (
          <button 
            onClick={() => { setActiveSubTab('USERS'); cancelUserEdit(); }}
            className={`flex-1 py-3 rounded-xl text-[10px] font-black uppercase tracking-tight transition-all flex items-center justify-center gap-2 ${
              activeSubTab === 'USERS' ? 'bg-black text-white shadow-md' : 'text-slate-500 hover:text-black'
            }`}
          >
            <Users size={16} /> Usuários
          </button>
        )}
      </div>

      {activeSubTab === 'LOCATIONS' && (
        <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-200">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h2 className="text-xl font-black text-black tracking-tight">Locais e Empresas</h2>
              <p className="text-[10px] font-bold text-slate-500 uppercase">Postos, Oficinas e Clientes</p>
            </div>
            <button 
              onClick={() => setIsAdding(!isAdding)}
              className={`p-3 rounded-2xl transition-all shadow-md active:scale-95 ${
                isAdding ? 'bg-red-50 text-red-600' : 'bg-black text-white'
              }`}
            >
              {isAdding ? <Plus className="rotate-45" size={20} /> : <Plus size={20} />}
            </button>
          </div>

          {isAdding && (
            <form onSubmit={handleSubmitLocation} className="space-y-4 animate-in fade-in zoom-in duration-200 mb-6 bg-slate-50 p-5 rounded-2xl border border-slate-200">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-black uppercase ml-1">Nome</label>
                  <input
                    type="text"
                    placeholder="Ex: Posto Ipiranga"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl focus:border-black outline-none transition-all text-sm font-bold text-black"
                  />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-black uppercase ml-1">Categoria</label>
                  <select
                    value={locType}
                    onChange={(e) => setLocType(e.target.value as any)}
                    className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl outline-none text-sm font-bold text-black appearance-none"
                  >
                    <option value="POSTO">Posto</option>
                    <option value="OFICINA">Oficina</option>
                    <option value="CLIENTE">Cliente</option>
                  </select>
                </div>
              </div>
              <button type="submit" className="w-full bg-black text-white py-4 rounded-xl font-black uppercase text-[11px] tracking-widest shadow-xl">Salvar Local</button>
            </form>
          )}

          <div className="space-y-2">
            <SectionHeader title="Postos" icon={Fuel} colorClass="bg-blue-50 text-blue-600" count={groupedLocations.POSTO.length} />
            {groupedLocations.POSTO.map(l => (
              <div key={l.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <span className="text-sm font-bold text-black">{l.name}</span>
                <button onClick={() => onRemoveLocation(l.id)} className="text-slate-300 hover:text-red-500"><Trash2 size={16} /></button>
              </div>
            ))}

            <SectionHeader title="Oficinas" icon={Wrench} colorClass="bg-orange-50 text-orange-600" count={groupedLocations.OFICINA.length} />
            {groupedLocations.OFICINA.map(l => (
              <div key={l.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <span className="text-sm font-bold text-black">{l.name}</span>
                <button onClick={() => onRemoveLocation(l.id)} className="text-slate-300 hover:text-red-500"><Trash2 size={16} /></button>
              </div>
            ))}

            <SectionHeader title="Clientes" icon={Building2} colorClass="bg-emerald-50 text-emerald-600" count={groupedLocations.CLIENTE.length} />
            {groupedLocations.CLIENTE.map(l => (
              <div key={l.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <span className="text-sm font-bold text-black">{l.name}</span>
                <button onClick={() => onRemoveLocation(l.id)} className="text-slate-300 hover:text-red-500"><Trash2 size={16} /></button>
              </div>
            ))}
          </div>
        </div>
      )}

      {activeSubTab === 'USERS' && currentUserRole === UserRole.ADMIN && (
        <div className="bg-white p-6 rounded-[32px] shadow-sm border border-slate-200">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h2 className="text-xl font-black text-black tracking-tight">Gestão de Equipe</h2>
              <p className="text-[10px] font-bold text-slate-500 uppercase">Usuários e Permissões</p>
            </div>
            {!editingUserId && (
              <button 
                onClick={() => setIsAdding(!isAdding)}
                className={`p-3 rounded-2xl transition-all shadow-md active:scale-95 ${
                  isAdding ? 'bg-red-50 text-red-600' : 'bg-black text-white'
                }`}
              >
                {isAdding ? <Plus className="rotate-45" size={20} /> : <Plus size={20} />}
              </button>
            )}
          </div>

          {isAdding && (
            <form onSubmit={handleSubmitUser} className="space-y-4 animate-in fade-in zoom-in duration-200 mb-6 bg-slate-50 p-5 rounded-2xl border border-slate-200">
              <div className="flex justify-between items-center mb-2">
                <h4 className="text-[10px] font-black uppercase text-slate-400">{editingUserId ? 'Editando Usuário' : 'Novo Usuário'}</h4>
                {editingUserId && <button type="button" onClick={cancelUserEdit} className="text-red-500 hover:text-red-700"><X size={18} /></button>}
              </div>
              <div className="grid grid-cols-1 gap-4">
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-black uppercase ml-1">Nome Completo</label>
                  <input type="text" value={userName} onChange={e => setUserName(e.target.value)} className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl focus:border-black outline-none font-bold text-black" placeholder="Ex: João Silva" />
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-black uppercase ml-1">Login</label>
                    <input type="text" value={userUsername} onChange={e => setUserUsername(e.target.value)} className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl focus:border-black outline-none font-bold text-black" placeholder="joao.silva" />
                  </div>
                   <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-black uppercase ml-1">Senha</label>
                    <input type="password" value={userPass} onChange={e => setUserPass(e.target.value)} className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl focus:border-black outline-none font-bold text-black" placeholder="••••" />
                  </div>
                </div>
                <div className="space-y-1.5">
                  <label className="text-[10px] font-black text-black uppercase ml-1">Nível de Acesso</label>
                  <select value={userRole} onChange={e => setUserRole(e.target.value as UserRole)} className="w-full p-4 bg-white border-2 border-slate-200 rounded-xl outline-none font-bold text-black">
                    <option value={UserRole.ADMIN}>Administrador</option>
                    <option value={UserRole.STANDARD}>Usuário Padrão</option>
                    <option value={UserRole.SIMPLE}>Usuário Simples</option>
                  </select>
                </div>
              </div>
              <button type="submit" className={`w-full text-white py-4 rounded-xl font-black uppercase text-[11px] tracking-widest shadow-xl flex items-center justify-center gap-2 ${editingUserId ? 'bg-amber-600' : 'bg-black'}`}>
                {editingUserId ? <><Save size={16} /> Atualizar Usuário</> : 'Cadastrar Usuário'}
              </button>
            </form>
          )}

          <div className="space-y-3">
            {users.map(u => (
              <div key={u.id} className="flex items-center justify-between p-5 bg-slate-50 rounded-2xl border border-slate-100 shadow-sm">
                <div className="flex items-center gap-4">
                  <div className={`p-3 rounded-xl ${u.role === UserRole.ADMIN ? 'bg-black text-white' : u.role === UserRole.STANDARD ? 'bg-blue-100 text-blue-600' : 'bg-slate-200 text-slate-500'}`}>
                    {u.role === UserRole.ADMIN ? <ShieldCheck size={20} /> : u.role === UserRole.STANDARD ? <UserCheck size={20} /> : <UserIcon size={20} />}
                  </div>
                  <div>
                    <h4 className="text-sm font-black text-black">{u.name}</h4>
                    <div className="flex items-center gap-2">
                      <span className="text-[9px] font-black uppercase text-slate-400">@{u.username}</span>
                      <span className="text-[8px] font-black uppercase bg-slate-200 px-1.5 py-0.5 rounded text-slate-600">{u.role}</span>
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <button onClick={() => handleEditUser(u)} className="text-slate-400 hover:text-amber-600 transition-colors p-2 bg-white rounded-xl shadow-sm"><Pencil size={16} /></button>
                  {u.username !== 'admin' && (
                     <button onClick={() => onRemoveUser(u.id)} className="text-slate-300 hover:text-red-500 transition-colors p-2 bg-white rounded-xl shadow-sm"><Trash2 size={16} /></button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location, PaymentMethod, User, UserRole } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { Settings } from './components/Settings';
import { Reports } from './components/Reports';
import { Login } from './components/Login';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Pencil, Fuel, Wrench, Gauge, MapPin, Navigation, FileText, Printer, Zap, CreditCard, Wallet, Settings as SettingsIcon, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('autoGasto_loggedUser');
    return saved ? JSON.parse(saved) : null;
  });

  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('autoGasto_users');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Administrador', username: 'admin', role: UserRole.ADMIN, password: '123' },
      { id: '2', name: 'Usuário Padrão', username: 'padrao', role: UserRole.STANDARD, password: '123' },
      { id: '3', name: 'Usuário Simples', username: 'simples', role: UserRole.SIMPLE, password: '123' }
    ];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'settings' | 'reports'>(() => {
     // Default tab based on role if logged in
     const savedUser = localStorage.getItem('autoGasto_loggedUser');
     if (savedUser) {
       const user = JSON.parse(savedUser) as User;
       if (user.role === UserRole.SIMPLE) return 'reports';
     }
     return 'dashboard';
  });
  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem('autoGasto_loggedUser', JSON.stringify(currentUser));
  }, [currentUser]);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleLogin = (user: User) => {
    setUsers(prev => {
      if (!prev.find(u => u.username.toLowerCase() === user.username.toLowerCase())) {
        return [...prev, user];
      }
      return prev;
    });
    setCurrentUser(user);
    // Determine default tab after login
    if (user.role === UserRole.SIMPLE) setActiveTab('reports');
    else setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
  };

  const handleSaveExpense = (data: Omit<Expense, 'id'> | Expense) => {
    if ('id' in data) {
      setExpenses(prev => 
        prev.map(e => e.id === data.id ? (data as Expense) : e)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
      );
    } else {
      const expense: Expense = {
        ...data,
        id: crypto.randomUUID(),
        userId: currentUser?.id
      };
      setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
    }
    setIsFormOpen(false);
    setEditingExpense(null);
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleAddUser = (user: Omit<User, 'id'>) => {
    setUsers([...users, { ...user, id: crypto.randomUUID() }]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
    // If updating currently logged in user
    if (currentUser?.id === updatedUser.id) {
      setCurrentUser(updatedUser);
    }
  };

  const handleRemoveUser = (id: string) => {
    setUsers(users.filter(u => u.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const handleEditExpense = (expense: Expense) => {
    if (currentUser?.role === UserRole.SIMPLE && expense.userId !== currentUser.id) {
      alert("Acesso negado: você só pode editar seus próprios registros.");
      return;
    }
    setEditingExpense(expense);
    setIsFormOpen(true);
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  const getPaymentMethodLabel = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return { label: 'PIX', icon: <Zap size={10} /> };
      case 'CREDITO': return { label: 'Crédito', icon: <CreditCard size={10} /> };
      case 'DEBITO': return { label: 'Débito', icon: <CreditCard size={10} /> };
      case 'DINHEIRO': return { label: 'Dinheiro', icon: <Wallet size={10} /> };
      case 'NOTA_PRAZO': return { label: 'Nota a Prazo', icon: <FileText size={10} /> };
      default: return { label: '-', icon: null };
    }
  };

  const NavItem = ({ id, icon: Icon, label }: { id: any, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center gap-1 flex-1 py-1 transition-all rounded-xl ${
        activeTab === id ? 'text-blue-600 bg-blue-50/50' : 'text-slate-500 hover:text-slate-700'
      }`}
    >
      <Icon size={20} className={activeTab === id ? 'scale-110' : ''} />
      <span className="text-[9px] font-black uppercase tracking-tighter">{label}</span>
    </button>
  );

  if (!currentUser) {
    return <Login onLogin={handleLogin} availableUsers={users} />;
  }

  return (
    <div className="flex min-h-screen bg-[#F8FAFC] w-full overflow-x-hidden">
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-200 flex items-center justify-between z-[90] no-print safe-pb shadow-[0_-8px_30px_rgb(0,0,0,0.08)] h-16 px-4 max-w-lg mx-auto md:rounded-t-[32px]">
        {currentUser.role !== UserRole.SIMPLE && <NavItem id="dashboard" icon={LayoutDashboard} label="Início" />}
        <NavItem id="history" icon={History} label="Histórico" />

        <div className="relative -top-6">
          <button 
            onClick={() => {
              setEditingExpense(null);
              setIsFormOpen(true);
            }}
            className="w-14 h-14 bg-blue-600 text-white rounded-2xl shadow-xl flex items-center justify-center active:scale-90 hover:bg-blue-700 transition-all border-4 border-[#F8FAFC]"
          >
            <Plus size={28} strokeWidth={3} />
          </button>
        </div>

        <NavItem id="reports" icon={FileText} label="Relatórios" />
        {currentUser.role === UserRole.ADMIN && <NavItem id="settings" icon={SettingsIcon} label="Ajustes" />}
      </nav>

      <div className="flex-1 transition-all duration-300 pb-24 w-full overflow-x-hidden">
        <header className="bg-white/90 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40 no-print">
          <div className="max-w-4xl mx-auto px-4 py-4 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-md">
                <Gauge size={18} />
              </div>
              <div className="min-w-0">
                <h2 className="text-xs md:text-sm font-black text-black uppercase tracking-tight truncate leading-none mb-1">
                  {currentUser.name}
                </h2>
                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">
                  {currentUser.role === UserRole.ADMIN ? 'Administrador' : currentUser.role === UserRole.STANDARD ? 'Padrão' : 'Simples'}
                </span>
              </div>
            </div>

            <div className="flex items-center gap-2 shrink-0">
              <span className="text-[9px] font-black text-black uppercase tracking-widest bg-slate-100 px-2.5 py-1.5 rounded-xl border border-slate-300">
                KM: {lastOdometer.toLocaleString()}
              </span>
              <button onClick={handleLogout} className="p-2 bg-slate-100 rounded-xl text-slate-500 hover:text-red-600 border border-slate-300">
                <LogOut size={16} />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 md:px-6 py-6 w-full">
          {activeTab === 'dashboard' && currentUser.role !== UserRole.SIMPLE && (
            <div className="no-print animate-in fade-in duration-500 w-full overflow-x-hidden">
              {expenses.length >= 2 && currentUser.role === UserRole.ADMIN && (
                <div className="mb-6 bg-gradient-to-br from-blue-700 to-indigo-800 rounded-[28px] p-6 text-white shadow-xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                  <div className="relative z-10">
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center space-x-2">
                        <Sparkles size={16} className="text-yellow-300" />
                        <h2 className="font-black text-xs md:text-sm uppercase tracking-tight">Sugestões de Economia</h2>
                      </div>
                      <button onClick={fetchAIInsights} disabled={loadingInsights} className="text-[9px] font-black uppercase tracking-widest bg-white/20 px-3 py-1.5 rounded-lg border border-white/10">
                        {loadingInsights ? "..." : "Atualizar"}
                      </button>
                    </div>
                    {insights.length > 0 ? (
                      <div className="space-y-2">
                        {insights.slice(0, 2).map((tip, idx) => (
                          <div key={idx} className="bg-white/10 backdrop-blur-md p-3 rounded-xl text-[10px] md:text-[11px] font-bold border border-white/5 shadow-sm">{tip}</div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-white/70 text-[10px] font-bold">Gerencie suas despesas e peça dicas à IA.</p>
                    )}
                  </div>
                </div>
              )}
              <Dashboard expenses={expenses} />
            </div>
          )}

          {activeTab === 'settings' && currentUser.role === UserRole.ADMIN && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Settings 
                locations={locations} onAddLocation={handleAddLocation} onRemoveLocation={handleRemoveLocation} 
                users={users} onAddUser={handleAddUser} onUpdateUser={handleUpdateUser} onRemoveUser={handleRemoveUser}
                currentUserRole={currentUser.role}
              />
            </div>
          )}

          {activeTab === 'reports' && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Reports expenses={expenses} locations={locations} forcedRole={currentUser.role} />
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-4 animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <div className="flex justify-between items-center mb-4 no-print px-1">
                <h3 className="text-xl font-black text-black tracking-tight">Atividades</h3>
                <button onClick={() => window.print()} className="p-2.5 bg-white border border-slate-300 rounded-xl text-black hover:bg-slate-50 transition-all shadow-sm"><Printer size={18} /></button>
              </div>

              {expenses.length === 0 ? (
                <div className="bg-white p-12 text-center text-slate-400 rounded-[32px] border-2 border-dashed border-slate-200">
                  <History size={40} className="mx-auto mb-4 opacity-20" />
                  <p className="text-sm font-bold">Nenhum lançamento encontrado.</p>
                </div>
              ) : (
                expenses.map(expense => (
                  <div key={expense.id} className="bg-white rounded-[24px] p-4 md:p-5 shadow-md border border-slate-200 flex items-center gap-4 group active:scale-[0.98] transition-all w-full hover:shadow-lg">
                    <div className={`p-3 rounded-2xl shrink-0 ${
                      expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-700' : 
                      expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-700' :
                      'bg-emerald-50 text-emerald-700'
                    }`}>
                      {expense.type === ExpenseType.FUEL ? <Fuel size={20} /> : 
                       expense.type === ExpenseType.MAINTENANCE ? <Wrench size={20} /> : 
                       <Navigation size={20} />}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] md:text-[10px] font-black uppercase text-slate-600">{new Date(expense.date).toLocaleDateString()}</span>
                        {expense.type === ExpenseType.SERVICE_REVENUE && (
                          <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded-md ${
                            expense.status === 'RECEIVED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                          }`}>
                            {expense.status === 'RECEIVED' ? 'OK' : 'PENDENTE'}
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-2 mb-0.5">
                        <h4 className="font-black text-black text-sm md:text-base tracking-tight truncate">
                          {expense.type === ExpenseType.FUEL ? expense.fuelType : 
                          expense.type === ExpenseType.SERVICE_REVENUE ? 'Serviço Realizado' : 'Manutenção'}
                        </h4>
                        {expense.type === ExpenseType.FUEL && expense.liters && expense.liters > 0 && (
                          <span className="text-[9px] font-black text-slate-600 bg-slate-100 px-1.5 py-0.5 rounded-md border border-slate-200">
                            R$ {(expense.value / expense.liters).toLocaleString('pt-BR', { minimumFractionDigits: 2 })} /L
                          </span>
                        )}
                      </div>
                      <div className="flex flex-wrap gap-2 mt-0.5">
                        <p className="text-[10px] md:text-[11px] font-bold text-slate-700 truncate flex items-center gap-1">
                          <MapPin size={8} /> {getLocationName(expense.locationId)}
                        </p>
                        <span className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-1 bg-blue-50 px-1.5 rounded-md">
                          {getPaymentMethodLabel(expense.paymentMethod).icon}
                          {getPaymentMethodLabel(expense.paymentMethod).label}
                        </span>
                      </div>
                    </div>

                    <div className="text-right shrink-0">
                      <div className={`text-base md:text-lg font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-700' : 'text-black'}`}>
                        {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </div>
                      <div className="flex items-center justify-end gap-1.5 mt-1">
                         <span className="text-[9px] font-black uppercase text-slate-500 mr-1">{expense.odometer.toLocaleString()} KM</span>
                         {(currentUser.role !== UserRole.SIMPLE || expense.userId === currentUser.id) && (
                           <>
                            <button onClick={() => handleEditExpense(expense)} className="text-slate-400 hover:text-amber-600 transition-colors p-1.5 bg-slate-50 rounded-lg"><Pencil size={14} /></button>
                            <button onClick={() => handleDeleteExpense(expense.id)} className="text-slate-400 hover:text-red-500 transition-colors p-1.5 bg-slate-50 rounded-lg"><Trash2 size={14} /></button>
                           </>
                         )}
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </main>
      </div>

      {isFormOpen && (
        <ExpenseForm 
          lastOdometer={lastOdometer} 
          locations={locations} 
          onAdd={handleSaveExpense} 
          onClose={() => { setIsFormOpen(false); setEditingExpense(null); }}
          initialData={editingExpense}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Expense, ExpenseType, Location, PaymentMethod, UserRole } from '../types';
import { FileText, Printer, Calendar, Filter, Fuel, Wrench, Navigation, DollarSign, HandCoins, CheckCircle2, Clock, Zap, CreditCard, Wallet } from 'lucide-react';

interface ReportsProps {
  expenses: Expense[];
  locations: Location[];
  forcedRole?: UserRole;
}

type ReportType = 'ALL' | 'FUEL' | 'MAINTENANCE' | 'SERVICE';
type StatusFilter = 'ALL' | 'RECEIVED' | 'PENDING';
type PaymentFilter = 'ALL' | PaymentMethod;

export const Reports: React.FC<ReportsProps> = ({ expenses, locations, forcedRole }) => {
  const isSimpleUser = forcedRole === UserRole.SIMPLE;

  const [startDate, setStartDate] = useState<string>(new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0]);
  const [endDate, setEndDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [reportType, setReportType] = useState<ReportType>(isSimpleUser ? 'SERVICE' : 'ALL');
  const [statusFilter, setStatusFilter] = useState<StatusFilter>('ALL');
  const [paymentFilter, setPaymentFilter] = useState<PaymentFilter>('ALL');

  useEffect(() => {
    if (isSimpleUser) setReportType('SERVICE');
  }, [isSimpleUser]);

  const filteredData = useMemo(() => {
    return expenses.filter(e => {
      const date = new Date(e.date);
      const start = new Date(startDate);
      const end = new Date(endDate);
      end.setHours(23, 59, 59, 999);
      const matchesDate = date >= start && date <= end;

      const currentReportType = isSimpleUser ? 'SERVICE' : reportType;

      const matchesType = currentReportType === 'ALL' || 
                         (currentReportType === 'FUEL' && e.type === ExpenseType.FUEL) || 
                         (currentReportType === 'MAINTENANCE' && e.type === ExpenseType.MAINTENANCE) || 
                         (currentReportType === 'SERVICE' && e.type === ExpenseType.SERVICE_REVENUE);

      const matchesStatus = statusFilter === 'ALL' || (e.type === ExpenseType.SERVICE_REVENUE && e.status === statusFilter) || (e.type !== ExpenseType.SERVICE_REVENUE && statusFilter === 'RECEIVED');
      const matchesPayment = paymentFilter === 'ALL' || e.paymentMethod === paymentFilter;
      return matchesDate && matchesType && matchesStatus && matchesPayment;
    }).sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
  }, [expenses, startDate, endDate, reportType, statusFilter, paymentFilter, isSimpleUser]);

  const totals = useMemo(() => {
    return filteredData.reduce((acc, curr) => {
      if (curr.type === ExpenseType.SERVICE_REVENUE) {
        if (curr.status === 'RECEIVED') acc.earned += curr.value;
        else acc.pending += curr.value;
      } else {
        acc.spent += curr.value;
      }
      return acc;
    }, { spent: 0, earned: 0, pending: 0 });
  }, [filteredData]);

  const getLocationName = (id?: string) => locations.find(l => l.id === id)?.name || 'N/A';
  const getPaymentMethodIcon = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return <Zap size={12} />;
      case 'CREDITO': case 'DEBITO': return <CreditCard size={12} />;
      case 'DINHEIRO': return <Wallet size={12} />;
      case 'NOTA_PRAZO': return <FileText size={12} />;
      default: return null;
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-5 rounded-[28px] border border-slate-200 shadow-sm no-print">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-2">
            <Filter size={18} className="text-blue-600" />
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-700">Filtrar Relatório</span>
          </div>
          <button onClick={() => window.print()} className="bg-black text-white p-3 rounded-2xl shadow-lg active:scale-95"><Printer size={18} /></button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
          <div className="space-y-1">
            <label className="text-[9px] font-black text-black uppercase ml-1">Início</label>
            <input type="date" value={startDate} onChange={e => setStartDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-xs font-bold text-black" />
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-black uppercase ml-1">Fim</label>
            <input type="date" value={endDate} onChange={e => setEndDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-xs font-bold text-black" />
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-black uppercase ml-1">Tipo</label>
            <select 
              disabled={isSimpleUser} 
              value={isSimpleUser ? 'SERVICE' : reportType} 
              onChange={e => setReportType(e.target.value as any)} 
              className={`w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-xs font-bold text-black appearance-none ${isSimpleUser ? 'opacity-50' : ''}`}
            >
              {!isSimpleUser && <option value="ALL">Todos</option>}
              {!isSimpleUser && <option value="FUEL">Combustível</option>}
              {!isSimpleUser && <option value="MAINTENANCE">Manutenção</option>}
              <option value="SERVICE">Serviços</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-black uppercase ml-1">Status</label>
            <select value={statusFilter} onChange={e => setStatusFilter(e.target.value as any)} className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-xs font-bold text-black appearance-none">
              <option value="ALL">Todos</option>
              <option value="RECEIVED">Recebidos</option>
              <option value="PENDING">Pendentes</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[9px] font-black text-black uppercase ml-1">Pagto.</label>
            <select value={paymentFilter} onChange={e => setPaymentFilter(e.target.value as any)} className="w-full p-4 bg-slate-50 border border-slate-300 rounded-2xl text-xs font-bold text-black appearance-none">
              <option value="ALL">Todas</option>
              <option value="PIX">PIX</option>
              <option value="CREDITO">Crédito</option>
              <option value="DEBITO">Débito</option>
              <option value="DINHEIRO">Dinheiro</option>
              <option value="NOTA_PRAZO">Nota a Prazo</option>
            </select>
          </div>
        </div>
        {isSimpleUser && (
          <p className="mt-4 text-[9px] font-black text-amber-600 uppercase tracking-widest bg-amber-50 p-2 rounded-xl border border-amber-100">
            Acesso Restrito: Visualizando apenas relatórios de serviço.
          </p>
        )}
      </div>

      <div className="bg-white rounded-[32px] border border-slate-200 shadow-md overflow-hidden">
        <div className="p-6 md:p-8 bg-slate-50/50 grid grid-cols-2 md:grid-cols-3 gap-4 border-b border-slate-200">
          <div className="col-span-2 md:col-span-1 mb-2 md:mb-0">
            <h3 className="text-xl font-black tracking-tight text-black">Relatório</h3>
            <p className="text-[10px] font-bold text-slate-700 uppercase">{filteredData.length} registros encontrados</p>
          </div>
          {!isSimpleUser && (
            <div className="bg-white p-3 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-[8px] font-black text-slate-500 uppercase mb-1">Total Gasto</p>
              <p className="text-lg font-black text-red-600">R$ {totals.spent.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            </div>
          )}
          <div className="bg-white p-3 rounded-2xl border border-slate-200 shadow-sm">
            <p className="text-[8px] font-black text-slate-500 uppercase mb-1">Total Ganho</p>
            <p className="text-lg font-black text-emerald-600">R$ {totals.earned.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
          </div>
          {totals.pending > 0 && (
            <div className="bg-white p-3 rounded-2xl border border-slate-200 shadow-sm">
              <p className="text-[8px] font-black text-slate-500 uppercase mb-1">Total Pendente</p>
              <p className="text-lg font-black text-amber-600">R$ {totals.pending.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            </div>
          )}
        </div>

        <div className="overflow-x-auto scrollbar-hide">
          <table className="w-full text-left min-w-[600px]">
            <thead>
              <tr className="bg-white border-b border-slate-200">
                <th className="px-6 py-4 text-[9px] font-black text-black uppercase tracking-widest">Data</th>
                <th className="px-6 py-4 text-[9px] font-black text-black uppercase tracking-widest">Categoria</th>
                <th className="px-6 py-4 text-[9px] font-black text-black uppercase tracking-widest">Local</th>
                <th className="px-6 py-4 text-[9px] font-black text-black uppercase tracking-widest text-right">Valor</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {filteredData.map(e => (
                <tr key={e.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4 text-[11px] font-black text-slate-700">{new Date(e.date).toLocaleDateString()}</td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col">
                      <span className="text-xs font-black text-black">{e.type === 'FUEL' ? 'Combustível' : e.type === 'MAINTENANCE' ? 'Oficina' : 'Serviço'}</span>
                      <span className="text-[8px] font-black text-slate-600 uppercase flex items-center gap-1">
                        {getPaymentMethodIcon(e.paymentMethod)} 
                        {e.paymentMethod === 'NOTA_PRAZO' ? 'Nota a Prazo' : e.paymentMethod}
                      </span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-xs font-black text-slate-800 truncate max-w-[150px]">{getLocationName(e.locationId)}</td>
                  <td className={`px-6 py-4 text-right text-xs font-black ${e.type === 'SERVICE_REVENUE' ? 'text-emerald-700' : 'text-black'}`}>
                    {e.type === 'SERVICE_REVENUE' ? '+' : ''} R$ {e.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Expense, ExpenseType, CarStats, Location, PaymentMethod, User, UserRole } from './types';
import { Dashboard } from './components/Dashboard';
import { ExpenseForm } from './components/ExpenseForm';
import { Settings } from './components/Settings';
import { Reports } from './components/Reports';
import { Login } from './components/Login';
import { getInsights } from './services/geminiService';
import { Plus, LayoutDashboard, History, Sparkles, Trash2, Pencil, Fuel, Wrench, Gauge, MapPin, Navigation, FileText, Printer, Zap, CreditCard, Wallet, Settings as SettingsIcon, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    try {
      const saved = localStorage.getItem('autoGasto_loggedUser');
      if (!saved || saved === 'null') return null;
      return JSON.parse(saved);
    } catch (e) {
      console.error("Erro ao carregar usuário logado:", e);
      return null;
    }
  });

  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('autoGasto_users');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Administrador', username: 'admin', role: UserRole.ADMIN, password: '123' },
      { id: '2', name: 'Usuário Padrão', username: 'padrao', role: UserRole.STANDARD, password: '123' },
      { id: '3', name: 'Usuário Simples', username: 'simples', role: UserRole.SIMPLE, password: '123' }
    ];
  });

  const [expenses, setExpenses] = useState<Expense[]>(() => {
    const saved = localStorage.getItem('autoGasto_expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [locations, setLocations] = useState<Location[]>(() => {
    const saved = localStorage.getItem('autoGasto_locations');
    return saved ? JSON.parse(saved) : [
      { id: '1', name: 'Posto Central', type: 'POSTO' },
      { id: '2', name: 'Oficina do Zé', type: 'OFICINA' }
    ];
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<Expense | null>(null);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'history' | 'settings' | 'reports'>(() => {
     try {
       const savedUserStr = localStorage.getItem('autoGasto_loggedUser');
       if (savedUserStr && savedUserStr !== 'null') {
         const user = JSON.parse(savedUserStr);
         if (user && user.role === UserRole.SIMPLE) return 'reports';
       }
     } catch (e) {
       console.error("Erro ao inicializar aba ativa:", e);
     }
     return 'dashboard';
  });

  const [insights, setInsights] = useState<string[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);

  useEffect(() => {
    localStorage.setItem('autoGasto_users', JSON.stringify(users));
  }, [users]);

  useEffect(() => {
    localStorage.setItem('autoGasto_loggedUser', JSON.stringify(currentUser));
  }, [currentUser]);

  useEffect(() => {
    localStorage.setItem('autoGasto_expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('autoGasto_locations', JSON.stringify(locations));
  }, [locations]);

  const lastOdometer = useMemo(() => {
    return expenses.length > 0 ? Math.max(...expenses.map(e => e.odometer)) : 0;
  }, [expenses]);

  const handleLogin = (user: User) => {
    setUsers(prev => {
      if (!prev.find(u => u.username.toLowerCase() === user.username.toLowerCase())) {
        return [...prev, user];
      }
      return prev;
    });
    setCurrentUser(user);
    if (user.role === UserRole.SIMPLE) setActiveTab('reports');
    else setActiveTab('dashboard');
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setActiveTab('dashboard');
  };

  const handleSaveExpense = (data: Omit<Expense, 'id'> | Expense) => {
    if ('id' in data) {
      setExpenses(prev => 
        prev.map(e => e.id === data.id ? (data as Expense) : e)
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
      );
    } else {
      const expense: Expense = {
        ...data,
        id: crypto.randomUUID(),
        userId: currentUser?.id
      };
      setExpenses(prev => [...prev, expense].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));
    }
    setIsFormOpen(false);
    setEditingExpense(null);
  };

  const handleAddLocation = (loc: Omit<Location, 'id'>) => {
    setLocations([...locations, { ...loc, id: crypto.randomUUID() }]);
  };

  const handleRemoveLocation = (id: string) => {
    setLocations(locations.filter(l => l.id !== id));
  };

  const handleAddUser = (user: Omit<User, 'id'>) => {
    setUsers([...users, { ...user, id: crypto.randomUUID() }]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(users.map(u => u.id === updatedUser.id ? updatedUser : u));
    if (currentUser?.id === updatedUser.id) {
      setCurrentUser(updatedUser);
    }
  };

  const handleRemoveUser = (id: string) => {
    setUsers(users.filter(u => u.id !== id));
  };

  const handleDeleteExpense = (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este registro permanentemente?')) {
      setExpenses(prev => prev.filter(e => e.id !== id));
    }
  };

  const handleEditExpense = (expense: Expense) => {
    if (currentUser?.role === UserRole.SIMPLE && expense.userId !== currentUser.id) {
      alert("Acesso negado: você só pode editar seus próprios registros.");
      return;
    }
    setEditingExpense(expense);
    setIsFormOpen(true);
  };

  const fetchAIInsights = async () => {
    if (expenses.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(expenses);
    setInsights(data);
    setLoadingInsights(false);
  };

  const getLocationName = (id?: string) => {
    return locations.find(l => l.id === id)?.name || 'Local não informado';
  };

  const getPaymentMethodLabel = (method?: PaymentMethod) => {
    switch (method) {
      case 'PIX': return { label: 'PIX', icon: <Zap size={10} /> };
      case 'CREDITO': return { label: 'Crédito', icon: <CreditCard size={10} /> };
      case 'DEBITO': return { label: 'Débito', icon: <CreditCard size={10} /> };
      case 'DINHEIRO': return { label: 'Dinheiro', icon: <Wallet size={10} /> };
      case 'NOTA_PRAZO': return { label: 'Nota a Prazo', icon: <FileText size={10} /> };
      default: return { label: '-', icon: null };
    }
  };

  const NavItem = ({ id, icon: Icon, label }: { id: any, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center gap-1 flex-1 py-1 transition-all rounded-xl ${
        activeTab === id ? 'text-blue-600 bg-blue-50/50' : 'text-slate-500 hover:text-slate-700'
      }`}
    >
      <Icon size={20} className={activeTab === id ? 'scale-110' : ''} />
      <span className="text-[9px] font-black uppercase tracking-tighter">{label}</span>
    </button>
  );

  if (!currentUser) {
    return <Login onLogin={handleLogin} availableUsers={users} />;
  }

  return (
    <div className="flex min-h-screen bg-[#F8FAFC] w-full overflow-x-hidden">
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-200 flex items-center justify-between z-[90] no-print safe-pb shadow-[0_-8px_30px_rgb(0,0,0,0.08)] h-16 px-4 max-w-lg mx-auto md:rounded-t-[32px]">
        {currentUser.role !== UserRole.SIMPLE && <NavItem id="dashboard" icon={LayoutDashboard} label="Início" />}
        <NavItem id="history" icon={History} label="Histórico" />

        <div className="relative -top-6">
          <button 
            onClick={() => {
              setEditingExpense(null);
              setIsFormOpen(true);
            }}
            className="w-14 h-14 bg-blue-600 text-white rounded-2xl shadow-xl flex items-center justify-center active:scale-90 hover:bg-blue-700 transition-all border-4 border-[#F8FAFC]"
          >
            <Plus size={28} strokeWidth={3} />
          </button>
        </div>

        <NavItem id="reports" icon={FileText} label="Relatórios" />
        {currentUser.role === UserRole.ADMIN && <NavItem id="settings" icon={SettingsIcon} label="Ajustes" />}
      </nav>

      <div className="flex-1 transition-all duration-300 pb-24 w-full overflow-x-hidden">
        <header className="bg-white/90 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40 no-print">
          <div className="max-w-4xl mx-auto px-4 py-4 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-md">
                <Gauge size={18} />
              </div>
              <div className="min-w-0">
                <h2 className="text-xs md:text-sm font-black text-black uppercase tracking-tight truncate leading-none mb-1">
                  {currentUser.name}
                </h2>
                <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">
                  {currentUser.role === UserRole.ADMIN ? 'Administrador' : currentUser.role === UserRole.STANDARD ? 'Padrão' : 'Simples'}
                </span>
              </div>
            </div>

            <div className="flex items-center gap-2 shrink-0">
              <span className="text-[9px] font-black text-black uppercase tracking-widest bg-slate-100 px-2.5 py-1.5 rounded-xl border border-slate-300">
                KM: {lastOdometer.toLocaleString()}
              </span>
              <button onClick={handleLogout} className="p-2 bg-slate-100 rounded-xl text-slate-500 hover:text-red-600 border border-slate-300">
                <LogOut size={16} />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 md:px-6 py-6 w-full">
          {activeTab === 'dashboard' && currentUser.role !== UserRole.SIMPLE && (
            <div className="no-print animate-in fade-in duration-500 w-full overflow-x-hidden">
              {expenses.length >= 2 && currentUser.role === UserRole.ADMIN && (
                <div className="mb-6 bg-gradient-to-br from-blue-700 to-indigo-800 rounded-[28px] p-6 text-white shadow-xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                  <div className="relative z-10">
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center space-x-2">
                        <Sparkles size={16} className="text-yellow-300" />
                        <h2 className="font-black text-xs md:text-sm uppercase tracking-tight">Sugestões de Economia</h2>
                      </div>
                      <button onClick={fetchAIInsights} disabled={loadingInsights} className="text-[9px] font-black uppercase tracking-widest bg-white/20 px-3 py-1.5 rounded-lg border border-white/10">
                        {loadingInsights ? "..." : "Atualizar"}
                      </button>
                    </div>
                    {insights.length > 0 ? (
                      <div className="space-y-2">
                        {insights.slice(0, 2).map((tip, idx) => (
                          <div key={idx} className="bg-white/10 backdrop-blur-md p-3 rounded-xl text-[10px] md:text-[11px] font-bold border border-white/5 shadow-sm">{tip}</div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-white/70 text-[10px] font-bold">Gerencie suas despesas e peça dicas à IA.</p>
                    )}
                  </div>
                </div>
              )}
              <Dashboard expenses={expenses} />
            </div>
          )}

          {activeTab === 'settings' && currentUser.role === UserRole.ADMIN && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Settings 
                locations={locations} onAddLocation={handleAddLocation} onRemoveLocation={handleRemoveLocation} 
                users={users} onAddUser={handleAddUser} onUpdateUser={handleUpdateUser} onRemoveUser={handleRemoveUser}
                currentUserRole={currentUser.role}
              />
            </div>
          )}

          {activeTab === 'reports' && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Reports expenses={expenses} locations={locations} forcedRole={currentUser.role} />
            </div>
          )}

          {activeTab === 'history' && (
            <div className="space-y-4 animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <div className="flex justify-between items-center mb-4 no-print px-1">
                <h3 className="text-xl font-black text-black tracking-tight">Atividades</h3>
                <button onClick={() => window.print()} className="p-2.5 bg-white border border-slate-300 rounded-xl text-black hover:bg-slate-50 transition-all shadow-sm"><Printer size={18} /></button>
              </div>

              {expenses.length === 0 ? (
                <div className="bg-white p-12 text-center text-slate-400 rounded-[32px] border-2 border-dashed border-slate-200">
                  <History size={40} className="mx-auto mb-4 opacity-20" />
                  <p className="text-sm font-bold">Nenhum lançamento encontrado.</p>
                </div>
              ) : (
                expenses.map(expense => (
                  <div key={expense.id} className="bg-white rounded-[24px] p-4 md:p-5 shadow-md border border-slate-200 flex items-center gap-4 group active:scale-[0.98] transition-all w-full hover:shadow-lg">
                    <div className={`p-3 rounded-2xl shrink-0 ${
                      expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-700' : 
                      expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-700' :
                      'bg-emerald-50 text-emerald-700'
                    }`}>
                      {expense.type === ExpenseType.FUEL ? <Fuel size={20} /> : 
                       expense.type === ExpenseType.MAINTENANCE ? <Wrench size={20} /> : 
                       <Navigation size={20} />}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] md:text-[10px] font-black uppercase text-slate-600">{new Date(expense.date).toLocaleDateString()}</span>
                        {expense.type === ExpenseType.SERVICE_REVENUE && (
                          <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded-md ${
                            expense.status === 'RECEIVED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                          }`}>
                            {expense.status === 'RECEIVED' ? 'OK' : 'PENDENTE'}
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-2 mb-0.5">
                        <h4 className="font-black text-black text-sm md:text-base tracking-tight truncate">
                          {expense.type === ExpenseType.FUEL ? expense.fuelType : 
                          expense.type === ExpenseType.SERVICE_REVENUE ? 'Serviço Realizado' : 'Manutenção'}
                        </h4>
                        {expense.type === ExpenseType.FUEL && expense.liters && expense.liters > 0 && (
                          <span className="text-[9px] font-black text-slate-600 bg-slate-100 px-1.5 py-0.5 rounded-md border border-slate-200">
                            R$ {(expense.value / expense.liters).toLocaleString('pt-BR', { minimumFractionDigits: 2 })} /L
                          </span>
                        )}
                      </div>
                      <div className="flex flex-wrap gap-2 mt-0.5">
                        <p className="text-[10px] md:text-[11px] font-bold text-slate-700 truncate flex items-center gap-1">
                          <MapPin size={8} /> {getLocationName(expense.locationId)}
                        </p>
                        <span className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-1 bg-blue-50 px-1.5 rounded-md">
                          {getPaymentMethodLabel(expense.paymentMethod).icon}
                          {getPaymentMethodLabel(expense.paymentMethod).label}
                        </span>
                      </div>
                    </div>

                    <div className="text-right shrink-0">
                      <div className={`text-base md:text-lg font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-700' : 'text-black'}`}>
                        {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </div>
                      <div className="flex items-center justify-end gap-1.5 mt-1">
                         <span className="text-[9px] font-black uppercase text-slate-500 mr-1">{expense.odometer.toLocaleString()} KM</span>
                         {(currentUser.role !== UserRole.SIMPLE || expense.userId === currentUser.id) && (
                           <>
                            <button onClick={() => handleEditExpense(expense)} className="text-slate-400 hover:text-amber-600 transition-colors p-1.5 bg-slate-50 rounded-lg"><Pencil size={14} /></button>
                            <button onClick={() => handleDeleteExpense(expense.id)} className="text-slate-400 hover:text-red-500 transition-colors p-1.5 bg-slate-50 rounded-lg"><Trash2 size={14} /></button>
                           </>
                         )}
                      </div>
                    </div>
                  </div>
                ))
              )}
