  };

  const fetchAIInsights = async () => {
    if (filteredExpensesByVehicle.length < 2) return;
    setLoadingInsights(true);
    const data = await getInsights(filteredExpensesByVehicle);
    setInsights(data);
    setLoadingInsights(false);
  };

  const NavItem = ({ id, icon: Icon, label }: { id: any, icon: any, label: string }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center justify-center gap-1 flex-1 py-1 transition-all rounded-xl ${
        activeTab === id ? 'text-blue-600 bg-blue-50/50' : 'text-slate-500 hover:text-slate-700'
      }`}
    >
      <Icon size={20} className={activeTab === id ? 'scale-110' : ''} />
      <span className="text-[9px] font-black uppercase tracking-tighter">{label}</span>
    </button>
  );

  if (!currentUser) {
    return <Login onLogin={handleLogin} availableUsers={users} />;
  }

  const isAdmin = currentUser.role === UserRole.ADMIN;
  const isStandard = currentUser.role === UserRole.STANDARD;
  const isSimple = currentUser.role === UserRole.SIMPLE;

  return (
    <div className="flex min-h-screen bg-[#F8FAFC] w-full overflow-x-hidden">
      <nav className="fixed bottom-0 left-0 right-0 bg-white/95 backdrop-blur-md border-t border-slate-200 flex items-center justify-center z-[90] no-print safe-pb shadow-[0_-8px_30px_rgb(0,0,0,0.08)] h-16 px-4 max-w-lg mx-auto md:rounded-t-[32px] gap-2">
        {(isAdmin || isStandard) && <NavItem id="dashboard" icon={LayoutDashboard} label="Início" />}
        {isAdmin && <NavItem id="history" icon={History} label="Histórico" />}
        {isAdmin && (
          <div className="relative -top-6 px-2">
            <button 
              onClick={() => {
                if (vehicles.length === 0) {
                  alert("Cadastre um veículo primeiro em Ajustes.");
                  setActiveTab('settings');
                } else {
                  setEditingExpense(null);
                  setIsFormOpen(true);
                }
              }}
              className="w-14 h-14 bg-blue-600 text-white rounded-2xl shadow-xl flex items-center justify-center active:scale-90 hover:bg-blue-700 transition-all border-4 border-[#F8FAFC]"
            >
              <Plus size={28} strokeWidth={3} />
            </button>
          </div>
        )}
        <NavItem id="reports" icon={FileText} label="Relatórios" />
        {isAdmin && <NavItem id="settings" icon={SettingsIcon} label="Ajustes" />}
      </nav>

      <div className="flex-1 transition-all duration-300 pb-24 w-full overflow-x-hidden">
        <header className="bg-white/90 backdrop-blur-md border-b border-slate-200 sticky top-0 z-40 no-print">
          <div className="max-w-4xl mx-auto px-4 py-4 flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white shadow-md">
                <Gauge size={18} />
              </div>
              <div className="min-w-0">
                <h2 className="text-xs md:text-sm font-black text-black uppercase tracking-tight truncate leading-none mb-1">
                  {currentUser.name}
                </h2>
                <div className="flex items-center gap-2">
                  <span className="text-[8px] font-black text-slate-400 uppercase tracking-widest">
                    {currentUser.role === UserRole.ADMIN ? 'Administrador' : currentUser.role === UserRole.STANDARD ? 'Padrão' : 'Simples'}
                  </span>
                  {activeVehicle && (
                    <span className="text-[8px] font-black text-blue-600 uppercase tracking-widest bg-blue-50 px-1.5 rounded">
                      {activeVehicle.plate}
                    </span>
                  )}
                </div>
              </div>
            </div>

            <div className="flex items-center gap-2 shrink-0">
              {activeVehicle ? (
                <span className="text-[9px] font-black text-black uppercase tracking-widest bg-slate-100 px-2.5 py-1.5 rounded-xl border border-slate-300">
                  KM: {lastOdometer.toLocaleString()}
                </span>
              ) : (
                <span className="text-[9px] font-black text-red-500 uppercase tracking-widest bg-red-50 px-2.5 py-1.5 rounded-xl border border-red-200">
                  Sem Veículo
                </span>
              )}
              <button onClick={handleLogout} className="p-2 bg-slate-100 rounded-xl text-slate-500 hover:text-red-600 border border-slate-300">
                <LogOut size={16} />
              </button>
            </div>
          </div>
        </header>

        <main className="max-w-4xl mx-auto px-4 md:px-6 py-6 w-full">
          {!activeVehicle && isAdmin && activeTab !== 'settings' && (
            <div className="mb-6 bg-amber-50 border-2 border-dashed border-amber-200 p-8 rounded-[32px] text-center">
              <Car size={40} className="mx-auto mb-4 text-amber-500" />
              <h3 className="text-lg font-black text-amber-900 uppercase">Nenhum Veículo Cadastrado</h3>
              <p className="text-sm font-bold text-amber-700 mt-2 mb-6">Para começar a lançar despesas e ver seu desempenho, cadastre seu primeiro veículo.</p>
              <button 
                onClick={() => setActiveTab('settings')}
                className="bg-amber-600 text-white px-8 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg active:scale-95"
              >
                Cadastrar Veículo Agora
              </button>
            </div>
          )}

          {activeTab === 'dashboard' && !isSimple && (
            <div className="no-print animate-in fade-in duration-500 w-full overflow-x-hidden">
              {filteredExpensesByVehicle.length >= 2 && (isAdmin || isStandard) && (
                <div className="mb-6 bg-gradient-to-br from-blue-700 to-indigo-800 rounded-[28px] p-6 text-white shadow-xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                  <div className="relative z-10">
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center space-x-2">
                        <Sparkles size={16} className="text-yellow-300" />
                        <h2 className="font-black text-xs md:text-sm uppercase tracking-tight">Sugestões de Controle</h2>
                      </div>
                      <button onClick={fetchAIInsights} disabled={loadingInsights} className="text-[9px] font-black uppercase tracking-widest bg-white/20 px-3 py-1.5 rounded-lg border border-white/10">
                        {loadingInsights ? "..." : "Analisar"}
                      </button>
                    </div>
                    {insights.length > 0 ? (
                      <div className="space-y-2">
                        {insights.slice(0, 2).map((tip, idx) => (
                          <div key={idx} className="bg-white/10 backdrop-blur-md p-3 rounded-xl text-[10px] md:text-[11px] font-bold border border-white/5 shadow-sm">{tip}</div>
                        ))}
                      </div>
                    ) : (
                      <p className="text-white/70 text-[10px] font-bold">Analisando o comportamento do seu {activeVehicle?.model || 'veículo'}...</p>
                    )}
                  </div>
                </div>
              )}
              <Dashboard expenses={filteredExpensesByVehicle} />
            </div>
          )}

          {activeTab === 'settings' && isAdmin && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Settings 
                locations={locations} onAddLocation={handleAddLocation} onRemoveLocation={handleRemoveLocation} 
                users={users} onAddUser={handleAddUser} onUpdateUser={handleUpdateUser} onRemoveUser={handleRemoveUser}
                currentUserRole={currentUser.role}
                vehicles={vehicles} onAddVehicle={handleAddVehicle} onRemoveVehicle={handleRemoveVehicle}
                activeVehicleId={activeVehicleId} onSelectVehicle={setActiveVehicleId}
              />
            </div>
          )}

          {activeTab === 'reports' && (
            <div className="animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <Reports expenses={filteredExpensesByVehicle} locations={locations} forcedRole={currentUser.role} />
            </div>
          )}

          {activeTab === 'history' && isAdmin && (
            <div className="space-y-4 animate-in slide-in-from-left-4 duration-300 w-full overflow-x-hidden">
              <div className="flex justify-between items-center mb-4 no-print px-1">
                <h3 className="text-xl font-black text-black tracking-tight">Fluxo de Atividades</h3>
                <button onClick={() => window.print()} className="p-2.5 bg-white border border-slate-300 rounded-xl text-black hover:bg-slate-50 transition-all shadow-sm"><Printer size={18} /></button>
              </div>

              {filteredExpensesByVehicle.length === 0 ? (
                <div className="bg-white p-12 text-center text-slate-400 rounded-[32px] border-2 border-dashed border-slate-200">
                  <History size={40} className="mx-auto mb-4 opacity-20" />
                  <p className="text-sm font-bold">Nenhum lançamento para o veículo {activeVehicle?.plate || ''}.</p>
                </div>
              ) : (
                filteredExpensesByVehicle.map(expense => (
                  <div key={expense.id} className="bg-white rounded-[24px] p-4 md:p-5 shadow-md border border-slate-200 flex items-center gap-4 group active:scale-[0.98] transition-all w-full hover:shadow-lg">
                    <div className={`p-3 rounded-2xl shrink-0 ${
                      expense.type === ExpenseType.FUEL ? 'bg-blue-50 text-blue-700' : 
                      expense.type === ExpenseType.MAINTENANCE ? 'bg-orange-50 text-orange-700' :
                      'bg-emerald-50 text-emerald-700'
                    }`}>
                      {expense.type === ExpenseType.FUEL ? <Fuel size={20} /> : 
                       expense.type === ExpenseType.MAINTENANCE ? <Wrench size={20} /> : 
                       <Navigation size={20} />}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <span className="text-[9px] md:text-[10px] font-black uppercase text-slate-600">{new Date(expense.date).toLocaleDateString()}</span>
                        {expense.type === ExpenseType.SERVICE_REVENUE && (
                          <span className={`text-[8px] font-black uppercase px-1.5 py-0.5 rounded-md ${
                            expense.status === 'RECEIVED' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                          }`}>
                            {expense.status === 'RECEIVED' ? 'OK' : 'PENDENTE'}
                          </span>
                        )}
                      </div>
                      <div className="flex items-center gap-2 mb-0.5">
                        <h4 className="font-black text-black text-sm md:text-base tracking-tight truncate">
                          {expense.type === ExpenseType.FUEL ? expense.fuelType : 
                          expense.type === ExpenseType.SERVICE_REVENUE ? 'Serviço Realizado' : 'Manutenção'}
                        </h4>
                      </div>
                    </div>

                    <div className="text-right shrink-0">
                      <div className={`text-base md:text-lg font-black ${expense.type === ExpenseType.SERVICE_REVENUE ? 'text-emerald-700' : 'text-black'}`}>
                        {expense.type === ExpenseType.SERVICE_REVENUE ? '+' : ''} R$ {expense.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                      </div>
                      <div className="flex items-center justify-end gap-1.5 mt-1">
                         <span className="text-[9px] font-black uppercase text-slate-500 mr-1">{expense.odometer.toLocaleString()} KM</span>
                         {isAdmin && (
                           <>
                            <button onClick={() => handleEditExpense(expense)} className="text-slate-400 hover:text-amber-600 transition-colors p-1.5 bg-slate-50 rounded-lg"><Pencil size={14} /></button>
                            <button onClick={() => handleDeleteExpense(expense.id)} className="text-slate-400 hover:text-red-500 transition-colors p-1.5 bg-slate-50 rounded-lg"><Trash2 size={14} /></button>
                           </>
                         )}
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          )}
        </main>
      </div>

      {isFormOpen && isAdmin && (
        <ExpenseForm 
          lastOdometer={lastOdometer} 
          locations={locations} 
          vehicles={vehicles}
          activeVehicleId={activeVehicleId}
          onAdd={handleSaveExpense} 
          onClose={() => { setIsFormOpen(false); setEditingExpense(null); }}
          initialData={editingExpense}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { ExpenseType, Expense, Location, FuelType, MaintenanceItem, PaymentMethod, Vehicle } from '../types';
import { Plus, X, Trash2, CreditCard, Wallet, Zap, FileText, Save, Car } from 'lucide-react';

interface ExpenseFormProps {
  onAdd: (expense: Omit<Expense, 'id'> | Expense) => void;
  onClose: () => void;
  lastOdometer: number;
  locations: Location[];
  vehicles: Vehicle[];
  activeVehicleId: string | null;
  initialData?: Expense | null;
}

export const ExpenseForm: React.FC<ExpenseFormProps> = ({ 
  onAdd, 
  onClose, 
  lastOdometer, 
  locations, 
  vehicles,
  activeVehicleId,
  initialData 
}) => {
  const [type, setType] = useState<ExpenseType>(initialData?.type || ExpenseType.FUEL);
  const [date, setDate] = useState(initialData?.date || new Date().toISOString().split('T')[0]);
  const [locationId, setLocationId] = useState<string>(initialData?.locationId || '');
  const [vehicleId, setVehicleId] = useState<string>(initialData?.vehicleId || activeVehicleId || (vehicles.length > 0 ? vehicles[0].id : ''));
  const [notes, setNotes] = useState(initialData?.notes || '');
  const [status, setStatus] = useState<'RECEIVED' | 'PENDING'>(initialData?.status || 'RECEIVED');
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>(initialData?.paymentMethod || 'PIX');
  const [odometer, setOdometer] = useState<string>(initialData?.odometer.toString() || lastOdometer.toString());
  const [fuelType, setFuelType] = useState<FuelType>(initialData?.fuelType || 'Gasolina');
  const [fuelValue, setFuelValue] = useState<string>(initialData?.type === ExpenseType.FUEL ? initialData.value.toString() : '');
  const [liters, setLiters] = useState<string>(initialData?.liters?.toString() || '');
  const [maintItems, setMaintItems] = useState<MaintenanceItem[]>(
    initialData?.maintenanceItems || [{ id: crypto.randomUUID(), description: '', value: 0 }]
  );
  const [odometerStart, setOdometerStart] = useState<string>(initialData?.odometerStart?.toString() || lastOdometer.toString());
  const [ratePerKm, setRatePerKm] = useState<string>(initialData?.ratePerKm?.toString() || '0.00');

  const totalValue = useMemo(() => {
    if (type === ExpenseType.FUEL) return parseFloat(fuelValue) || 0;
    if (type === ExpenseType.MAINTENANCE) return maintItems.reduce((acc, item) => acc + (item.value || 0), 0);
    if (type === ExpenseType.SERVICE_REVENUE) {
      const dist = (parseFloat(odometer) || 0) - (parseFloat(odometerStart) || 0);
      return Math.max(0, dist * (parseFloat(ratePerKm) || 0));
    }
    return 0;
  }, [type, fuelValue, maintItems, odometer, odometerStart, ratePerKm]);

  const addMaintItem = () => {
    setMaintItems([...maintItems, { id: crypto.randomUUID(), description: '', value: 0 }]);
  };

  const updateMaintItem = (id: string, field: 'description' | 'value', val: any) => {
    setMaintItems(maintItems.map(item => 
      item.id === id ? { ...item, [field]: field === 'value' ? parseFloat(val) || 0 : val } : item
    ));
  };

  const removeMaintItem = (id: string) => {
    if (maintItems.length > 1) {
      setMaintItems(maintItems.filter(item => item.id !== id));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!locationId) {
      alert("Por favor, selecione um local ou empresa.");
      return;
    }
    if (!vehicleId) {
      alert("Por favor, selecione um veículo.");
      return;
    }

    const basePayload = {
      type, 
      date, 
      odometer: parseFloat(odometer) || 0, 
      value: totalValue, 
      locationId, 
      vehicleId,
      notes: notes.trim(), 
      paymentMethod,
      description: type === ExpenseType.FUEL ? fuelType : (type === ExpenseType.SERVICE_REVENUE ? 'Km Rodado' : 'Manutenção'),
    };

    let payload: any = { ...basePayload };
    if (initialData?.id) payload.id = initialData.id;

    if (type === ExpenseType.FUEL) { 
      payload.fuelType = fuelType; 
      payload.liters = parseFloat(liters) || 0; 
    }
    else if (type === ExpenseType.MAINTENANCE) {
      payload.maintenanceItems = maintItems.filter(i => i.description.trim() !== '');
    }
    else if (type === ExpenseType.SERVICE_REVENUE) { 
      payload.odometerStart = parseFloat(odometerStart) || 0; 
      payload.ratePerKm = parseFloat(ratePerKm) || 0; 
      payload.status = status; 
    }

    onAdd(payload);
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-end md:items-center justify-center p-0 md:p-4 overflow-hidden">
      <div className="bg-white rounded-t-[28px] md:rounded-[28px] shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[92vh]">
        <div className="p-5 border-b border-slate-200 flex justify-between items-center bg-white shrink-0">
          <div className="flex items-center gap-3">
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${initialData ? 'bg-amber-100 text-amber-700' : 'bg-blue-100 text-blue-700'}`}>
              {initialData ? <Save size={20} /> : <Plus size={20} />}
            </div>
            <div>
              <h3 className="text-xl font-black text-black uppercase tracking-tight">
                {initialData ? 'Editar Registro' : 'Novo Registro'}
              </h3>
              <p className="text-[10px] font-bold text-slate-500 uppercase">
                {initialData ? `ID: ${initialData.id.slice(0, 8)}` : 'Preencha os dados abaixo'}
              </p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-black transition-colors">
            <X size={28} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-5 space-y-5 overflow-y-auto pb-6 scrollbar-hide">
          {/* Veículo (Especialmente importante se houver 2 ou mais) */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Veículo</label>
            <div className="relative">
              <Car className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <select 
                value={vehicleId} 
                onChange={e => setVehicleId(e.target.value)} 
                className="w-full p-4 pl-12 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all appearance-none"
              >
                {vehicles.map(v => (
                  <option key={v.id} value={v.id} className="font-bold text-black">{v.model} ({v.plate})</option>
                ))}
              </select>
            </div>
          </div>

          {/* Tipo de Lançamento */}
          <div className={`flex bg-slate-100 p-1.5 rounded-2xl border border-slate-200 ${initialData ? 'opacity-60 pointer-events-none' : ''}`}>
            {(['FUEL', 'MAINTENANCE', 'SERVICE_REVENUE'] as ExpenseType[]).map((t) => (
              <button 
                key={t} 
                type="button" 
                onClick={() => setType(t)} 
                className={`flex-1 py-3 rounded-xl text-[11px] font-black uppercase tracking-tight transition-all ${
                  type === t ? 'bg-white text-black shadow-md border border-slate-200' : 'text-slate-500 hover:text-black'
                }`}
              >
                {t === 'FUEL' ? 'Abastecer' : t === 'MAINTENANCE' ? 'Oficina' : 'Serviço'}
              </button>
            ))}
          </div>

          {/* Data e KM */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Data</label>
              <input 
                type="date" 
                value={date} 
                onChange={e => setDate(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all" 
              />
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">KM Final</label>
              <input 
                type="number" 
                inputMode="numeric" 
                value={odometer} 
                onChange={e => setOdometer(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all" 
              />
            </div>
          </div>

          {/* Local */}
          <div className="space-y-1.5">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Local / Empresa</label>
            <div className="relative">
              <select 
                value={locationId} 
                onChange={e => setLocationId(e.target.value)} 
                className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-sm font-black text-black focus:border-blue-600 outline-none transition-all appearance-none"
              >
                <option value="">Selecione...</option>
                {locations.filter(l => (type === 'FUEL' && l.type === 'POSTO') || (type === 'MAINTENANCE' && l.type === 'OFICINA') || (type === 'SERVICE_REVENUE' && l.type === 'CLIENTE')).map(loc => (
                  <option key={loc.id} value={loc.id} className="font-bold text-black">{loc.name}</option>
                ))}
              </select>
              <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-black">
                <Plus size={20} />
              </div>
            </div>
          </div>

          {/* Pagamento */}
          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-black ml-1 tracking-wider">Pagamento</label>
            <div className="grid grid-cols-2 xs:grid-cols-3 sm:grid-cols-5 gap-2">
              {(['PIX', 'CREDITO', 'DEBITO', 'DINHEIRO', 'NOTA_PRAZO'] as PaymentMethod[]).map(pm => (
                <button 
                  key={pm} 
                  type="button" 
                  onClick={() => setPaymentMethod(pm)} 
                  className={`py-4 rounded-2xl flex flex-col items-center justify-center gap-1 border-2 transition-all ${
                    paymentMethod === pm ? 'bg-black border-black text-white shadow-lg scale-105' : 'bg-white border-slate-300 text-black hover:border-slate-400'
                  }`}
                >
                  {pm === 'PIX' ? <Zap size={18} /> : pm === 'DINHEIRO' ? <Wallet size={18} /> : pm === 'NOTA_PRAZO' ? <FileText size={18} /> : <CreditCard size={18} />}
                  <span className="text-[9px] font-black uppercase tracking-tight">
                    {pm === 'NOTA_PRAZO' ? 'A Prazo' : pm}
                  </span>
                </button>
              ))}
            </div>
          </div>

          {/* Abastecimento */}
          {type === 'FUEL' && (
            <div className="grid grid-cols-2 gap-4 p-5 bg-blue-50/50 rounded-[28px] border-2 border-blue-100">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-black ml-1">Valor (R$)</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={fuelValue} 
                  onChange={e => setFuelValue(e.target.value)} 
                  placeholder="0,00"
                  className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
              <div className="space-y-1.5">
                <label className="text-[10px] font-black uppercase text-black ml-1">Litros</label>
                <input 
                  type="number" 
                  inputMode="decimal" 
                  step="0.01" 
                  value={liters} 
                  onChange={e => setLiters(e.target.value)} 
                  placeholder="0.00"
                  className="w-full p-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black text-black focus:border-blue-600 outline-none transition-all placeholder:text-slate-300" 
                />
              </div>
            </div>
          )}

          {/* Oficina */}
          {type === 'MAINTENANCE' && (
